-- Poems batch 164
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('000250f7-85dd-4e6b-a6c7-90a830533d8b','余得英州石山副之五絕句送曾鼎臣  其一','曾丰','宋','宋诗','song-poetry','','[]','小山欲與岳爲曹，其末雖危本則牢。',32,'全唐诗/poet.song.163000.json','["小山欲與岳爲曹，其末雖危本則牢。", "屹立挺身行所獨，旁羅垂首讓其高。"]'),
('ab7a05c2-1f99-4fec-9569-896e795eaa2c','余得英州石山副之五絕句送曾鼎臣  其二','曾丰','宋','宋诗','song-poetry','','[]','湖上飛來小祝融，羣青在側一居中。',32,'全唐诗/poet.song.163000.json','["湖上飛來小祝融，羣青在側一居中。", "何當容衆常相下，不必稱孤獨自雄。"]'),
('f1489bc1-0b35-4cbf-bee2-45b81b9ef3e3','余得英州石山副之五絕句送曾鼎臣  其三','曾丰','宋','宋诗','song-poetry','','[]','巖巖迥不與凡同，骨有餘清豈久窮。',32,'全唐诗/poet.song.163000.json','["巖巖迥不與凡同，骨有餘清豈久窮。", "雅趣未應爲獨行，皇恩猶許是三公。"]'),
('8958df1e-feec-4f34-ba59-f8cac9ff524b','余得英州石山副之五絕句送曾鼎臣  其四','曾丰','宋','宋诗','song-poetry','','[]','夢不曾爲嶺表遊，眼中陡頓有英州。',32,'全唐诗/poet.song.163000.json','["夢不曾爲嶺表遊，眼中陡頓有英州。", "知君結此石交後，一洗從前勢利羞。"]'),
('56e8375e-2f64-46a6-ba56-dd3611f6cc10','余得英州石山副之五絕句送曾鼎臣  其五','曾丰','宋','宋诗','song-poetry','','[]','吾宗世住望仙村，華蓋崢嶸日在門。',32,'全唐诗/poet.song.163000.json','["吾宗世住望仙村，華蓋崢嶸日在門。", "忽得祝融尤可重，方知華蓋未爲尊。"]'),
('7680d4af-f862-40c4-b103-61f2b17f906e','再遊南華有祖師衣鉢  其一','曾丰','宋','宋诗','song-poetry','','[]','西方達磨問歸程，衣鉢都留作麽生。',32,'全唐诗/poet.song.163000.json','["西方達磨問歸程，衣鉢都留作麽生。", "正道眼空嫌長物，如何更带履同行。"]'),
('b18dc305-c2b3-456c-8ddc-cf9a09290c7c','再遊南華有祖師衣鉢  其二','曾丰','宋','宋诗','song-poetry','','[]','達磨將身带履歸，殷勤分付鉢和衣。',32,'全唐诗/poet.song.163000.json','["達磨將身带履歸，殷勤分付鉢和衣。", "更和衣鉢將歸去，免與中原講是非。"]'),
('92d8a27d-ec37-4b84-821b-44f774364f34','再遊南華有祖師衣鉢  其三','曾丰','宋','宋诗','song-poetry','','[]','佛自無言人自訛，但留衣鉢說能多。',32,'全唐诗/poet.song.163000.json','["佛自無言人自訛，但留衣鉢說能多。", "假令和履多留下，誰奈沙門頰舌何。"]'),
('f9a7084f-96ea-452c-a1fa-6beace0e84e9','道邊松','曾丰','宋','宋诗','song-poetry','','[]','撼雨號風太古音，道中豈作買臣吟。',32,'全唐诗/poet.song.163000.json','["撼雨號風太古音，道中豈作買臣吟。", "火雲蒸雨無逃處，乞與行人數畝陰。"]'),
('90faed7a-8fe8-4207-9091-c23710f78fb4','道邊竹','曾丰','宋','宋诗','song-poetry','','[]','騰身已往化爲龍，未化先拔濟物功。',32,'全唐诗/poet.song.163000.json','["騰身已往化爲龍，未化先拔濟物功。", "六月乾坤塵撲火，行人無箇不清風。"]'),
('378b05af-c16f-4f36-a516-4f9285176ee9','道邊梅','曾丰','宋','宋诗','song-poetry','','[]','本隨馹使上長安，非到中途意便闌。',32,'全唐诗/poet.song.163000.json','["本隨馹使上長安，非到中途意便闌。", "爲念征夫行旅苦，與生滿舌遶牙酸。"]'),
('ad650f41-dd83-493f-864d-e9a91e39b4ef','戊申除夕送歲','曾丰','宋','宋诗','song-poetry','','[]','四十餘番送歲回，百年身世半摧頹。',32,'全唐诗/poet.song.163000.json','["四十餘番送歲回，百年身世半摧頹。", "更將四十餘番送，歲定相辭不復來。"]'),
('67afb49d-2ee4-4ef7-b9dc-19a4ee71d495','次韻楊誠齋雪中  其一','曾丰','宋','宋诗','song-poetry','','[]','夜閉袁門晏未開，開門滿目是瓊瑰。',32,'全唐诗/poet.song.163000.json','["夜閉袁門晏未開，開門滿目是瓊瑰。", "木綿著地還飛起，楊絮沾人倒撲回。"]'),
('99f9626e-fccc-48c0-bf6a-028156f47305','次韻楊誠齋雪中  其二','曾丰','宋','宋诗','song-poetry','','[]','雪兒初是玉仙妃，謫墮人間尚縞衣。',32,'全唐诗/poet.song.163000.json','["雪兒初是玉仙妃，謫墮人間尚縞衣。", "撲地狂風相衮起，疑乘白鶴刺天飛。"]'),
('a15a7a2c-8e3e-4e8a-8e69-0944e3d56625','中都寄廣東提幹彭元忠  其一','曾丰','宋','宋诗','song-poetry','','[]','舜峯蟲鳥亂號鳴，猶是簫韶節奏餘。',32,'全唐诗/poet.song.163000.json','["舜峯蟲鳥亂號鳴，猶是簫韶節奏餘。", "入耳雖歸哦咏裏，收心更聽寂寥初。"]'),
('30e70a96-f00a-4ed0-861e-26651f420049','中都寄廣東提幹彭元忠  其二','曾丰','宋','宋诗','song-poetry','','[]','君到韶如杜到夔，新功不比舊鑪鎚。',32,'全唐诗/poet.song.163000.json','["君到韶如杜到夔，新功不比舊鑪鎚。", "磨礱詩律如韶律，未必知音有仲尼。"]'),
('eef9674b-4566-4d78-aee6-e5795c3076f0','中都寄廣東提幹彭元忠  其三','曾丰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','同年同郡更同官，無適非同况歲寒。',32,'全唐诗/poet.song.163000.json','["同年同郡更同官，無適非同况歲寒。", "最是西湖好同賞，却相先後到長安。"]'),
('787fee1e-ea1d-4014-a9ba-5dfdf36d2c65','中都寄廣東提幹彭元忠  其四','曾丰','宋','宋诗','song-poetry','','[]','十期九度自參差，彼此無詞可遂非。',32,'全唐诗/poet.song.163000.json','["十期九度自參差，彼此無詞可遂非。", "投老江西沙石畔，鷗盟不請更相違。"]'),
('40929df4-7461-46ff-bee3-183c90ac75d5','張仲山補試余調官皆不得意相會次一詠','曾丰','宋','宋诗','song-poetry','','[]','君自戰餘成眊矂，吾行到處得揶揄。',32,'全唐诗/poet.song.163000.json','["君自戰餘成眊矂，吾行到處得揶揄。", "兩窮邂逅空相視，只問歸時有信無。"]'),
('51a1dd4f-b13e-4311-976f-78aa0f42bbc9','癸卯與宋堯夫集于豫章之貢院既別堯夫就親南豐戊申赴召除評事余到部再得款堯夫賦詩道舊次韻答之  其一','曾丰','宋','宋诗','song-poetry','','[]','吾人同醉豫章春，別後惟君日日新。',32,'全唐诗/poet.song.163000.json','["吾人同醉豫章春，別後惟君日日新。", "家據東床官北關，腰錢騎鶴更何人。"]'),
('c058d18a-961b-4e91-bb87-23ac3b7eee5d','癸卯與宋堯夫集于豫章之貢院既別堯夫就親南豐戊申赴召除評事余到部再得款堯夫賦詩道舊次韻答之  其二','曾丰','宋','宋诗','song-poetry','','[]','天意雖多與願從，更將雌道守吾雄。',32,'全唐诗/poet.song.163000.json','["天意雖多與願從，更將雌道守吾雄。", "騏驎已脫斜飛路，雕鶚初摶直上風。"]'),
('eeec345b-d9a2-46b8-bdb8-dcf76c02605a','癸卯與宋堯夫集于豫章之貢院既別堯夫就親南豐戊申赴召除評事余到部再得款堯夫賦詩道舊次韻答之  其三','曾丰','宋','宋诗','song-poetry','','[]','伶俜賀監坐詩狂，曼倩猶摩粟一囊。',32,'全唐诗/poet.song.163000.json','["伶俜賀監坐詩狂，曼倩猶摩粟一囊。", "鐘鼎狂心老來冷，江山歸路夢中長。"]'),
('af481cfe-46af-45bc-9769-a21cd157ed0e','癸卯與宋堯夫集于豫章之貢院既別堯夫就親南豐戊申赴召除評事余到部再得款堯夫賦詩道舊次韻答之  其四','曾丰','宋','宋诗','song-poetry','','[]','征衣浪自染京塵，骨相終寒不是清。',32,'全唐诗/poet.song.163000.json','["征衣浪自染京塵，骨相終寒不是清。", "大似有緣乘下澤，多應無分直承明。"]'),
('73600472-c8a8-4720-98af-76ef2411da60','秦望山  其一','曾丰','宋','宋诗','song-poetry','','[]','六國爭雄已坐擒，更何所望此登臨。',32,'全唐诗/poet.song.163000.json','["六國爭雄已坐擒，更何所望此登臨。", "真成馭鶴乘鸞去，未愜秦皇好大心。"]'),
('139e55f3-f59a-4428-a265-52b92c93b885','秦望山  其二','曾丰','宋','宋诗','song-poetry','','[]','銳意秦皇初學仙，要和鷄犬也昇天。',32,'全唐诗/poet.song.163000.json','["銳意秦皇初學仙，要和鷄犬也昇天。", "那知身與鮑俱臭，嬴氏炊寒不復烟。"]'),
('b826e8a8-6e35-4a8d-9bf1-cb89632ebc71','戒永州道聞思歸樂  其一','曾丰','宋','宋诗','song-poetry','','[]','宦遊佳處是零陵，廩稍優饒水石清。',32,'全唐诗/poet.song.163000.json','["宦遊佳處是零陵，廩稍優饒水石清。", "心不思歸歸不樂，汝休强勸拂人情。"]'),
('cb245dd8-ac7e-471f-9e77-969732439d9a','戒永州道聞思歸樂  其二','曾丰','宋','宋诗','song-poetry','','[]','張翰陶潜出信緣，思蓴愛菊返丘園。',32,'全唐诗/poet.song.163000.json','["張翰陶潜出信緣，思蓴愛菊返丘園。", "帝魂已託杜鵑去，今汝寧非二子魂。"]'),
('5c41130d-61c7-42c5-9b6d-585627f771f1','戒永州道聞思歸樂  其三','曾丰','宋','宋诗','song-poetry','','[]','田園無力辦難俱，有益猶堪學把鋤。',32,'全唐诗/poet.song.163000.json','["田園無力辦難俱，有益猶堪學把鋤。", "二者即今皆未具，教吾歸去却如何。"]'),
('af3bd75f-ac9d-43d7-b152-03502e7bd73f','清湘城西飛來峰  其一','曾丰','宋','宋诗','song-poetry','','[]','解后南鵬怒輒翔，乘風附翼過清湘。',32,'全唐诗/poet.song.163000.json','["解后南鵬怒輒翔，乘風附翼過清湘。", "羅浮本是仙家景，借與如來作寶坊。"]'),
('05e5197c-4536-4e40-9002-54ecf27d2161','清湘城西飛來峰  其二','曾丰','宋','宋诗','song-poetry','','[]','三處飛來一樣奇，佛無所擇我何辭。',32,'全唐诗/poet.song.163000.json','["三處飛來一樣奇，佛無所擇我何辭。", "重輕較到毫釐處，鳴雁行中此白眉。"]'),
('e9f8d96a-90a4-4b32-9547-1bd3c3c5bd1e','清湘城西飛來峰  其三','曾丰','宋','宋诗','song-poetry','','[]','鬼輸天雨玉崔嵬，乞與湘人眼豁開。',32,'全唐诗/poet.song.163000.json','["鬼輸天雨玉崔嵬，乞與湘人眼豁開。", "爲報湘人莫私有，飛來有日更飛回。"]'),
('2d9bced0-c257-4a49-9497-027ad6507a33','回雁峰  其一','曾丰','宋','宋诗','song-poetry','','[]','每向畫圖詩集看，祝融如孔雁如顔。',32,'全唐诗/poet.song.163000.json','["每向畫圖詩集看，祝融如孔雁如顔。", "雁峯今幸一相識，實校于名大似慳。"]'),
('aa1663e9-3e4e-42ef-9bc2-02c5abe1a6e1','回雁峰  其二','曾丰','宋','宋诗','song-poetry','','[]','揚雄非有動人姿，蓋代清名天下知。',32,'全唐诗/poet.song.163000.json','["揚雄非有動人姿，蓋代清名天下知。", "回雁名今與雄等，豈忘外陋慕中奇。"]'),
('ead230aa-4942-4397-b675-ab36b866c921','回雁峰  其三','曾丰','宋','宋诗','song-poetry','','[]','賓鴻初忌瘴邊嵐，止到峯前不更南。',32,'全唐诗/poet.song.163000.json','["賓鴻初忌瘴邊嵐，止到峯前不更南。", "近日鴻多更南去，峯名幾似晉清談。"]'),
('563b2e8b-1b42-44b4-91d0-f6bff8f3645c','回雁峰  其四','曾丰','宋','宋诗','song-poetry','','[]','雁入窮南失意多，以峯爲記誓毋過。',32,'全唐诗/poet.song.163000.json','["雁入窮南失意多，以峯爲記誓毋過。", "寧無忘記蹉過去，彼自輕生獨奈何。"]'),
('e9f06955-140b-42f9-90fc-7b49cdf2b3ee','回雁峰  其五','曾丰','宋','宋诗','song-poetry','','[]','此峯與雁作標題，記不分明有忘時。',32,'全唐诗/poet.song.163000.json','["此峯與雁作標題，記不分明有忘時。", "雁自會書真草字，標題安用此峯爲。"]'),
('d517193b-714d-4e6d-884f-acb6e75de5ae','西蜀泉上人久留中都  其一','曾丰','宋','宋诗','song-poetry','','[]','佛出西方打底州，西人何用更東遊。',32,'全唐诗/poet.song.163000.json','["佛出西方打底州，西人何用更東遊。", "騎馿莫說尋馿事，辦取工夫一轉頭。"]'),
('a84e2784-9044-41c2-bfc6-4e7ca01267a3','西蜀泉上人久留中都  其二','曾丰','宋','宋诗','song-poetry','','[]','擔水人家旦過寮，騎牛來看浙江潮。',32,'全唐诗/poet.song.163000.json','["擔水人家旦過寮，騎牛來看浙江潮。", "相逢便說三生話，不管人言舌太饒。"]'),
('20537748-590b-4891-9698-a2fb4756d3cb','西蜀泉上人久留中都  其三','曾丰','宋','宋诗','song-poetry','','[]','特地東遊訪祖師，東人占了鉢和衣。',32,'全唐诗/poet.song.163000.json','["特地東遊訪祖師，東人占了鉢和衣。", "幸餘隻履爲心印，猶在西方可急歸。"]'),
('ade19efc-e5b4-4d7c-83fe-c05f364e165f','題三生圖','曾丰','宋','宋诗','song-poetry','','[]','閑去閑來自在嬉，故人不記問于誰。',32,'全唐诗/poet.song.163000.json','["閑去閑來自在嬉，故人不記問于誰。", "都來一箇真消息，安用頻更可漏爲。"]'),
('cecfe0cb-c42e-44ef-8147-a482376e2a0e','禽言','曾丰','宋','宋诗','song-poetry','','[]','禽言勸我不如歸，似念官卑俸入微。',32,'全唐诗/poet.song.163000.json','["禽言勸我不如歸，似念官卑俸入微。", "或道哥哥行不得，家貧歸去更無衣。"]'),
('52cb85e2-bed7-4746-8469-75da328c576b','義寧産蓴菜中秋大熟副以六絕送楊伯子  其一','曾丰','宋','宋诗','song-poetry','','[]','秋行春令氣猶凝，柳曳寒絲軟蘸冰。',32,'全唐诗/poet.song.163000.json','["秋行春令氣猶凝，柳曳寒絲軟蘸冰。", "又似瑶池樂棚下，鬼工遺落水晶藤。"]'),
('1002b62c-0edc-49bf-afa4-5a71180bdc47','義寧産蓴菜中秋大熟副以六絕送楊伯子  其二','曾丰','宋','宋诗','song-poetry','','[]','垂垂水綫白封青，一筯能生兩眼明。',32,'全唐诗/poet.song.163000.json','["垂垂水綫白封青，一筯能生兩眼明。", "分野自爲牛女地，何如墮落玉繩精。"]'),
