('99189029-6262-4391-8018-2a842ee8e797','迎倉使李監丞八絕  其二','曾丰','宋','宋诗','song-poetry','','[]','一尉初收百里塵，一同尋訪萬家春。',32,'全唐诗/poet.song.163000.json','["一尉初收百里塵，一同尋訪萬家春。", "留中幸到爭先處，請外甘爲勇退人。"]'),
('a963f3fa-b0a5-49fb-89d7-569686961db0','迎倉使李監丞八絕  其三','曾丰','宋','宋诗','song-poetry','','[]','星屏熊軾兩從容，未始論功莫大功。',32,'全唐诗/poet.song.163000.json','["星屏熊軾兩從容，未始論功莫大功。", "南劍人人無劍氣，宜春在在有春風。"]'),
('2c33e0ca-69a6-4c18-95da-b8f5feeb8b5d','迎倉使李監丞八絕  其四','曾丰','宋','宋诗','song-poetry','','[]','二十餘年兩度來，來賓蓮幕主霜臺。',32,'全唐诗/poet.song.163000.json','["二十餘年兩度來，來賓蓮幕主霜臺。", "今吾猶是故吾爾，白眼豈須青眼哉。"]'),
('2d1c4682-396d-427b-a721-7caeb060259e','迎倉使李監丞八絕  其五','曾丰','宋','宋诗','song-poetry','','[]','入境諏民察吏餘，羅浮賞罷更豐湖。',32,'全唐诗/poet.song.163000.json','["入境諏民察吏餘，羅浮賞罷更豐湖。", "相迎魚鳥如相告，車騎今回又較都。"]'),
('93b3165e-414d-43fa-b9ea-e0c1a543cd37','迎倉使李監丞八絕  其六','曾丰','宋','宋诗','song-poetry','','[]','農瓶無粟可重搜，官帑錢猶地上流。',32,'全唐诗/poet.song.163000.json','["農瓶無粟可重搜，官帑錢猶地上流。", "望我方來觀俗使，從今且作富民侯。"]'),
('07521bb4-b4c4-4992-a2ad-b68f007ab362','迎倉使李監丞八絕  其七','曾丰','宋','宋诗','song-poetry','','[]','南海江山鬰所懷，今晨何喜夙容開。',32,'全唐诗/poet.song.163000.json','["南海江山鬰所懷，今晨何喜夙容開。", "一千里外行人報，二十年前知己來。"]'),
('36b91975-1289-4112-99fb-63ef43c0560d','迎倉使李監丞八絕  其八','曾丰','宋','宋诗','song-poetry','','[]','同游漕幕舊三賓，臺府兩爲新主人。',32,'全唐诗/poet.song.163000.json','["同游漕幕舊三賓，臺府兩爲新主人。", "應念江西撙齋老，長裾猶曳幕中塵。"]'),
('575d11f0-8b4c-4d83-bfdc-ea854cbb6cad','題悟性寺卧雲堂呈源上人  其一','曾丰','宋','宋诗','song-poetry','','[]','僧與白雲同住山，夢同雲出覺同還。',32,'全唐诗/poet.song.163000.json','["僧與白雲同住山，夢同雲出覺同還。", "勿移枕席下堂去，堂下吾疑是世間。"]'),
('7383031d-cb9a-4234-b685-23d71644f322','題悟性寺卧雲堂呈源上人  其二','曾丰','宋','宋诗','song-poetry','','[]','一片閑雲逗半空，僧閑况復與雲同。',32,'全唐诗/poet.song.163000.json','["一片閑雲逗半空，僧閑况復與雲同。", "夢中不向華胥路，直出無何入大通。"]'),
('90973456-8281-4763-8f69-73bbd1f8553d','題悟性寺卧雲堂呈源上人  其三','曾丰','宋','宋诗','song-poetry','','[]','渠儂高卧傲吾徒，不道吾徒反傲渠。',32,'全唐诗/poet.song.163000.json','["渠儂高卧傲吾徒，不道吾徒反傲渠。", "渠不得雲無卧處，吾元自與太空俱。"]'),
('30d7b22b-01e2-4ee4-9f94-6e07d90ce445','賀廣東黄漕生辰六絕  其一','曾丰','宋','宋诗','song-poetry','','[]','博落山中黄子楊，少從李生受仙方。',32,'全唐诗/poet.song.163000.json','["博落山中黄子楊，少從李生受仙方。", "道成初試飛昇步，引手蟾宮折桂香。"]'),
('5ae72e4d-357e-4853-a976-b469b42b1f76','賀廣東黄漕生辰六絕  其二','曾丰','宋','宋诗','song-poetry','','[]','詔會蟾宮籍裏人，召還仙闕作仙賓。',32,'全唐诗/poet.song.163000.json','["詔會蟾宮籍裏人，召還仙闕作仙賓。", "王宮專席談先聖，朝路分班謁上真。"]'),
('b19c0e07-c799-4296-a7e4-40daba370ef7','賀廣東黄漕生辰六絕  其三','曾丰','宋','宋诗','song-poetry','','[]','奏事口含雞舌香，仙賓俄又作仙郎。',32,'全唐诗/poet.song.163000.json','["奏事口含雞舌香，仙賓俄又作仙郎。", "漢留不住王中散，又駕仙風出帝鄉。"]'),
('84eee5e3-0dae-43af-8448-07a277f4a9c1','賀廣東黄漕生辰六絕  其四','曾丰','宋','宋诗','song-poetry','','[]','計臺使長秘書丞，一士去天三館輕。',32,'全唐诗/poet.song.163000.json','["計臺使長秘書丞，一士去天三館輕。", "行詔仙郎主仙監，道山風月倍光明。"]'),
('d285507d-c7f3-41e9-9866-5b62c337044f','賀廣東黄漕生辰六絕  其五','曾丰','宋','宋诗','song-poetry','','[]','數從仙伯至仙公，一歲一遷三歲中。',32,'全唐诗/poet.song.163000.json','["數從仙伯至仙公，一歲一遷三歲中。", "三歲三遷吾事足，歸驕明月弄清風。"]'),
('4ef64139-fe17-4389-bd78-c39302332cdd','賀廣東黄漕生辰六絕  其六','曾丰','宋','宋诗','song-poetry','','[]','上界仙官執禮勤，逍遥歸入散仙羣。',32,'全唐诗/poet.song.163000.json','["上界仙官執禮勤，逍遥歸入散仙羣。", "百千歲後人相識，白石山前黄老君。"]'),
('0f5dd77a-2af3-4524-8395-0f5e74b03db8','贈相士','曾丰','宋','宋诗','song-poetry','','[]','舌端偷得不傳機，說破人生不載疑。',64,'全唐诗/poet.song.163000.json','["舌端偷得不傳機，說破人生不載疑。", "造物密教傳寫信，秋風已爲長蟾枝。", "平時拍手儻來話，今日回頭真箇奇。", "除却唐朝袁與李，問君此外更饒誰。"]'),
('9214e9b2-d6d8-4402-bf23-4377f8363c75','代賀皇太子生日','曾丰','宋','宋诗','song-poetry','','[]','里社鳴連日，黄河清九灣。',192,'全唐诗/poet.song.163000.json','["里社鳴連日，黄河清九灣。", "乾坤和氣滿，朝野太平還。", "星斕荆州界，光流蘭殿間。", "階蓂猶美少，籬菊具花慳。", "祥吹譁銅律，歡聲塞衛環。", "天資岐更嶷，淵德雅而嫺。", "銀榜題新出，桑弧掛未彎。", "雙龍牢國本，三善繫人寰。", "牆石塗深碧，車輪刷淺斑。", "誕彌今月是，宴饌兩宮頒。", "魚藻清遊急，銅龍白晝閑。", "承華門可款，博望客難攀。", "曾玷瀛洲選，仍聯甪里班。", "夢雖疎角觀，足未遽商山。", "江右新持節，吳頭舊逼蠻。", "五雲依遠庇，三祝護童顔。"]'),
('25881fef-1f28-4d7e-9b31-03792b3a2196','代賀皇太子生日','曾丰','宋','宋诗','song-poetry','','[]','運轉黄河舊，波澄少海清。',120,'全唐诗/poet.song.163000.json','["運轉黄河舊，波澄少海清。", "菊籬浮喜色，蘭殿沸歡聲。", "岐嶷親王羨，聰明左右驚。", "英姿涵玉裕，冊禮建蠻精。", "入省龍樓晚，歸休鶴禁晴。", "講筵心會道，賓苑禮通情。", "誕日愉謠滿，儲庭瑞彩盈。", "兩宮筵具渥，六佾舞儀輕。", "靜念孤蹤遠，曾叨四友榮。", "尚稽陪角綺，遥祝壽籛鏗。"]'),
('afa930e5-1b2f-43d1-94f1-305af15f95ad','聞德壽皇帝慶七十','曾丰','宋','宋诗','song-poetry','','[]','堯壽元非啜雉羹，秦皇漢武却營營。',32,'全唐诗/poet.song.163000.json','["堯壽元非啜雉羹，秦皇漢武却營營。", "有心去採三山藥，何似歸休一日兵。"]'),
('983fdf81-58ec-435e-8243-f77dd3047da5','伏波廟','曾丰','宋','宋诗','song-poetry','','[]','古廟秋深栗葉紅，綠沉金鏁尚英風。',32,'全唐诗/poet.song.163000.json','["古廟秋深栗葉紅，綠沉金鏁尚英風。", "鵠書示子今來少，誰似當年矍鑠翁。"]'),
('e1449207-e3b8-473c-944b-9b01bd62a49f','送孫莘老移知南京','曾丰','宋','宋诗','song-poetry','','[]','稚年曾未覩風標，瀚海初聞拔俊髦。',320,'全唐诗/poet.song.163000.json','["稚年曾未覩風標，瀚海初聞拔俊髦。", "國子先生曾并席，蓬萊學士看揮毫。", "量涵萬頃滄溟闊，氣吐千尋太華高。", "述性妙思窮孔孟，指南餘藻屈雄褒。", "談經落落鑑遒鐸，飛步僊僊踏海鼇。", "忠力敢前輕履尾，剛腸一决快吹毛。", "歸來有意成陶賦，謫去無言弔楚騷。", "志不下人寧碌碌，時非知我但囂囂。", "吳江春水尋幽寺，越嶺秋風聽怒濤。", "宣室鬼神靈語斷，長安鐘鼓夢思勞。", "廣陵南隔迷桑梓，泗水東來照節旄。", "威憺四隅消警吠，惠流比屋樂耕繅。", "真仙應祝通時澤，朽骨平冤息夜號。", "瀟灑幅巾忘夢覺，清凉丈室笑燻膏。", "淮陽大節孤尤峻，吏部雄材晚更豪。", "濫使執經稱弟子，虛煩解榻下功曹。", "曾迷馬祖山前鹿，頓悟華亭水底篙。", "細札忽聞更屏翰，高牙俄見列弓刀。", "照回天子今方晤，怒拂龍顔昔未遭。", "屈指陪京非久駐，太平功業待伊皋。"]'),
('ea5b365c-a024-4784-98a2-d966e9541155','甲申大水  其一','曾丰','宋','宋诗','song-poetry','','[]','吾州背山面江流，一雨便有泛溢憂。',67,'全唐诗/poet.song.163000.json','["吾州背山面江流，一雨便有泛溢憂。", "况復梅霖倒江海，白晝洶若龍移湫。", "眼看上流沒高樹，下流屋廬渺無處。", "君不見甲子之歲至甲申，如此災變已三度。"]'),
('bd5cd5b0-54b2-44af-839e-8f3156fffcf9','甲申大水  其二','曾丰','宋','宋诗','song-poetry','','[]','歙水震蕩方流東，婺水南來塞其衝。',67,'全唐诗/poet.song.163000.json','["歙水震蕩方流東，婺水南來塞其衝。", "二水爭雄屹不去，孤城匯爲河伯宮。", "經旬水落流民復，身在不用嗟無屋。", "君不見去年金人破淮壖，城郭千里無人烟。"]'),
('cb0dda61-1f35-4579-b35c-26c001eea9a0','辛丑大水','曾丰','宋','宋诗','song-poetry','','[]','天公哀此生人苦，潸然出涕灑下土。',176,'全唐诗/poet.song.163000.json','["天公哀此生人苦，潸然出涕灑下土。", "五晝五夜涕不已，平陸成河山作渚。", "是方爲邑本漥下，今者之變頃未覩。", "何止人家水半扉，或壓或溺遍處所。", "居家老稚幾爲魚，夜乘一葉投山塢。", "雖知此邦禍可免，頗念吾廬欹莫拄。", "朝登山巔聊放目，流尸蔽江可勝數。", "何處奔洪之所擠，一旦至斯辜非汝。", "天公用是涕愈流，陽侯正自喜且舞。", "我願天公且收涕，憂之反傷亦奚補。", "但令老眼開日月，蒼生自然得安堵。"]'),
('3a1e2ce9-5f79-4f62-879d-ed91459b585e','壽陳龍圖','曾丰','宋','宋诗','song-poetry','','[]','參差鴛瓦封清霜，玉虬薦瑞初騰驤。',192,'全唐诗/poet.song.163000.json','["參差鴛瓦封清霜，玉虬薦瑞初騰驤。", "三山一夜應圖讖，曉來沙磧堪褰裳。", "瑩煌戟戶掛弧矢，瑞氣氤氳結霞綺。", "帝令來作金鼎和，趁得寒梅雪香蕊。", "精神照座如神仙，滔滔揮翰傾河源。", "杜詩韓筆繼騷雅，鳳髓鸞膠家世傳。", "皇皇轡絡輝鄉國，春逐霜蹄滿南陌。", "禁城龍閣儼圖書，班近天顔還咫尺。", "泥書細札九天飛，好看錦衣蒙衮知。", "亨時得路方平坦，沙堤犖錯黄金羈。", "年年愛日回南陸，慶壽階庭照蘭玉。", "南陸仙翁識姓名，星官曾見刊瓊籙。"]'),
('b40d5b6e-4655-4fe3-8ed3-31671a000e4d','遊南山','曾丰','宋','宋诗','song-poetry','','[]','氤氳猶積氣，膚寸忽層陰。',48,'全唐诗/poet.song.163000.json','["氤氳猶積氣，膚寸忽層陰。", "甘雨新來足，青山舊隠深。", "隨緣酬萬物，聞早遂初心。", "彭澤曹溪意，亭前無古今。"]'),
('9a83827c-9f10-458c-8eaa-6a0697198494','壽林中書  其一','曾丰','宋','宋诗','song-poetry','','[]','巖巖風采百工師，龍馬精神海鶴姿。',64,'全唐诗/poet.song.163000.json','["巖巖風采百工師，龍馬精神海鶴姿。", "宮女猶傳洞簫賦，都人今作衮衣詩。", "幸逢堯舜登賢日，正是臯夔相國時。", "聖主佇知宣室事，甘棠何止郡人思。"]'),
('20752106-9477-42b7-aedd-64545ef8ffc1','壽林中書  其二','曾丰','宋','宋诗','song-poetry','','[]','鳳歷推來恰半千，高名千古重於山。',64,'全唐诗/poet.song.163000.json','["鳳歷推來恰半千，高名千古重於山。", "降因天下思姚宋，世有斯文屬孔顔。", "異俗已傳吾父至，中原今仗老臣安。", "璽書幾日來宣室，走馬傳宣夾路看。"]'),
('76c05346-9765-4359-a88d-9624d63aaac9','壽林中書  其三','曾丰','宋','宋诗','song-poetry','','[]','四鎮名藩忽十春，平生材術老經綸。',64,'全唐诗/poet.song.163000.json','["四鎮名藩忽十春，平生材術老經綸。", "古來學問須行己，曾向艱危不愛身。", "許國莫疑勳業大，傾朝共羨寵光頻。", "從今更覺功名重，正是人間五福人。"]'),
('c20e69a4-a016-4b29-a814-2de5b4bb3af1','再遊登滕王閣','曾丰','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','故閣崢嶸已劫灰，又看新閣上烟煤。',64,'全唐诗/poet.song.163000.json','["故閣崢嶸已劫灰，又看新閣上烟煤。", "斷碑無日不濃墨，古砌新秋猶雜苔。", "江闊鳥疑飛不過，風輕帆遠趁先開。", "天高地迥詩囊小，收拾不多空一來。"]'),
('0a385a93-8880-426b-bf67-1645a1f4c6b4','陳子尚滄洲趣','曾丰','宋','宋诗','song-poetry','','[]','湘江之水青悠悠，滄江宛在江中流。',64,'全唐诗/poet.song.163000.json','["湘江之水青悠悠，滄江宛在江中流。", "猗蘭青青結幽思，杜若紛紛生遠愁。", "前灣瞥見一漁艇，何處飛來雙白鷗。", "帝子不歸煙雨暮，參差吹斷楚天秋。"]'),
('8dac2288-7b25-4fd6-933d-a252861b2486','頹春涉途','曾丰','宋','宋诗','song-poetry','','[]','曾謂東風意向偏，也從僻處放春妍。',64,'全唐诗/poet.song.163000.json','["曾謂東風意向偏，也從僻處放春妍。", "山山長草青無間，樹樹成陰綠不專。", "黠獸幽居疑辟地，俊禽高舉欲登天。", "物情不一吾何擇，出處升沉任自然。"]'),
('f5991bb2-82f2-4206-80f0-41e273ff33a0','呈羅春信','曾丰','宋','宋诗','song-poetry','','[]','受命鍾材不已凉，未論道德與文章。',64,'全唐诗/poet.song.163000.json','["受命鍾材不已凉，未論道德與文章。", "晚謀事事成迂叟，羈跡年年是漫郎。", "銳意向前旋磨蟻，灰心求退觸藩羊。", "車中幸有司南柄，試與迷途指大方。"]'),
('99cc0f8c-08d8-4833-8dfc-e2447a39bf3f','閒居幽步','曾丰','宋','宋诗','song-poetry','','[]','歸歟無可答休休，小放吾心與目流。',64,'全唐诗/poet.song.163000.json','["歸歟無可答休休，小放吾心與目流。", "山不去門如自售，雲無留意似他求。", "有如許柏得能古，都幾何松若箇幽。", "更有疎梅修竹在，其他莫與子孫謀。"]'),
('911e5ec2-1a67-43fa-8fe6-de02e3296ef8','方稚川恕齋五絕  其一','曾丰','宋','宋诗','song-poetry','','[]','求仁亦多途，取近惟一路。',24,'全唐诗/poet.song.163000.json','["求仁亦多途，取近惟一路。", "內恕以及人，知君用心處。"]'),
('4ef17b28-856e-4799-bf04-f3f5e16a4efe','方稚川恕齋五絕  其二','曾丰','宋','宋诗','song-poetry','','[]','安宅曠弗居，浪自分彼己。',24,'全唐诗/poet.song.163000.json','["安宅曠弗居，浪自分彼己。", "儻由恕門歸，天下一人耳。"]'),
('5006993c-6440-4612-8cdf-289a640870c9','方稚川恕齋五絕  其三','曾丰','宋','宋诗','song-poetry','','[]','此道固非淺，聖門兩三人。',24,'全唐诗/poet.song.163000.json','["此道固非淺，聖門兩三人。", "佳名長在眼，無實勿爲賓。"]'),
('9c94cf22-1954-43a3-a87e-985e9a61fce3','方稚川恕齋五絕  其四','曾丰','宋','宋诗','song-poetry','','[]','一心貫羣倫，乃是吾祖事。',24,'全唐诗/poet.song.163000.json','["一心貫羣倫，乃是吾祖事。", "耳孫不繩武，愧子兩大字。"]'),
('ee4ad4ed-66c5-40f3-b6fe-963d48f2390e','方稚川恕齋五絕  其五','曾丰','宋','宋诗','song-poetry','','[]','視後而著鞭，書此以自儆。',24,'全唐诗/poet.song.163000.json','["視後而著鞭，書此以自儆。", "一言行終身，要處君已領。"]'),
('1c902401-0cf0-4011-85e8-a1d8349ae800','值侯修學趣儒人稍急因遺蓮花蓮實西瓜於吾宗翔叔作詩以勉之  其一','曾丰','宋','宋诗','song-poetry','','[]','絳玉裁花碧玉莖，亭亭香遠韻逾清。',32,'全唐诗/poet.song.163000.json','["絳玉裁花碧玉莖，亭亭香遠韻逾清。", "羣仙競倚西風笑，爲報臨淮政已成。"]'),
('b7832144-9910-42b6-8e63-0aab437f9ad4','值侯修學趣儒人稍急因遺蓮花蓮實西瓜於吾宗翔叔作詩以勉之  其二','曾丰','宋','宋诗','song-poetry','','[]','珠房顆顆綠英英，興味超然芹藻馨。',32,'全唐诗/poet.song.163000.json','["珠房顆顆綠英英，興味超然芹藻馨。", "不必鐵槌撾碎却，苦心應念子衿青。"]'),
('1f309e4e-b605-46fb-a5f6-7397ad9b3717','值侯修學趣儒人稍急因遺蓮花蓮實西瓜於吾宗翔叔作詩以勉之  其三','曾丰','宋','宋诗','song-poetry','','[]','紺色毬兒護水晶，味甘如蜜冷如冰。',32,'全唐诗/poet.song.163000.json','["紺色毬兒護水晶，味甘如蜜冷如冰。", "香風飄滿葵丘戍，散與鴞林解鬰蒸。"]'),
('4db9c3ac-d9dc-4f22-949e-e187521dba39','留別金陵故舊','曾丰','宋','宋诗','song-poetry','','[]','公家事畢更何爲，迴眷錢塘臂欲飛。',32,'全唐诗/poet.song.163000.json','["公家事畢更何爲，迴眷錢塘臂欲飛。", "留客故人雖意厚，倚門有母待兒歸。"]'),
('060eccc5-f69f-4a1d-872b-30a469f8f764','踈山','曾丰','宋','宋诗','song-poetry','','[]','草徑蜿蜒十里閑，雲關若在畫圖看。',32,'全唐诗/poet.song.163000.json','["草徑蜿蜒十里閑，雲關若在畫圖看。", "萬松密翠地無影，一水長清天自寒。"]'),
('60866ee4-b86d-4aef-9494-a72b6fe8b677','題雪竇飛雪亭','高元之','宋','宋诗','song-poetry','','[]','危亭上拂烟霧光，蒼崖深到蛟螭穴。',80,'全唐诗/poet.song.163000.json','["危亭上拂烟霧光，蒼崖深到蛟螭穴。", "天河飛來破山翠，寒入疎林風自發。", "翻珠錯玉無時歇，巖前散作千秋雪。", "寒聲蕭蕭凜毛髮，白雲朵朵翔空滅。", "飛流濺沫入毫端，天與一詩爲題絕。"]'),
('e83985e2-62d5-4515-8d01-70a655682bc1','雪竇寺','高元之','宋','宋诗','song-poetry','','[]','雪竇深雲處，相携到乳泉。',48,'全唐诗/poet.song.163000.json','["雪竇深雲處，相携到乳泉。", "沙田春事晚，山寺野花妍。", "香飯饑南燭，丹房記景天。", "仙居應六八，更欲上風煙。"]'),
('b65c466e-1c1c-4375-8e0b-edad617af811','小晦嶺','高元之','宋','宋诗','song-poetry','','[]','路自崎嶇心自平，雲扃無鎖但徐行。',32,'全唐诗/poet.song.163000.json','["路自崎嶇心自平，雲扃無鎖但徐行。", "松風石溜含悲怨，中有樵夫度嶺聲。"]'),
('07236e30-1531-4246-8d0a-ac18e02841ea','大小晦山','高元之','宋','宋诗','song-poetry','','[]','大晦出小晦，過盡山峰翠。',48,'全唐诗/poet.song.163000.json','["大晦出小晦，過盡山峰翠。", "寒雲抱幽石，枯卉老壖瀨。", "沿流路偪側，當道屋破碎。", "却立重回首，瀑布瀉雲背。"]'),
('1b49efc5-155e-4922-9dee-58a3656b386a','長汀即事','高元之','宋','宋诗','song-poetry','','[]','楊花剩得晴方好，榆莢其如世上貧。',32,'全唐诗/poet.song.163000.json','["楊花剩得晴方好，榆莢其如世上貧。", "花向喜中看更好，分明春色解欺人。"]'),
('339eac6f-08ab-4b2a-934f-bf7c30222f30','句','高元之','宋','宋诗','song-poetry','','[]','灑窗蠶食葉，入竹蟹行沙。',12,'全唐诗/poet.song.163000.json','["灑窗蠶食葉，入竹蟹行沙。"]'),
('4ed1cfb8-4eb1-4546-a054-bcf04e3db9ff','新笋','釋德輝','宋','宋诗','song-poetry','','[]','竹笋初生牛犢角，蕨芽新長小兒拳。',32,'全唐诗/poet.song.163000.json','["竹笋初生牛犢角，蕨芽新長小兒拳。", "旋挑野菜炊香飯，便是江南二月天。"]'),
('81b97df2-9e25-4d27-bc7f-6f99efb8f6b9','辭世偈','釋德輝','宋','宋诗','song-poetry','','[]','一生無利亦無名，圓頂方袍自在行。',64,'全唐诗/poet.song.163000.json','["一生無利亦無名，圓頂方袍自在行。", "道念只從心上起，禪機俱向舌根生。", "百千萬劫假非假，六十三年真不真。", "今向無名叢內去，不遺一物在南屏。"]'),
('7f99b0f3-ac46-4c64-b2f6-b4cea81f4a77','句  其一','劉甲','宋','宋诗','song-poetry','','[]','山圍梓蜀千秋景，水接東吳萬里天。',16,'全唐诗/poet.song.163000.json','["山圍梓蜀千秋景，水接東吳萬里天。"]'),
('8b70635a-e7f4-40f0-8956-28bc1fc375c4','句  其二','劉甲','宋','宋诗','song-poetry','','[]','一川带繞三平島，萬巘環趨兩翠巒。',16,'全唐诗/poet.song.163000.json','["一川带繞三平島，萬巘環趨兩翠巒。"]'),
('5071b3c0-24cc-43c1-afe2-e1e515eeae6b','瀔水驛中','趙善漣','宋','宋诗','song-poetry','','[]','家山迢遞白雲遮，行役偏愁去路賒。',64,'全唐诗/poet.song.163000.json','["家山迢遞白雲遮，行役偏愁去路賒。", "朝涉桐江寒入脛，夜眠孤館夢歸家。", "幾年城市成春夢，萬古江山閲歲華。", "若問歸裝何所有，擔頭只許插梅花。"]'),
('8f19915a-93da-4ac9-be8f-7ea303cdefb8','仙都石笋','趙善漣','宋','宋诗','song-poetry','','[]','崑崙失却大龍蟠，迸出層巖一角寒。',64,'全唐诗/poet.song.163000.json','["崑崙失却大龍蟠，迸出層巖一角寒。", "初日煙霞翻錦籜，九天風露混琅玕。", "香涵老翠山靈護，根透鴻濛地軸安。", "天柱直疑爲竹祖，仙翁圖作子孫看。"]'),
('64c3b871-e006-4156-b806-73b5015d32cb','池亭夜遊','趙善漣','宋','宋诗','song-poetry','','[]','踏月清詩骨，露華夜已深。',48,'全唐诗/poet.song.163000.json','["踏月清詩骨，露華夜已深。", "樹摇知鳥宿，波靜覺魚沉。", "報國慚無術，思親空有心。", "躊躇誰與語，唧唧亂蛩吟。"]'),
('f5b42594-bcbf-4b15-9df9-9e59d60bfbb9','懷歸','趙善漣','宋','宋诗','song-poetry','','[]','遊子何時返，家山萬里餘。',48,'全唐诗/poet.song.163000.json','["遊子何時返，家山萬里餘。", "望雲愁思切，對月賞心疏。", "相嚴煩龜卜，頻逢絕雁書。", "浮名在京國，繫我欲如何。"]'),
('6f2bfd0b-5b56-4796-8a37-627f7998c0a2','白雲巖','劉光祖','宋','宋诗','song-poetry','','[]','萬竹山中丹葉秋，五峰巖訝白雲留。',32,'全唐诗/poet.song.163000.json','["萬竹山中丹葉秋，五峰巖訝白雲留。", "黄花夾路開無主，青嶂隨人翠欲流。"]'),
('f83b09e6-bfd6-4cfd-ae65-d79c6d0d0c02','詩一首','劉光祖','宋','宋诗','song-poetry','','[]','嶺似頹城野日荒，關留遺迹界金房。',32,'全唐诗/poet.song.163000.json','["嶺似頹城野日荒，關留遺迹界金房。", "蜀人初向京西道，是處爲家莫斷腸。"]'),
('3250833d-cece-4b85-8c52-19fbe200eab6','除夕','劉光祖','宋','宋诗','song-poetry','','[]','房州亦是家，守歲落燈花。',24,'全唐诗/poet.song.163000.json','["房州亦是家，守歲落燈花。", "鄉信長憑雁，僧餐自施鴉。"]'),
('f98808c1-1a19-4eab-9d45-e9b939d6c186','穿珠節','劉光祖','宋','宋诗','song-poetry','','[]','晴日喧闐半癭民，石灘爭拾寶璣勻。',32,'全唐诗/poet.song.163000.json','["晴日喧闐半癭民，石灘爭拾寶璣勻。", "夔州踏磧遨頭宴，防渚穿珠市尾人。"]'),
('c41dc2fc-7b95-4ebe-93f2-74bc4a9bb7ba','詩一首','劉光祖','宋','宋诗','song-poetry','','[]','往日房陵憐逐客，物情不覺在天涯。',64,'全唐诗/poet.song.163000.json','["往日房陵憐逐客，物情不覺在天涯。", "十年來作六州長，四海共知雙鬢華。", "封內半爲胡敵踐，路傍時問野人家。", "京山初入京西道，晚景輕風旆脚斜。"]'),
('44526011-dbe4-4f5c-9850-73911a12c6ae','游荆門上泉寺  其一','劉光祖','宋','宋诗','song-poetry','','[]','上泉山下石叢叢，小似飛來天竺峰。',32,'全唐诗/poet.song.163000.json','["上泉山下石叢叢，小似飛來天竺峰。", "草木自腴巖自秀，幽姿不肯入廛中。"]'),
('edac07b3-69ba-4025-9ce8-4bdef066cbfa','游荆門上泉寺  其二','劉光祖','宋','宋诗','song-poetry','','[]','碧玉潭深黄玉花，蓮經聽徹便爲家。',32,'全唐诗/poet.song.163000.json','["碧玉潭深黄玉花，蓮經聽徹便爲家。", "憑君爲我頻膏雨，長使村村足稻麻。"]'),
('d5188cbb-06a9-4956-8084-8ee6f144fd62','鶴林寺','劉光祖','宋','宋诗','song-poetry','','[]','竹院逢僧話，山門掃地迎。',48,'全唐诗/poet.song.163000.json','["竹院逢僧話，山門掃地迎。", "英雄猶有迹，般若太無情。", "玉樹春陰密，琅玕晚暑清。", "半年來往屢，只合送行旌。"]'),
('a832bb74-4478-478e-ac4a-9acd7a56475b','句  其一','劉光祖','宋','宋诗','song-poetry','','[]','女媧山下少人行，澗谷聲中一鳥鳴。',16,'全唐诗/poet.song.163000.json','["女媧山下少人行，澗谷聲中一鳥鳴。"]'),
('2e8e8e35-edb7-401f-b079-c4cc47e7cac6','句  其二','劉光祖','宋','宋诗','song-poetry','','[]','同登二樂榭，擬續四賢詩。',12,'全唐诗/poet.song.163000.json','["同登二樂榭，擬續四賢詩。"]'),
('eb95539f-00f1-4808-8760-2d13e6b031dd','句  其三','劉光祖','宋','宋诗','song-poetry','','[]','思君天闊水悠悠。',8,'全唐诗/poet.song.163000.json','["思君天闊水悠悠。"]'),
('333ab23b-e85b-400f-b3d3-5915d95d523a','奉和御製秋懷詩二首  其一','徐沖淵','宋','宋诗','song-poetry','','[]','東壁星辰爛不收，夜涼河漢截天流。',64,'全唐诗/poet.song.163000.json','["東壁星辰爛不收，夜涼河漢截天流。", "芙蓉院靜琴三疊，翡翠簾開月一鈎。", "黄屋非心辭大寶，碧雲有意思高秋。", "金聲玉振掩前作，漢祖空懷猛士憂。"]'),
('1ad29614-269f-4684-ae66-285ce42607ae','奉和御製秋懷詩二首  其二','徐沖淵','宋','宋诗','song-poetry','','[]','天末虹蜺晚未收，龍池新雨漲清流。',64,'全唐诗/poet.song.163000.json','["天末虹蜺晚未收，龍池新雨漲清流。", "鷗緣適意頻依渚，魚不貪香懶上鈎。", "賸喜三邊無警報，况當萬寶得成秋。", "嘯歌高蹈羲皇上，不復深貽海內憂。"]'),
('e11308a8-6d7b-44a3-96a2-d554682656b1','題清音亭  其一','徐沖淵','宋','宋诗','song-poetry','','[]','新池碧甃玉囘環，一水來從天柱山。',32,'全唐诗/poet.song.163000.json','["新池碧甃玉囘環，一水來從天柱山。", "試作流觴擬修禊，蘭亭風景坐追還。"]'),
('0ca4fe79-1eec-4c71-8295-a4d7f726439e','題清音亭  其二','徐沖淵','宋','宋诗','song-poetry','','[]','人間絲竹競哇淫，只有清流解洗心。',32,'全唐诗/poet.song.163000.json','["人間絲竹競哇淫，只有清流解洗心。", "試論此山泉石看，茂林修竹勝山陰。"]'),
('306dcd43-1f90-40e7-beb2-cd563586f90a','題清音亭  其三','徐沖淵','宋','宋诗','song-poetry','','[]','泉聲飽聽玉琮琤，世路羊腸我倦行。',32,'全唐诗/poet.song.163000.json','["泉聲飽聽玉琮琤，世路羊腸我倦行。", "但得一觴仍一詠，不妨高枕寄浮生。"]'),
('a0c5f5d5-2c87-4e65-a9aa-fc06815dbffa','中秋夕設醮洞霄宮','徐沖淵','宋','宋诗','song-poetry','','[]','老桂吹香古殿秋，瓊鐘敲處月當樓。',64,'全唐诗/poet.song.163000.json','["老桂吹香古殿秋，瓊鐘敲處月當樓。", "星壇露下斗光冷，天宇雲空灝氣浮。", "羽客朝元鏘玉佩，寶熏凝霧靄金虯。", "步虛政在千巖上，咫尺高靈想下游。"]'),
('8b2a8965-5f16-4c8c-ab7a-2fb98f1f9549','清音亭憩暑','徐沖淵','宋','宋诗','song-poetry','','[]','水落石澗鳴，中含太古音。',84,'全唐诗/poet.song.164000.json','["水落石澗鳴，中含太古音。", "安得微妙人，寫入朱弦琴。", "六月天不雨，赤日雲無陰。", "道人憩其側，脫巾卧青林。", "好風松上來，聊復披吾襟。", "朱炎拆厚地，晴嵐冒高岑。", "願分一勺泉，爲民作甘霖。"]'),
('dd3f9906-4b68-4407-ba0e-d1f1edac24ff','清隠齋飲酒','徐沖淵','宋','宋诗','song-poetry','','[]','暖風薄雨輕烟散，晴日游絲飛絮亂。',64,'全唐诗/poet.song.164000.json','["暖風薄雨輕烟散，晴日游絲飛絮亂。", "竹窗午夢啼鳥驚，松軒晚飲幽人喚。", "一壺碧酒如春濃，萬斛羈愁若冰泮。", "興來索筆謾題詩，碧桃花下綸巾岸。"]'),
('5ee2b991-c161-4bcb-91d1-ec55e95186e0','冰壺','徐沖淵','宋','宋诗','song-poetry','','[]','一泓雖淺清，長時自甘冷。',24,'全唐诗/poet.song.164000.json','["一泓雖淺清，長時自甘冷。", "可憐病渴人，臨深垂短綆。"]'),
('bc836205-6837-46b9-93a4-41a8b5b7c8a3','通明館灑掃二首  其一','徐沖淵','宋','宋诗','song-poetry','','[]','聖恩寬大放還鄉，便著草鞋挑鉢囊。',64,'全唐诗/poet.song.164000.json','["聖恩寬大放還鄉，便著草鞋挑鉢囊。", "中路忽逢天柱詔，一行今侍玉皇香。", "浮舟載月苕溪上，倚杖瞻雲魏闕旁。", "身到通明上頭館，好山驚見暮蒼蒼。"]'),
('b830812d-6634-48d7-8d7b-1339834951f0','通明館灑掃二首  其二','徐沖淵','宋','宋诗','song-poetry','','[]','逋客還山一笑咍，故人憐我不嫌猜。',64,'全唐诗/poet.song.164000.json','["逋客還山一笑咍，故人憐我不嫌猜。", "曉猿夜鶴總歡喜，蕙帳草堂相與開。", "可爲雨芽煙蕨住，直緣流水古松來。", "枝巢若許鷦鷯借，投老此生真快哉。"]'),
('d2b5978a-f7db-4e06-ae5d-96139bbd5d86','沖虛齋池荷','徐沖淵','宋','宋诗','song-poetry','','[]','道人埋甕作新塘，胸次五湖波渺茫。',64,'全唐诗/poet.song.164000.json','["道人埋甕作新塘，胸次五湖波渺茫。", "太華移根聊戲劇，洄池分種不尋常。", "冰壺夜浸綠荷露，玉鑒晚吹紅藕香。", "可待秋風蓮子熟，會乘一葉汎滄浪。"]'),
('d4472acd-fece-45cc-9a7c-293ec73f15c4','句','徐沖淵','宋','宋诗','song-poetry','','[]','破衲卷雲秋漠漠。',8,'全唐诗/poet.song.164000.json','["破衲卷雲秋漠漠。"]'),
('942eb312-a48b-4b1b-bfc0-796c784cd584','第一山','王渥','宋','宋诗','song-poetry','','[]','亭聳東南第一山，登臨身在白雲間。',48,'全唐诗/poet.song.164000.json','["亭聳東南第一山，登臨身在白雲間。", "市樓斜日紅高下，客艇輕波綠往還。", "輿地望中成異境，將軍閫外亦胡顔。"]'),
('c32b6182-348f-482d-8f79-119fd3927072','淳熙壬寅烏石山別□□嗣老禪師','趙公廙','宋','宋诗','song-poetry','','[]','箇裏靈山處處通，本無來往與西東。',32,'全唐诗/poet.song.164000.json','["箇裏靈山處處通，本無來往與西東。", "臨行一句如何會，烏石山頭撞曉風。"]'),
('becf67f1-fff5-4fbd-b24e-09e6fc772725','句','林元仲','宋','宋诗','song-poetry','','[]','原上卧龍無起日，柱頭化鶴見何年。',16,'全唐诗/poet.song.164000.json','["原上卧龍無起日，柱頭化鶴見何年。"]'),
('f8180abe-0c13-479b-9f6d-193ef3e61f43','峽州','汪德輸','宋','宋诗','song-poetry','','[]','醉翁昔日經行處，遐想英風萬古愁。',32,'全唐诗/poet.song.164000.json','["醉翁昔日經行處，遐想英風萬古愁。", "芳草斜陽渾似舊，茫茫江水自空流。"]'),
('3bfbd088-8f3b-4e24-9dd6-0e7eee46991d','瑞麥贊','林某','宋','宋诗','song-poetry','','[]','淳熙天子，御圖三七。',120,'全唐诗/poet.song.164000.json','["淳熙天子，御圖三七。", "協氣所鍾，嘉禾乃出。", "巴夔之山，亙連阡陌。", "或兩其歧，或六其脊。", "惟是西門，近郊所植。", "六六同穎，函三爲一。", "茲誠創見，圖寫漏逸。", "乃知人爲，不逮天力。", "上方寅畏，擯華務實。", "臣不敢獻，私志於室。", "采詩之官，汗青之筆。", "編諸詩書，示此其質。"]'),
('e96b94b5-4e32-431e-8c10-19aac17c938c','桃源','李韋之','宋','宋诗','song-poetry','','[]','商山四老人，避世還出世。',24,'全唐诗/poet.song.164000.json','["商山四老人，避世還出世。", "桃源獨終隠，坐看日月逝。"]'),
('05e00a0c-c478-49d1-ac34-799dbb81c0fc','參政謝公挽詞  其一','黄定','宋','宋诗','song-poetry','','[]','落落朋良會，千齡際遇難。',48,'全唐诗/poet.song.164000.json','["落落朋良會，千齡際遇難。", "雞香初坐帳，獬豸即峩冠。", "自抗囊封疏，長開黼座顔。", "西樞東府事，施設未全殫。"]'),
('d2e6eb31-c50c-4e91-960d-1b1153b4a063','參政謝公挽詞  其二','黄定','宋','宋诗','song-poetry','','[]','一自參機政，居然重本兵。',48,'全唐诗/poet.song.164000.json','["一自參機政，居然重本兵。", "尤優文與武，謚重敏兼榮。", "行矣躋三府，天乎夢兩楹。", "鄱陽當日讖，端的付唐生。"]'),
('573d3ca5-ff80-44ac-84dc-0f81fb3e245a','舍人崔公挽詞  其一','黄定','宋','宋诗','song-poetry','','[]','昭代培英俊，皇天獨不仁。',48,'全唐诗/poet.song.164000.json','["昭代培英俊，皇天獨不仁。", "儒林埋鸑鷟，翰苑失麒麟。", "青史空遺字，黄麻半掩塵。", "惟餘忠藎語，分付義方人。"]'),
('67b9e20c-2d5e-4583-a495-52a0a419487f','舍人崔公挽詞  其二','黄定','宋','宋诗','song-poetry','','[]','昔會錢同舍，欽聞玉潤姿。',48,'全唐诗/poet.song.164000.json','["昔會錢同舍，欽聞玉潤姿。", "公時尚縈服，我亦去持麾。", "再起風斯下，重來霧怯披。", "方圖問奇字，抆淚賦哀詞。"]'),
('007357ce-2210-4eb2-a8b8-b404b97bdb9d','侍郎李公挽詞  其一','黄定','宋','宋诗','song-poetry','','[]','昭代論人物，如公實罕儔。',48,'全唐诗/poet.song.164000.json','["昭代論人物，如公實罕儔。", "行藏一無愧，才業兩俱優。", "矜式新韋布，封章動冕旒。", "持荷簪筆地，猶想舊風流。"]'),
('30528738-cca3-4ec4-ab72-506a083c59cc','侍郎李公挽詞  其二','黄定','宋','宋诗','song-poetry','','[]','吏績今無匹，邦人合去思。',48,'全唐诗/poet.song.164000.json','["吏績今無匹，邦人合去思。", "築隄防水患，振廩粒民饑。", "歷歷新安戒，洋洋近古詩。", "經綸曾未究，空有典刑遺。"]'),
('eae6b013-e0e4-4d09-b9d7-f37e5039a54d','石門洞','王孝嚴','宋','宋诗','song-poetry','','[]','天下洞天三十六，玄鶴洞天一仙谷。',240,'全唐诗/poet.song.164000.json','["天下洞天三十六，玄鶴洞天一仙谷。", "兩山對峙一如門，深崖百丈垂飛瀑。", "青牛往矣不復見，白雲空鎖故山麓。", "奇哉勝地得人勝，至今俗客來忘俗。", "向來我實勞夢想，一旦登臨快心目。", "尋師訪道語未罷，扶藜上朝玄水淥。", "九天雲綻漏𩆵雨，一沼波翻濺瓊玉。", "亭高噴雪逼人寒，地冷風霜滿空蔌。", "老龍底事不知倦，雷澤千年無斷續。", "必是分潢天上來，便欲窮源駕黄鵠。", "康樂曾登最高處，謫仙幾向岩前宿。", "壁間禪壓已有詩，想見思泉傾萬斛。", "安得前人不道句，更與羲仙醉時讀。", "千峰如峽蒼波束，二十四灘猶箭速。", "轉頭溪風一棹寒，但效雙鳬到山曲。"]'),
('834aa9d3-1088-4e9f-9580-9f9b289ae1bd','舫齋','王孝嚴','宋','宋诗','song-poetry','','[]','我本湖漘一漫郎，生來住處波茫茫。',272,'全唐诗/poet.song.164000.json','["我本湖漘一漫郎，生來住處波茫茫。", "時尋畫舸破烟水，菰蒲滿路荷花香。", "一川窈窕詫紅蓼，兩岸蘆葦明秋霜。", "船頭鷗鳥日來往，溪上風月相迎將。", "一行作吏便相失，合眼靈運春池塘。", "紛紛雁鶩實可厭，紙尾姓字隨低昂。", "簿書終是俗人甚，江湖到了難相忘。", "公餘頼有數椽在，疏櫺兩行如船裝。", "不知風波世路險，穩著萬斛隨風檣。", "人生短篷何日近，向來苕霅今括蒼。", "江山轉柁千萬里，故人兩地遥相望。", "誰能爲我幻竹葉，頃刻泛宅歸滄浪。", "祇憑平生氣湖海，隨所寓處爲艅艎。", "夜寒滿載明月窗，北風打頭人不忙。", "動來況自不如靜，悔吝不到虛舟傍。", "胸襟五湖與三江，是中莫測誰望洋。", "直須喚取李郭輩，相與共泛無何鄉。"]'),
('de9a3ca6-46f9-4451-b2ed-6835df7eb7a7','含笑花','許開','宋','宋诗','song-poetry','','[]','獻笑佳人絕可憐，姿姿靨輔巧承歡。',32,'全唐诗/poet.song.164000.json','["獻笑佳人絕可憐，姿姿靨輔巧承歡。", "一枝不用千金買，雨洗風吹却粲然。"]'),
('73f9ce7b-8d3b-493c-af82-f2e2bbb8ff24','水仙花','許開','宋','宋诗','song-poetry','','[]','定州紅花瓷，塊石藝靈苗。',72,'全唐诗/poet.song.164000.json','["定州紅花瓷，塊石藝靈苗。", "方苞茁水仙，厥名爲玉霄。", "適從閩越來，綠綬擁翠條。", "十花冒其顛，一一振鷺翹。", "粉蕤間黄白，清香從風飄。", "回首天台山，更識膽瓶蕉。"]'),
('bdc9be09-fd77-4443-b1f2-2146e55165eb','茉莉花','許開','宋','宋诗','song-poetry','','[]','火令行南國，彤雲間丹霞。',36,'全唐诗/poet.song.164000.json','["火令行南國，彤雲間丹霞。", "之子方熱中，濯濯冰雪花。", "植根却月盤，趣駕七香車。"]'),
('3ee09cc7-892b-4de7-973b-6454894b69a6','洞霄宮','許開','宋','宋诗','song-poetry','','[]','珠宮梁柱太平年，福地從知接洞天。',64,'全唐诗/poet.song.164000.json','["珠宮梁柱太平年，福地從知接洞天。", "曲檻一峰飛怪石，幽亭三峽迸流泉。", "驪龍睡重時方旱，白鶴歸來客欲仙。", "殿上紅雲西日映，此身如在玉皇前。"]'),
('1264d9b6-4d77-4a51-9c76-73245c5788b2','跋游本蘭亭序','李大異','宋','宋诗','song-poetry','','[]','真僞紛紛甚得知，風流千古一羲之。',32,'全唐诗/poet.song.164000.json','["真僞紛紛甚得知，風流千古一羲之。", "山陰勝概今何在，却有人傳定武碑。"]'),
('bce14a93-175c-4a47-bb8d-c0dd4d91dc03','欣欣亭  其一','李大異','宋','宋诗','song-poetry','','[]','門外青山收暮雨，林間歸路出行人。',32,'全唐诗/poet.song.164000.json','["門外青山收暮雨，林間歸路出行人。", "鷓鴣勸我早歸去，擬斫釣筒收紫筠。"]'),
('8146ec54-8e58-4713-8d56-e164e956351f','欣欣亭  其二','李大異','宋','宋诗','song-poetry','','[]','雨露汪洋四海春，嶺南嶺北多歸人。',32,'全唐诗/poet.song.164000.json','["雨露汪洋四海春，嶺南嶺北多歸人。", "朝中賢士罕過此，莫惜青錢呼白鱗。"]'),
('84b78fba-328c-4203-90df-7a65960f4461','曾兄惠然見臨篤敘世契示以先哲遺墨稽首敬觀因題其後','李大異','宋','宋诗','song-poetry','','[]','家傳文獻六經香，袖有驪珠日月光。',32,'全唐诗/poet.song.164000.json','["家傳文獻六經香，袖有驪珠日月光。", "喬木陰陰人已遠，祇應故笏是甘棠。"]'),
('1106d607-b0c5-4ad2-850a-28e2ba5eed71','上桂林詹帥','姚宋佐','宋','宋诗','song-poetry','','[]','九月無霜飛葉少，四時有笋亂叢深。',32,'全唐诗/poet.song.164000.json','["九月無霜飛葉少，四時有笋亂叢深。", "桂林二十四巖洞，杖屨十年供醉吟。"]'),
('74107fcd-a029-435a-ac1e-9abf26baab76','梅月吟','姚宋佐','宋','宋诗','song-poetry','','[]','梅花得月太清生，月得梅花越樣明。',32,'全唐诗/poet.song.164000.json','["梅花得月太清生，月得梅花越樣明。", "梅月蕭疏兩奇絕，有人踏月繞花行。"]'),
('32e2737b-4894-43e9-807a-4aaf8e37164e','句  其一','姚宋佐','宋','宋诗','song-poetry','','[]','當日客星今底處，化成臺輔柄璇霄。',16,'全唐诗/poet.song.164000.json','["當日客星今底處，化成臺輔柄璇霄。"]'),
('b31a713f-c9d4-4cc9-98a9-81d4ba3ee531','句  其二','姚宋佐','宋','宋诗','song-poetry','','[]','蠻丁誦吏部，沙戶知退之。',12,'全唐诗/poet.song.164000.json','["蠻丁誦吏部，沙戶知退之。"]'),
('02664335-80f0-4cba-9b5e-bc5d79003c90','九鯉湖','黄艾','宋','宋诗','song-poetry','','[]','九鯉山頭爽氣芬，潺湲九漈隔溪聞。',64,'全唐诗/poet.song.164000.json','["九鯉山頭爽氣芬，潺湲九漈隔溪聞。", "青嶂高障海東日，碧溪流穿湖曲雲。", "坐聽𤠔聲憐草閣，夜深月色度松門。", "無緣能結茅齋宿，綠水丹山欲共分。"]'),
('3508c81b-0adc-4a92-852a-8b3469ce9ce7','題丹徒漕渠','顧時大','宋','宋诗','song-poetry','','[]','兩岡相望山壁立，地形脊高勢回潴。',64,'全唐诗/poet.song.164000.json','["兩岡相望山壁立，地形脊高勢回潴。", "練湖寸板雖得尺，庱亭泄去如尾閭。", "自從秦鑿興赭徒，大業廣此事遨娛。", "歲久不治成癥瘀，下視一綫皆泥塗。"]'),
('71fa0e08-3d70-481b-84de-3b69f416d715','句','楊大全','宋','宋诗','song-poetry','','[]','前溪六時水，上界數聲鐘。',12,'全唐诗/poet.song.164000.json','["前溪六時水，上界數聲鐘。"]'),
('53f10307-909f-4b9e-9e5f-c63b2fcc6c9c','風鈴','胡朝穎','宋','宋诗','song-poetry','','[]','風不能調碎玉聲，宮商濫奏竟難名。',32,'全唐诗/poet.song.164000.json','["風不能調碎玉聲，宮商濫奏竟難名。", "誰家稚女敲方響，一曲從頭學不成。"]'),
('7610534f-da19-4371-9f6b-6625ef7f983a','旅夜書懷','胡朝穎','宋','宋诗','song-poetry','','[]','十日春光九日陰，故關千里未歸心。',32,'全唐诗/poet.song.164000.json','["十日春光九日陰，故關千里未歸心。", "遥憐兒女寒窗底，指點燈花語夜深。"]'),
('98ee9f55-809c-4e29-ab97-59926d7727be','春遊','胡朝穎','宋','宋诗','song-poetry','','[]','風煙冉冉草萋萋，乍雨還晴不作泥。',64,'全唐诗/poet.song.164000.json','["風煙冉冉草萋萋，乍雨還晴不作泥。", "粉蝶亂隨花片妥，黄鸝雙壓柳枝低。", "一灣淥水明鳬影，數里青山送馬蹄。", "無限春光吟不盡，浮紅浪紫望中迷。"]'),
('b95cca3e-2ccc-42ed-9337-f0e218d5e3ec','小金山','胡朝穎','宋','宋诗','song-poetry','','[]','天光雲影碧相涵，百頃玻璃一望間。',64,'全唐诗/poet.song.164000.json','["天光雲影碧相涵，百頃玻璃一望間。", "綠水遶門迷客渡，白雲終日伴僧閑。", "疏鐘破曉潛虬動，老木成陰倦鳥還。", "喚取頭陀磨石壁，爲渠題作小金山。"]'),
('9f887be9-702f-4dcb-9446-3e53ebf9a033','句  其一','胡朝穎','宋','宋诗','song-poetry','','[]','科名成後竟如何。',8,'全唐诗/poet.song.164000.json','["科名成後竟如何。"]'),
('4a770cdd-0144-4afe-90ef-45e689b8f13a','句  其二','胡朝穎','宋','宋诗','song-poetry','','[]','久聞父老言沙讖，爲問何時出狀元。',16,'全唐诗/poet.song.164000.json','["久聞父老言沙讖，爲問何時出狀元。"]'),
('c65ece0b-4435-4103-9a52-09143079a4f1','題資福院平綠軒二首  其一','陳炳','宋','宋诗','song-poetry','','[]','水屋圍春綠，雲岑送曉青。',48,'全唐诗/poet.song.164000.json','["水屋圍春綠，雲岑送曉青。", "無心向朝市，信步到禪扃。", "野境連天遠，疏鐘隔岸聽。", "杯行莫辭醉，簷月笑人醒。"]'),
('3d34335f-d342-4a0b-a936-9eb2e8d74ac4','題資福院平綠軒二首  其二','陳炳','宋','宋诗','song-poetry','','[]','白髮流年迅，青春盡日閑。',48,'全唐诗/poet.song.164000.json','["白髮流年迅，青春盡日閑。", "烟消漁舍出，風約櫓聲還。", "往事空搔首，微官祇强顔。", "漂零那對此，歸夢繞雲山。"]'),
('57d25fd8-3025-45c4-8c82-5a245994e78a','贈篆書吳全仲古風','歐陽光祖','宋','宋诗','song-poetry','','[]','黄帝史倉初作書，依類象形書亦疏。',336,'全唐诗/poet.song.164000.json','["黄帝史倉初作書，依類象形書亦疏。", "獸蹄鳥跡頗奇怪，乾端坤倪微發舒。", "周籀大篆十五篇，體製漸與蒼史殊。", "秦兼七國有天下，混一土宇同書車。", "趙高采歷競新作，胡母博學誇宏橅。", "是時小篆方挺出，蒼籀字畫勤芟除。", "雲陽繫囚變隸體，世喜簡便爭奔趨。", "人文日巧僞日勝，古意自此皆荒蕪。", "嶧山野火惟焦蘇，苦縣光和碑亦無。", "宣王石鼓後來出，真贋莫訂徒嗟吁。", "陽冰凜凜及前輩，字骨瘦硬中敷腴。", "潮乎下筆亦清切，杜陵謂與李蔡俱。", "寂寥恍已隔千載，遊心藝苑惟長驅。", "我朝巨筆惟章徐，武夷近數延陵吳。", "吳君心近覷天巧，瘦不露骨肥不粗。", "小字銀鈎鐵畫如，大字龍蛇相鬰紆。", "上窮羲黄下秦漢，掎摭彝鼎并盤盂。", "知音惜無浣花老，侯門欲曳鄒陽裾。", "勸君行矣勿留滯，識真四海多通儒。", "莫學婦人寫陰符，莫作奇字索酒沽。", "摩崖他日頌功德，大字深刻真良圖。"]'),
('e30be394-a71e-4e96-be58-e78bc2ccc931','和朱元晦九曲櫂歌  其一','歐陽光祖','宋','宋诗','song-poetry','','[]','聽取漁歌說武夷，武夷九曲水漣漪。',32,'全唐诗/poet.song.164000.json','["聽取漁歌說武夷，武夷九曲水漣漪。", "放舟理櫂從頭去，三十六峰天下奇。"]'),
('218d8f7b-03d2-4052-a4f0-27efe0ecea5a','和朱元晦九曲櫂歌  其二','歐陽光祖','宋','宋诗','song-poetry','','[]','一曲回看天鑑池，一邊草木與雲齊。',32,'全唐诗/poet.song.164000.json','["一曲回看天鑑池，一邊草木與雲齊。", "金龍玉簡無尋處，花自春風鳥自啼。"]'),
('bc39d470-baa0-49a8-9a0d-c774c454f5c4','和朱元晦九曲櫂歌  其三','歐陽光祖','宋','宋诗','song-poetry','','[]','玉女峰臨二曲流，刳心學道幾春秋。',32,'全唐诗/poet.song.164000.json','["玉女峰臨二曲流，刳心學道幾春秋。", "東風不信心如鐵，却放石楠花滿頭。"]'),
('07078c16-2b91-4440-ba4f-072427a009f4','和朱元晦九曲櫂歌  其四','歐陽光祖','宋','宋诗','song-poetry','','[]','仙人駕船朝上真，三曲溪流日淺清。',32,'全唐诗/poet.song.164000.json','["仙人駕船朝上真，三曲溪流日淺清。", "讀書巖前聞鶴唳，恐是舊時絃誦聲。"]'),
('f365d493-9065-460a-9972-3e3b09fe5984','和朱元晦九曲櫂歌  其五','歐陽光祖','宋','宋诗','song-poetry','','[]','日日金雞啁哳鳴，仙機巖前冬復春。',32,'全唐诗/poet.song.164000.json','["日日金雞啁哳鳴，仙機巖前冬復春。", "繫舟四曲看題石，詩與人存今幾人。"]'),
('a8fbe6bd-955b-4e8d-a160-f1c0bbaf08d8','和朱元晦九曲櫂歌  其六','歐陽光祖','宋','宋诗','song-poetry','','[]','五曲溪回屋數椽，上依翠壁下流泉。',32,'全唐诗/poet.song.164000.json','["五曲溪回屋數椽，上依翠壁下流泉。", "幽居不用立名字，大隠一峰高插天。"]'),
('cdc12214-32aa-4e94-adbf-7b4d90dac4c5','和朱元晦九曲櫂歌  其七','歐陽光祖','宋','宋诗','song-poetry','','[]','仙掌峰邊仙浴堂，泉聲戛戛潄琳琅。',32,'全唐诗/poet.song.164000.json','["仙掌峰邊仙浴堂，泉聲戛戛潄琳琅。", "流從六曲灘頭去，猶带落花風裏香。"]'),
('654fa831-989c-4f77-badd-640e1b134255','和朱元晦九曲櫂歌  其八','歐陽光祖','宋','宋诗','song-poetry','','[]','七曲溪邊古寺基，石塘春水綠漪漪。',32,'全唐诗/poet.song.164000.json','["七曲溪邊古寺基，石塘春水綠漪漪。", "澄波不見招提影，只有山光似舊時。"]'),
('2de34698-5f82-4804-8176-db38c60f583c','和朱元晦九曲櫂歌  其九','歐陽光祖','宋','宋诗','song-poetry','','[]','神仙蛻骨鼓樓山，一去丹霄更不還。',32,'全唐诗/poet.song.164000.json','["神仙蛻骨鼓樓山，一去丹霄更不還。", "停舟八曲訪遺迹，風雨蕭蕭生暮寒。"]'),
('984f2b9d-676f-4db4-9b20-7e691819cd11','和朱元晦九曲櫂歌  其一○','歐陽光祖','宋','宋诗','song-poetry','','[]','遊遍丹山與翠崖，新村渡口日西頹。',32,'全唐诗/poet.song.164000.json','["遊遍丹山與翠崖，新村渡口日西頹。", "神仙有無不可問，欵乃數聲歸去來。"]'),
('ef9a7d24-f9d4-4f0b-83ca-a7242ff3c50f','句','歐陽光祖','宋','宋诗','song-poetry','','[]','白髮駸駸吾老矣，名場從此欲投簪。',16,'全唐诗/poet.song.164000.json','["白髮駸駸吾老矣，名場從此欲投簪。"]'),
('6c5dbd1f-c50b-4104-b4db-58d5f5173d11','題釣臺','楊潛','宋','宋诗','song-poetry','','[]','遐想當年隠富春，生涯只寄一絲綸。',64,'全唐诗/poet.song.164000.json','["遐想當年隠富春，生涯只寄一絲綸。", "幸逢白水爲真主，肯向青山訪故人。", "試問勒功依日月，何如占象動星辰。", "回頭四七皆塵迹，獨有先生迹未塵。"]'),
('b562f8d0-eb03-4ca6-bc22-86aed68a9069','句','楊潛','宋','宋诗','song-poetry','','[]','烘日淺深色。',6,'全唐诗/poet.song.164000.json','["烘日淺深色。"]'),
('34ebbc60-f3ad-4244-9fab-305990421f05','春夜','錢大椿','宋','宋诗','song-poetry','','[]','燕子銜泥已下簾，深深庭院薄寒天。',64,'全唐诗/poet.song.164000.json','["燕子銜泥已下簾，深深庭院薄寒天。", "海棠枝上黄昏月，楊柳梢頭淺澹煙。", "勾引芳情春夢蝶，頻催愁緒夜啼鵑。", "踏青年少歸來晚，斗酒花陰枕石眠。"]'),
('47b08553-d51b-4e6a-9a27-98286959fad6','嘉定十六年題陶公惜陰處','吳紹','宋','宋诗','song-poetry','','[]','幽房翠竹籠蒼蘚，更有流泉濺石硔。',32,'全唐诗/poet.song.164000.json','["幽房翠竹籠蒼蘚，更有流泉濺石硔。", "莫道塵埃人易涴，試來摇足濯清風。"]'),
('1449af63-2a54-4be6-aef4-1f1b55bd00f1','乾道壬辰三月十日同叔衍游諸山用邵公濟大象閣韻','鄧椿','宋','宋诗','song-poetry','','[]','□山正南隆，翼蔽如壁壘。',132,'全唐诗/poet.song.164000.json','["□山正南隆，翼蔽如壁壘。", "白龍舞蜿蜒，漾漾環一水。", "最勝錦開屏，□秀當前起。", "石崩古有句，寧慮英靈止。", "東山屹相望，縷脉□□□。", "佳處更崇窅，頓倍客懷喜。", "後巖天下獨，人傑嘗□光。", "一門太平瑞，那復論表裏。", "盛事百年間，繼者能□耳。", "我來□乘酣，借□□□使。", "玉樹□風前，試把蒹葭倚。"]'),
('38565702-a8f4-4fd9-9da3-11d6a0530da0','荆山客邸題壁','范萬頃','宋','宋诗','song-poetry','','[]','囊金遺失正茫然，逆旅仁心盡付還。',32,'全唐诗/poet.song.164000.json','["囊金遺失正茫然，逆旅仁心盡付還。", "從此弋陽添故事，不教陰德擅燕山。"]'),
('5f1249d6-8065-437d-97ff-0481a3bc1899','梅花','葛郛','宋','宋诗','song-poetry','','[]','玉屑裝龍腦，雲衣覆麝{月齋}。',27,'全唐诗/poet.song.164000.json','["玉屑裝龍腦，雲衣覆麝{月齋}。", "何堪夜來雪，香色兩淒迷。"]'),
('f2ccdf21-1ff9-46aa-9b91-d67061d53096','留友人','葛郛','宋','宋诗','song-poetry','','[]','良友間何闊，春事遽如許。',72,'全唐诗/poet.song.164000.json','["良友間何闊，春事遽如許。", "勞君下鷗沙，一葉繫春渚。", "昨夢墜前世，再見欣欲舞。", "聊呼花底杯，酒面點紅雨。", "狂歌謝貫珠，清論雜揮麈。", "驪駒未可歌，妙句須君吐。"]'),
('233484d2-48fa-4485-8a0b-e3240f7f3a25','省過','程端蒙','宋','宋诗','song-poetry','','[]','此道從來信不疑，安行何處履危機。',64,'全唐诗/poet.song.164000.json','["此道從來信不疑，安行何處履危機。", "無心更與世俯仰，有口不談人是非。", "悔吝愆尤須謹細，存亡得失要知幾。", "師門有意無人會，一餉忘言對落暉。"]'),
('8c72a3a1-8b30-4a20-b77a-958a1057da6b','絕句','程端蒙','宋','宋诗','song-poetry','','[]','滿城塵土污人甚，出郭青山入眼多。',32,'全唐诗/poet.song.164000.json','["滿城塵土污人甚，出郭青山入眼多。", "拏取小舟烟霧裏，此生真個老漁蓑。"]'),
('2efe70d1-4951-4759-8b6b-33525102292a','送次卿兄還新安','程端蒙','宋','宋诗','song-poetry','','[]','聞君戒明發，值此深秋時。',120,'全唐诗/poet.song.164000.json','["聞君戒明發，值此深秋時。", "相送碧山下，殷勤薦離巵。", "與君夙通譜，况爾學同師。", "所期在聞道，肯爲矜文辭。", "易通久淪沒，遺書亦參差。", "向非考亭翁，入德將焉施。", "駕言各勇往，實踐仍精思。", "聖賢去千載，凜凜如在茲。", "君歸歙水上，豈徒事耘耔。", "至言啟茅塞，予方日孜孜。"]'),
('7a83695d-413b-4447-be3f-4fa20b36a8c1','題嚴因崇報禪寺','趙師龍','宋','宋诗','song-poetry','','[]','尋幽訪古到巖前，仰視雲霞接梵天。',64,'全唐诗/poet.song.164000.json','["尋幽訪古到巖前，仰視雲霞接梵天。", "六代興王那復在，千身化佛尚依然。", "老松欲作蒼龍去，怪石常如猛虎眠。", "已覺塵勞變清浄，何當築室向危巔。"]'),
('43e0f362-0f2c-453e-9cc7-c81d2c6d1659','題虛照堂','彭仲剛','宋','宋诗','song-poetry','','[]','宇空發天光，所患在自窒。',48,'全唐诗/poet.song.164000.json','["宇空發天光，所患在自窒。", "機乘不容穟，事至紛若櫛。", "是中有物橫，滿眼皆黑漆。", "斯堂亦空歟，爲我作虛室。"]'),
('9d63f727-b9d9-408f-9b46-30e868db8c74','題平心堂','彭仲剛','宋','宋诗','song-poetry','','[]','一泓不盈寸，天地同其流。',48,'全唐诗/poet.song.164000.json','["一泓不盈寸，天地同其流。", "微風相傾欹，浩浩懷山丘。", "牛馬已不辨，况能鑒微不。", "我欲稱物施，舍是將安求。"]'),
('7f5db68e-04bf-4d49-a7b5-64e0d70e3b31','三台峰','彭仲剛','宋','宋诗','song-poetry','','[]','雁蕩奇峰絕比倫，巍然森列應天文。',64,'全唐诗/poet.song.164000.json','["雁蕩奇峰絕比倫，巍然森列應天文。", "光聯奎壁期公輔，名顯瑶階欲致君。", "峻極冷擎中夜月，崢嶸突出半空雲。", "朝廷正爾需賢佐，光嶽鍾靈氣未分。"]'),
('e71dfb23-6e8b-4728-953f-54ef1443b364','廷對應制','陳亮','宋','宋诗','song-poetry','','[]','皇朝銳意急英賢，虜據中原七十年。',64,'全唐诗/poet.song.164000.json','["皇朝銳意急英賢，虜據中原七十年。", "際遇風雲凡事別，積功日月壯心愆。", "管簫器小誰能識，孔孟人存用則傳。", "慚負壽皇勤教育，奏篇半徹冕旒前。"]'),
('ca3975ea-60ed-4ce6-9949-1bf5b0454319','及第謝恩和御賜詩韻','陳亮','宋','宋诗','song-poetry','','[]','雲漢昭回倬錦章，爛然衣被九天光。',64,'全唐诗/poet.song.164000.json','["雲漢昭回倬錦章，爛然衣被九天光。", "已將德雨平分布，更把仁風與奉揚。", "治道脩明當正宁，皇威震疊到遐方。", "復讎自是平生志，勿謂儒臣鬢髮蒼。"]'),
('806464f7-85e3-440a-8507-cd79b61f1e22','謫仙歌','陳亮','宋','宋诗','song-poetry','','[]','李白字太白，清風肺腑明月魄。',341,'全唐诗/poet.song.164000.json','["李白字太白，清風肺腑明月魄。", "揚鞭獨步止一人，我誦太白手屢拍。", "嘗聞太白長庚星，夜半星在天上明。", "仰天高聲叫李白，星邊不見白應聲。", "又疑白星是酒星，銀河釀酒天上傾。", "奈無兩翅飛見白，王母池邊任解酲。", "欲遊金陵自采石，玩月乘舟歸赤壁。", "欲上箕山首陽巔，看白餐雪水底眠紫煙。", "又不知在何處，漱瑶泉，酌霞杯。", "悵望不見騎鶴來，白也如今安在哉。", "我生恨不與同時，死猶喜得見其詩。", "豈特文章惟足法，凜凜氣節安可移。", "金鑾殿上一篇頌，沉香亭裏行樂詞。", "此特太白細事耳，他人所知吾亦知。", "脫靴奴使高力士，辭官妾視楊貴妃。", "此真太白大節處，他人不知吾亦知。", "歌其什，鬼神泣，解使青塚枯骨立。", "呼其名，鬼神驚，惟有群仙側耳聽。", "我今去取崑山玉，將白儀形好彫琢。", "四方上下常相隨，江東渭北休興思。", "會須乞我乾坤造化兒，使我筆下光焰萬丈長虹飛。"]'),
('c417c825-80e2-45cf-b0a0-456cc168f322','詠梅  其一','陳亮','宋','宋诗','song-poetry','','[]','春回積雪層冰裏，香動荒山野水濱。',32,'全唐诗/poet.song.164000.json','["春回積雪層冰裏，香動荒山野水濱。", "带月一枝低弄影，背風千片遠隨人。"]'),
('a0a8ecdd-dcb4-41be-89fc-a80e70edc82c','詠梅  其二','陳亮','宋','宋诗','song-poetry','','[]','十里溫香撲馬來，江頭還見去年梅。',32,'全唐诗/poet.song.164000.json','["十里溫香撲馬來，江頭還見去年梅。", "喜開剩欲邀明月，愁落先教掃綠苔。"]'),
('a5abb431-f8e2-44c6-8d41-886265684db2','詠梅  其三','陳亮','宋','宋诗','song-poetry','','[]','爲探梅魁策蹇馿，竹梢疏處見清癯。',64,'全唐诗/poet.song.164000.json','["爲探梅魁策蹇馿，竹梢疏處見清癯。", "清香雅韻十分足，俗態囂塵一點無。", "寄我誰能如陸凱，愛渠自謂若林逋。", "夜窗却恐勞清夢，速剪寒梢浸玉壺。"]'),
('4c821b51-c2cb-44c0-a84f-fa4111dfe254','詠梅  其四','陳亮','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u548f\u7269", "\u6885\u82b1", "\u6292\u6000", "\u548f\u7269\u8bd7"]','疏枝橫玉瘦，小萼點珠光。',48,'全唐诗/poet.song.164000.json','["疏枝橫玉瘦，小萼點珠光。", "一朵忽先發，百花皆後香。", "欲傳春信息，不怕雪埋藏。", "玉笛休三弄，東君政主張。"]'),
('d1b9e660-de2f-4e3e-8f82-2a513d9d79c8','贈劉改之','陳亮','宋','宋诗','song-poetry','','[]','劉郎飲酒如渴虹，一飲澗壑俱成空。',192,'全唐诗/poet.song.164000.json','["劉郎飲酒如渴虹，一飲澗壑俱成空。", "胸中磊磈澆不下，時吐勁氣噓青紅。", "劉郎吟詩如飲酒，淋漓醉墨濡其首。", "笑鞭列缺起豐隆，變化風雷一揮手。", "吟詩飲酒總餘事，試問劉郎一何有。", "劉郎才如萬乘器，落濩輪囷難自致。", "彊親舉予作書生，却笑書生敗人意。", "合騎快馬健如龍，少年追逐曹景宗。", "弓弦霹靂餓鴞叫，鼻尖出火耳生風。", "安能規行復矩步，斂袂厭厭作新婦。", "黄金揮盡氣愈張，男兒龍變那可量。", "會須斫取契丹首，金甲牙旗歸故鄉。"]'),
('2fe4ffb2-5e83-401f-9da0-c863273bca0e','壽曾主管  其一','陳亮','宋','宋诗','song-poetry','','[]','累世名稱閥閲高，搢紳維復似英豪。',64,'全唐诗/poet.song.164000.json','["累世名稱閥閲高，搢紳維復似英豪。", "宏才咸許致千里，小試先觀夢四刀。", "方正寧容遷嶽麓，清明端可鑒絲毫。", "文章政事傳家美，須信池中有鳳毛。"]'),
('bdd6421e-e196-49df-ab7a-7d176620306b','壽曾主管  其二','陳亮','宋','宋诗','song-poetry','','[]','豫章此夕誕賢良，非霧非煙遶畫堂。',64,'全唐诗/poet.song.164000.json','["豫章此夕誕賢良，非霧非煙遶畫堂。", "正是庭蘭爭秀發，更當隴麥弄輕黄。", "一杯爲壽滄溟窄，萬口同詞日月長。", "朝晚定知歸禁近，千年常得侍清光。"]'),
('a455cb1c-356f-47a0-a867-2a263ddfc914','送文子徐妹丈赴隨州太學掾用司馬文正公送先郎中詩韵爲別','陳亮','宋','宋诗','song-poetry','','[]','昔仰南洲德，今逢世嗣賢。',48,'全唐诗/poet.song.164000.json','["昔仰南洲德，今逢世嗣賢。", "聲名江左重，文教漢東專。", "君意思空馬，吾生肯絕弦。", "江頭無語處，一葉浪花前。"]'),
('b347c578-c797-4675-bfd7-64d6cbaed917','送文子赴闕','陳亮','宋','宋诗','song-poetry','','[]','直排閶闔挽天潢，到得雲章自帝鄉。',64,'全唐诗/poet.song.164000.json','["直排閶闔挽天潢，到得雲章自帝鄉。", "電抉雷掀驚偉特，韵成鈞奏快鏗鏘。", "紫泥新拜絲綸寵，前席行依日月光。", "禁侍燕閑如獻納，願將民瘼達君王。"]'),
('7076abcc-84b3-4028-8ab5-6cc3fe9d64cc','送文子轉漕江東二首  其一','陳亮','宋','宋诗','song-poetry','','[]','九重寤寐憶忠誠，故向長沙起賈生。',64,'全唐诗/poet.song.164000.json','["九重寤寐憶忠誠，故向長沙起賈生。", "魏闕絲綸新借寵，秦淮草木舊知名。", "已聞塞下銷鋒鏑，正自胸中有甲兵。", "萬幕從茲無減竈，笑看卧鼓舊邊城。"]'),
('f5754e3c-e787-4026-ae87-e601435c14a9','送文子轉漕江東二首  其二','陳亮','宋','宋诗','song-poetry','','[]','詔頒英簜促鋒車，暫借長才按轉輸。',64,'全唐诗/poet.song.164000.json','["詔頒英簜促鋒車，暫借長才按轉輸。", "昔嘆當年無李牧，今知江左有夷吾。", "休論足食爲先策，自是平戎在用儒。", "來歲春風三月暮，沙堤隠隠接雲衢。"]'),
('aaeb699c-04fa-46c7-b292-f836120500a5','姑蘇臺同年會次袁說友韻','趙彥真','宋','宋诗','song-poetry','','[]','杏園名勝與春違，落落晨星入望稀。',64,'全唐诗/poet.song.164000.json','["杏園名勝與春違，落落晨星入望稀。", "百里我方欣際遇，二天公正許馮依。", "繡衣俱近雲霄路，綺席聊分山水暉。", "已幸光華參末至，鳳池行且看雙飛。"]'),
('acd51179-3c0a-4e6a-82ec-52ca211727dd','湘中','詹體仁','宋','宋诗','song-poetry','','[]','天寒楚雲浄，木落湘山幽。',48,'全唐诗/poet.song.164000.json','["天寒楚雲浄，木落湘山幽。", "空江夜來雨，水滿蘆花洲。", "西風何渺渺，滄波日悠悠。", "有懷誰與言，注目孤鴻秋。"]'),
('4d1509f3-9d01-480b-b608-f54aff4c8952','昔遊詩','詹體仁','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭八百里，玉盤盛水銀。',84,'全唐诗/poet.song.164000.json','["洞庭八百里，玉盤盛水銀。", "長虹忽照影，大哉五色輪。", "我舟渡其中，晃晃驚我神。", "朝發黄陵祠，暮至赤沙曲。", "借問此何處，滄灣三十六。", "青蘆望不盡，明月耿如燭。", "灣灣無人家，只就蘆花宿。"]'),
('b792a9cf-8f18-423f-b7b0-195c51741607','宿蘭溪水驛前','詹體仁','宋','宋诗','song-poetry','','[]','合眼波吹枕，開篷月入船。',48,'全唐诗/poet.song.164000.json','["合眼波吹枕，開篷月入船。", "奇哉一江水，寫此二更天。", "剩欲酣清賞，翻愁敗醉眠。", "今宵懷昨夕，雨卧萬峰前。"]'),
('913892b1-e2ed-4b9c-8291-043f211ec90d','江夏寓興','詹體仁','宋','宋诗','song-poetry','','[]','風與檣烏便，儂先塞雁來。',48,'全唐诗/poet.song.164000.json','["風與檣烏便，儂先塞雁來。", "山經七澤斷，潮自九江回。", "漁父猶知隠，騷人枉衒才。", "朋從正相遠，梅信爲誰開。"]'),
('bcf17c06-0157-4a8b-ab62-8a5c5a43741e','過廣陵驛','詹體仁','宋','宋诗','song-poetry','','[]','秋風江上芙蓉老，階下數株黄菊鮮。',64,'全唐诗/poet.song.164000.json','["秋風江上芙蓉老，階下數株黄菊鮮。", "落葉正飛揚子渡，行人又上廣陵船。", "寒砧萬戶月如水，老雁一聲霜滿天。", "自笑棲遲淮海客，十年心事一燈前。"]'),
('32378400-1326-4709-8ed0-62be0b77f71e','登岳陽樓','詹體仁','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','洞岳之東江水西，簾旌不動夕陽遲。',64,'全唐诗/poet.song.164000.json','["洞岳之東江水西，簾旌不動夕陽遲。", "登臨吳蜀橫分地，徙倚湖山欲暮時。", "萬里來遊還望遠，三年多難更凭危。", "白頭弔古霜風裏，老木蒼波無限悲。"]'),
('f4ec3047-e5ec-457e-a2a2-2b6329f264c4','解組自樂','詹體仁','宋','宋诗','song-poetry','','[]','去日春蠶吐素絲，歸來黄麥看金衣。',32,'全唐诗/poet.song.164000.json','["去日春蠶吐素絲，歸來黄麥看金衣。", "沙鷗不入鴛鴻侶，依舊滄浪繞釣磯。"]'),
('41718d70-6bd7-4c44-95a7-eb5d22034659','遊南臺閩粵王廟','詹體仁','宋','宋诗','song-poetry','','[]','海角釣龍人杳杳，雲間待雁路迢迢。',32,'全唐诗/poet.song.164000.json','["海角釣龍人杳杳，雲間待雁路迢迢。", "若爲借得山頭石，每到商秋坐看潮。"]'),
('38878928-7c57-42b8-95f7-63745848737b','幽居','詹體仁','宋','宋诗','song-poetry','','[]','投老安閑世味疏，深深水竹葺幽居。',32,'全唐诗/poet.song.164000.json','["投老安閑世味疏，深深水竹葺幽居。", "牀頭昨夜風吹落，多是經年未報書。"]'),
('4ad10122-da72-444b-be4f-918a24b59e14','姑蘇臺同年會次袁說友韻','詹體仁','宋','宋诗','song-poetry','','[]','秋鴻社燕巧相違，從古交遊會合稀。',64,'全唐诗/poet.song.164000.json','["秋鴻社燕巧相違，從古交遊會合稀。", "海內弟兄今有幾，吳中賢士得相依。", "已消桃李爭春意，且向桑榆共夕暉。", "回首慈恩舊題處，年華心事逐雲飛。"]'),
('8d120317-5428-4cda-9cbf-1a7a41990e42','登浮光四望亭','王柟','宋','宋诗','song-poetry','','[]','長年忍淚說中原，望徹中原隔戍垣。',64,'全唐诗/poet.song.164000.json','["長年忍淚說中原，望徹中原隔戍垣。", "誰遣江淮限南北，從來宇宙一乾坤。", "功名紙上徒虛語，歲月誰邊恐斷魂。", "老矣叫閽無處所，倚空長劍與誰論。"]'),
('e37752ff-a242-47a0-a007-34c86c6ea3a4','觀梅','王柟','宋','宋诗','song-poetry','','[]','誰見梅花正發時，江天雪意欲垂垂。',64,'全唐诗/poet.song.164000.json','["誰見梅花正發時，江天雪意欲垂垂。", "疏枝冷蕊春無幾，斷水殘雲意自奇。", "疏影偶因明月見，暗香惟有好風知。", "何人更起調羹手，莫道功成結子遲。"]'),
('e639cafd-046c-40da-8cb0-4a478e78a8da','南康泊舟欲遊廬山值雪','王柟','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','春風浩蕩江湖客，咫尺廬山風雨急。',32,'全唐诗/poet.song.164000.json','["春風浩蕩江湖客，咫尺廬山風雨急。", "門前老樹最關情，一夜相思頭盡白。"]'),
('64de608d-73ae-4d7e-b147-398b4c90af93','送留正知贛州','傅伯成','宋','宋诗','song-poetry','','[]','尚書鎮章江，慈母懷嬰兒。',60,'全唐诗/poet.song.164000.json','["尚書鎮章江，慈母懷嬰兒。", "去年甫去郡，未覺棠陰移。", "如何失調馭，衆目驚睽睽。", "詔書念前績，趣起持州麾。", "重臨亦云寵，去後良多思。"]'),
('ae53be43-9ee9-447b-a88f-4edfd06ad8fe','素馨花','傅伯成','宋','宋诗','song-poetry','','[]','昔日雲鬟鎖翠屏，只今烟冢伴荒城。',32,'全唐诗/poet.song.164000.json','["昔日雲鬟鎖翠屏，只今烟冢伴荒城。", "香魂斷續無人問，空有幽花獨擅名。"]'),
('8b0a87f7-1cf0-4049-8385-e4260a9cb815','五峰巖','傅伯成','宋','宋诗','song-poetry','','[]','山中亦何有，煙雲扶層梯。',24,'全唐诗/poet.song.164000.json','["山中亦何有，煙雲扶層梯。", "疊石撫空罅，洞水涵清漪。"]'),
('d8eec1c2-e964-4225-aeb6-8ba8580333c1','擬和元夕御製','傅伯成','宋','宋诗','song-poetry','','[]','萬戶千門綉作團，未央宮闕聳巑岏。',64,'全唐诗/poet.song.164000.json','["萬戶千門綉作團，未央宮闕聳巑岏。", "燈花無數排金粟，月魄當空倚扇紈。", "香繞御爐煙羃羃，玉瑶仙佩響珊珊。", "遊人共說歸來晚，一枕鈞天好夢殘。"]'),
('73a8e3b5-bc37-4f33-a2a6-d4bd8e6b27a5','擬和元夕御詩','傅伯成','宋','宋诗','song-poetry','','[]','元夜新添一月春，麴輕花嫩未成塵。',64,'全唐诗/poet.song.164000.json','["元夜新添一月春，麴輕花嫩未成塵。", "笙歌滿地醉還醒，樓閣中天奐且輪。", "新樂妙如儀鳳舞，遠人動似塞鴻賓。", "不知湛露恩多少，但見三韓拜舞頻。"]'),
('451e9ef6-c4c9-4cc8-a3db-ce514d3057a1','句','傅伯成','宋','宋诗','song-poetry','','[]','歲晚松篁期苦節，春光桃李任多情。',16,'全唐诗/poet.song.164000.json','["歲晚松篁期苦節，春光桃李任多情。"]'),
('e10d5023-e433-4213-abf1-22a64980ceb7','右軍祠堂','高祖之','宋','宋诗','song-poetry','','[]','一麾東晉守，八體入神書。',48,'全唐诗/poet.song.164000.json','["一麾東晉守，八體入神書。", "墨水傳遺蹟，蘭亭表舊居。", "挂冠高興逸，坦腹舊牀虛。", "峻嶺崇山景，依然想似初。"]'),
('ced14cb5-22db-483b-9cf1-dc7e58f47aba','臨終偈','張道成','宋','宋诗','song-poetry','','[]','七十四年命幻身，臨行動衆動群倫。',50,'全唐诗/poet.song.164000.json','["七十四年命幻身，臨行動衆動群倫。", "鳴鐘擊鼓渾閑事，一點圓明不動真。", "咦!擘破乾坤一玄牝，挐將日影掛林梢。"]'),
('ce1c3509-46b3-413a-b0bb-e64a2697c832','敬贊月林觀禪師  其一','陳貴謙','宋','宋诗','song-poetry','','[]','示現人間忍辱仙，單提獨弄祖師禪。',32,'全唐诗/poet.song.164000.json','["示現人間忍辱仙，單提獨弄祖師禪。", "生涯一鉢無安處，惟有聲名萬古傳。"]'),
('2d962d47-927f-4aa0-a1f3-015fca91051a','敬贊月林觀禪師  其二','陳貴謙','宋','宋诗','song-poetry','','[]','傳得西林夜半衣，解將鐵笛逆風吹。',32,'全唐诗/poet.song.164000.json','["傳得西林夜半衣，解將鐵笛逆風吹。", "重重話墮全擔荷，青出於藍只自知。"]'),
