('b570659e-1e5c-445a-85cc-a77fd9db403b','偈頌七十六首  其四○','釋師觀','宋','宋诗','song-poetry','','[]','時不待人，月不破五。',20,'全唐诗/poet.song.164000.json','["時不待人，月不破五。", "那一著子，未敢相許。"]'),
('a59f5b56-1c71-4052-9f2f-7332c1b5ab20','偈頌七十六首  其四一','釋師觀','宋','宋诗','song-poetry','','[]','驀直驀直，青天白日。',20,'全唐诗/poet.song.164000.json','["驀直驀直，青天白日。", "勘破了也，一文不直。"]'),
('c708315c-e9b7-40a8-bdf1-939c6b25e274','偈頌七十六首  其四二','釋師觀','宋','宋诗','song-poetry','','[]','開池不待月，池成月自來。',24,'全唐诗/poet.song.164000.json','["開池不待月，池成月自來。", "寒山逢拾得，拊掌笑咍咍。"]'),
('cc0c470a-df5e-4b9d-9ca8-d2b8fc642da9','偈頌七十六首  其四三','釋師觀','宋','宋诗','song-poetry','','[]','如來結制日，諸緣俱頓息。',34,'全唐诗/poet.song.164000.json','["如來結制日，諸緣俱頓息。", "九十日長期，衲僧口掛壁。", "咄，正是黑牛卧死水。"]'),
('68c1d49c-6813-4e38-bbd7-940d3235919f','偈頌七十六首  其四四','釋師觀','宋','宋诗','song-poetry','','[]','薰風自南來，殿閣生微凉。',24,'全唐诗/poet.song.164000.json','["薰風自南來，殿閣生微凉。", "要知端的意，拄杖爲敷揚。"]'),
('10214b76-72cb-4063-be05-4cd87f7cd139','偈頌七十六首  其四五','釋師觀','宋','宋诗','song-poetry','','[]','上元佳節是今日，匝地普天星斗出。',32,'全唐诗/poet.song.164000.json','["上元佳節是今日，匝地普天星斗出。", "好向機先著眼看，莫教蹉過然燈佛。"]'),
('b2ba14da-c0e5-4874-a87d-622dded6a795','偈頌七十六首  其四六','釋師觀','宋','宋诗','song-poetry','','[]','伎倆有盡，我默無窮。',20,'全唐诗/poet.song.164000.json','["伎倆有盡，我默無窮。", "達磨不識，眼瞎耳聾。"]'),
('e35d7a63-0a72-431f-a2df-76c13905ada7','偈頌七十六首  其四七','釋師觀','宋','宋诗','song-poetry','','[]','開眼見明，合眼見暗。',36,'全唐诗/poet.song.164000.json','["開眼見明，合眼見暗。", "開眼合眼，知而故犯。", "一毫頭上現乾坤，堪笑雲門咦顧鑑。"]'),
('e5a5ea37-6048-42d4-bd8d-ff1df4812cd2','偈頌七十六首  其四八','釋師觀','宋','宋诗','song-poetry','','[]','南泉水牯自天然，隨分些些任變遷。',32,'全唐诗/poet.song.164000.json','["南泉水牯自天然，隨分些些任變遷。", "長嘯一聲天地窄，了無佛法與人傳。"]'),
('8907d7b7-b6df-4e2d-a6dc-c829b199c5af','偈頌七十六首  其四九','釋師觀','宋','宋诗','song-poetry','','[]','秋風冷，秋桂香。',54,'全唐诗/poet.song.164000.json','["秋風冷，秋桂香。", "秋露白，秋葉黄。", "秋蛩吟，聲短長。", "此時景，有餘光。", "便恁麽去，正好喫棒。", "須知遠烟浪，刖有好商量。"]'),
('3ba26d94-024e-4dc8-b43a-9807c7949e95','偈頌七十六首  其五○','釋師觀','宋','宋诗','song-poetry','','[]','今朝七月一，解夏半月日。',36,'全唐诗/poet.song.164000.json','["今朝七月一，解夏半月日。", "摩挲拄杖子，笠頭勤拂拭。", "狗子無佛性，一文也不直。"]'),
('795e0e59-9ae2-4f5b-b2a5-4941d6af1096','偈頌七十六首  其五一','釋師觀','宋','宋诗','song-poetry','','[]','時節若至，其理自彰。',22,'全唐诗/poet.song.164000.json','["時節若至，其理自彰。", "一番新雨過，禾稻弄微黄。"]'),
('3a543a76-a378-4a29-a2a4-d76fb4c31c9e','偈頌七十六首  其五二','釋師觀','宋','宋诗','song-poetry','','[]','雲門有一曲，臘月二十五。',34,'全唐诗/poet.song.164000.json','["雲門有一曲，臘月二十五。", "拍拍是令，全身裏許。", "阿呵呵，萬像森羅齊作舞。"]'),
('0f5d5063-13c7-4d3a-9dae-2daf25b78dfa','偈頌七十六首  其五三','釋師觀','宋','宋诗','song-poetry','','[]','梵志翻著襪，是人皆道錯。',37,'全唐诗/poet.song.164000.json','["梵志翻著襪，是人皆道錯。", "寧可刺你眼，不可癮我脚。", "莫莫，醍醐上味，翻成毒藥。"]'),
('d1342311-7c7f-43f0-819a-0956129b05c9','偈頌七十六首  其五四','釋師觀','宋','宋诗','song-poetry','','[]','收麥纔了插秧來，終日忙忙安在哉。',32,'全唐诗/poet.song.164000.json','["收麥纔了插秧來，終日忙忙安在哉。", "直下更無回避所，優鉢羅花當處開。"]'),
('7f195480-f834-461b-999c-fee7da826af3','偈頌七十六首  其五五','釋師觀','宋','宋诗','song-poetry','','[]','前念是凡，後念是聖。',36,'全唐诗/poet.song.164000.json','["前念是凡，後念是聖。", "脫體無依，因邪打正。", "須彌頂上擊金鐘，七佛如來合掌聽。"]'),
('a426849a-8c91-4847-a4e5-913a0d96dc18','偈頌七十六首  其五六','釋師觀','宋','宋诗','song-poetry','','[]','萬里無寸草，衲僧何處討。',24,'全唐诗/poet.song.164000.json','["萬里無寸草，衲僧何處討。", "蘸雪喫冬瓜，誰知滋味好。"]'),
('1332139a-cb9f-440a-bba2-7f4c6bc684ab','偈頌七十六首  其五七','釋師觀','宋','宋诗','song-poetry','','[]','撾動禾山鼓，吹起少林笛。',33,'全唐诗/poet.song.164000.json','["撾動禾山鼓，吹起少林笛。", "當機覿面提，覿面當機疾。", "咄，一任風吹日炙。"]'),
('c6a04052-b1be-4200-9453-b5035539d5f0','偈頌七十六首  其五八','釋師觀','宋','宋诗','song-poetry','','[]','晷運推移，日南長至。',36,'全唐诗/poet.song.164000.json','["晷運推移，日南長至。", "自古自今，同天同地。", "靈山一會尚儼然，雷音堂中談不二。"]'),
('07cb030c-7301-4285-8801-ceffb24d165c','偈頌七十六首  其五九','釋師觀','宋','宋诗','song-poetry','','[]','孤雲野鶴，何天不飛。',20,'全唐诗/poet.song.164000.json','["孤雲野鶴，何天不飛。", "這一句子，同道方知。"]'),
('a3fd11cd-82cb-4f31-8d40-38c4117f307f','偈頌七十六首  其六○','釋師觀','宋','宋诗','song-poetry','','[]','礙處非牆壁，通處沒虛空。',24,'全唐诗/poet.song.164000.json','["礙處非牆壁，通處沒虛空。", "雙關俱透徹，別是一家風。"]'),
('f5c258d8-733d-4c1d-8f0c-dda42567758c','偈頌七十六首  其六一','釋師觀','宋','宋诗','song-poetry','','[]','葛公住此山，此山湛如藍。',24,'全唐诗/poet.song.164000.json','["葛公住此山，此山湛如藍。", "只今何處去，猶自口喃喃。"]'),
('bdbf3b0d-db20-40b6-8c18-19a596864401','偈頌七十六首  其六二','釋師觀','宋','宋诗','song-poetry','','[]','月已破五，年又過半。',36,'全唐诗/poet.song.164000.json','["月已破五，年又過半。", "拄杖拈來，如何判斷。", "百年三萬六千日，也是秦時𨍏轢鑽。"]'),
('c241f556-fb00-4bdb-ab49-9012ae485dac','偈頌七十六首  其六三','釋師觀','宋','宋诗','song-poetry','','[]','此世不移動，彼世不改變。',42,'全唐诗/poet.song.164000.json','["此世不移動，彼世不改變。", "當處發生，隨處滅盡。", "阿呵呵，見不見，秋風一陣來，落葉兩三片。"]'),
('26cb4101-39f8-49c1-a5e7-c330f4b5c33b','偈頌七十六首  其六四','釋師觀','宋','宋诗','song-poetry','','[]','問訊燒香，閑行靜坐。',20,'全唐诗/poet.song.164000.json','["問訊燒香，閑行靜坐。", "與麽分明，是箇什麽。"]'),
('f0cd8b9a-412e-4b63-88ad-ce6786d9ea5e','偈頌七十六首  其六五','釋師觀','宋','宋诗','song-poetry','','[]','一日不作，一日不食。',50,'全唐诗/poet.song.164000.json','["一日不作，一日不食。", "木平搬土，石霜泥壁。", "洪山斷足，仰山作息。", "澄翠門下，朝朝入室。", "如上所供，並皆詣實。"]'),
('006b7f36-d30f-4534-8e9d-0099080acd81','偈頌七十六首  其六六','釋師觀','宋','宋诗','song-poetry','','[]','臘盡春至，頭頭顯示。',28,'全唐诗/poet.song.164000.json','["臘盡春至，頭頭顯示。", "雪裏梅花，馨香撲鼻。", "認著依前還不是。"]'),
('c665c92e-74c7-4161-b446-503b9abb8a43','偈頌七十六首  其六七','釋師觀','宋','宋诗','song-poetry','','[]','一九與二九，相逢不出手。',24,'全唐诗/poet.song.164000.json','["一九與二九，相逢不出手。", "因甚不出手，免見揚家醜。"]'),
('b7cd8e8c-5950-4462-bf7a-fee64844b3f9','偈頌七十六首  其六八','釋師觀','宋','宋诗','song-poetry','','[]','山奇水秀洞中天，與麽分明知幾年。',32,'全唐诗/poet.song.164000.json','["山奇水秀洞中天，與麽分明知幾年。", "左右逢源無限意，幾人於此徹根源。"]'),
('71b8f4ea-c5a3-4fe5-af86-ac3713ef995e','偈頌七十六首  其六九','釋師觀','宋','宋诗','song-poetry','','[]','法法本來法，無法無非法。',28,'全唐诗/poet.song.164000.json','["法法本來法，無法無非法。", "這箇是烏回拄杖子，那箇是本來法。"]'),
('7e53560c-b541-47f2-84ef-735c5b94ad39','偈頌七十六首  其七○','釋師觀','宋','宋诗','song-poetry','','[]','昨日入院，今朝設粥。',28,'全唐诗/poet.song.164000.json','["昨日入院，今朝設粥。", "齋罷喫茶，參前澡浴。", "箇是靈山親付囑。"]'),
('a420dacb-e1b9-4631-9162-a9ce1a68e34c','偈頌七十六首  其七一','釋師觀','宋','宋诗','song-poetry','','[]','朝朝相似，日日一般。',27,'全唐诗/poet.song.164000.json','["朝朝相似，日日一般。", "年窮歲盡，盡底掀翻。", "依舊孟春猶寒。"]'),
('53842ad7-98b2-479b-baba-a6fb6850c571','偈頌七十六首  其七二','釋師觀','宋','宋诗','song-poetry','','[]','人笑鵓鳩拙，鵓鳩自不拙。',32,'全唐诗/poet.song.164000.json','["人笑鵓鳩拙，鵓鳩自不拙。", "兩莖柴子上，一生打得徹。", "打刀須是并州鐵。"]'),
('bb53fb76-9ec3-4341-a319-3bd4f71378e4','偈頌七十六首  其七三','釋師觀','宋','宋诗','song-poetry','','[]','今朝四月一，結夏又在即。',24,'全唐诗/poet.song.164000.json','["今朝四月一，結夏又在即。", "若是到家人，日日是好日。"]'),
('82d279c1-1480-40f8-9b66-089a253ea117','偈頌七十六首  其七四','釋師觀','宋','宋诗','song-poetry','','[]','鶴立松梢月，魚行水底天。',40,'全唐诗/poet.song.164000.json','["鶴立松梢月，魚行水底天。", "風光都買盡，不費一文錢。", "須知此語無窮日，只恐滄溟有盡年。"]'),
('4a1b717b-da0e-474f-9c14-d60df74e77c8','偈頌七十六首  其七五','釋師觀','宋','宋诗','song-poetry','','[]','今日十，昨日九。',34,'全唐诗/poet.song.164000.json','["今日十，昨日九。", "日來日往，阿誰知有。", "未了之人聽一言，只這而今誰動口。"]'),
('3d51e7b0-29a1-4f5c-a58f-b70492873546','偈頌七十六首  其七六','釋師觀','宋','宋诗','song-poetry','','[]','來時無蹤，去時無跡。',20,'全唐诗/poet.song.164000.json','["來時無蹤，去時無跡。", "七十五年，青天霹靂。"]'),
('e264693b-93b0-42af-b096-8a51a30549d0','頌古十七首  其一','釋師觀','宋','宋诗','song-poetry','','[]','指天指地，無處回避。',20,'全唐诗/poet.song.164000.json','["指天指地，無處回避。", "瞿曇瞿曇，討甚巴鼻。"]'),
('e4447b47-f89c-40d4-aa54-885581ad52f2','頌古十七首  其二','釋師觀','宋','宋诗','song-poetry','','[]','青天霹靂，何處尋覓。',20,'全唐诗/poet.song.164000.json','["青天霹靂，何處尋覓。", "一人傳虛，萬人傳實。"]'),
('97d61d8b-0a96-4efc-90c9-19592dbccbab','頌古十七首  其三','釋師觀','宋','宋诗','song-poetry','','[]','以此爲津梁，赤體露堂堂。',24,'全唐诗/poet.song.164000.json','["以此爲津梁，赤體露堂堂。", "風光都買盡，當處是家鄉。"]'),
('5f185fa0-dc46-4f56-97d1-78a7fe0ad3b9','頌古十七首  其四','釋師觀','宋','宋诗','song-poetry','','[]','青出於藍，而青於藍。',20,'全唐诗/poet.song.164000.json','["青出於藍，而青於藍。", "坐籌帷幄，鍛聖鎔凡。"]'),
('71ec0d1d-63a6-402e-bb3f-52440a79aba2','頌古十七首  其五','釋師觀','宋','宋诗','song-poetry','','[]','伶利道人何處去，至今尋覓杳無蹤。',32,'全唐诗/poet.song.164000.json','["伶利道人何處去，至今尋覓杳無蹤。", "有時冷地思量著，不覺全身在碧峰。"]'),
('d08e3bcb-e2f4-4136-8a90-9ed7e19319f0','頌古十七首  其六','釋師觀','宋','宋诗','song-poetry','','[]','張打油，李打油，不打渾身只打頭。',32,'全唐诗/poet.song.164000.json','["張打油，李打油，不打渾身只打頭。", "今朝有酒今朝醉，明日愁來明日愁。"]'),
('e7d6efd0-f6cd-4e9f-aba8-489c9642cc77','頌古十七首  其七','釋師觀','宋','宋诗','song-poetry','','[]','傀儡棚頭，全火祗候。',20,'全唐诗/poet.song.164000.json','["傀儡棚頭，全火祗候。", "明眼人前，一場漏逗。"]'),
('b76c49cd-2252-44eb-90ab-505c333ff0a3','頌古十七首  其八','釋師觀','宋','宋诗','song-poetry','','[]','趙州喚作火，全身入荒草。',24,'全唐诗/poet.song.164000.json','["趙州喚作火，全身入荒草。", "我今不是渠，渠今正是我。"]'),
('3bbc88f6-3d41-43c3-8de0-6e9220d62b78','頌古十七首  其九','釋師觀','宋','宋诗','song-poetry','','[]','出乎爾者返乎爾，箇裏那容說道理。',32,'全唐诗/poet.song.164000.json','["出乎爾者返乎爾，箇裏那容說道理。", "蹈雪沽來酒倍香，就船買得魚偏美。"]'),
('621a7e92-e338-455a-a6ce-48cc1d590380','頌古十七首  其一○','釋師觀','宋','宋诗','song-poetry','','[]','乾坤獨立，從者裏入。',20,'全唐诗/poet.song.164000.json','["乾坤獨立，從者裏入。", "風吹不著，雨打不濕。"]'),
('ce14fe69-3c45-4c63-8484-97dc91f51737','頌古十七首  其一一','釋師觀','宋','宋诗','song-poetry','','[]','報慈一隔，描邈不得。',20,'全唐诗/poet.song.164000.json','["報慈一隔，描邈不得。", "大用現前，不存軌則。"]'),
('09ad2114-94ce-4a3b-9a0a-8d399127ff77','頌古十七首  其一二','釋師觀','宋','宋诗','song-poetry','','[]','臘月火燒山，毫髮不相瞞。',24,'全唐诗/poet.song.164000.json','["臘月火燒山，毫髮不相瞞。", "佛手遮不得，人心似等閑。"]'),
('619b8fd4-1ba8-4f34-bc13-661c6aadae6f','頌古十七首  其一三','釋師觀','宋','宋诗','song-poetry','','[]','虛空迸裂，當處超越。',20,'全唐诗/poet.song.164000.json','["虛空迸裂，當處超越。", "堪笑雲門，多這一橛。"]'),
('6e32effe-3959-4985-9c38-c448f8677a50','頌古十七首  其一四','釋師觀','宋','宋诗','song-poetry','','[]','見成活許莫周遮，椎下分疎事轉差。',32,'全唐诗/poet.song.164000.json','["見成活許莫周遮，椎下分疎事轉差。", "若是咬人獅子子，何須牙上更安牙。"]'),
('97ade334-7820-4ac6-92e4-8797a1ec5f44','頌古十七首  其一五','釋師觀','宋','宋诗','song-poetry','','[]','不是風兮不是幡，入泥入水與人看。',32,'全唐诗/poet.song.164000.json','["不是風兮不是幡，入泥入水與人看。", "莫把是非來辨我，浮生穿鑿不相干。"]'),
('6a05855c-d703-46ee-8a95-cb79392d1fab','頌古十七首  其一六','釋師觀','宋','宋诗','song-poetry','','[]','佛法王法，更無兩樣。',20,'全唐诗/poet.song.164000.json','["佛法王法，更無兩樣。", "直下一刀，未爲諦當。"]'),
('dc4dd02f-f5a8-4a9c-9b92-31be8a7f06ef','頌古十七首  其一七','釋師觀','宋','宋诗','song-poetry','','[]','唇上碧斑賓豹博，舌頭當的帝都丁。',32,'全唐诗/poet.song.164000.json','["唇上碧斑賓豹博，舌頭當的帝都丁。", "頻呼小玉元無事，只要檀郎認得聲。"]'),
('175075a7-9212-490a-865e-49b08931a31b','三教贊','釋師觀','宋','宋诗','song-poetry','','[]','一即三，三即一，者一箇，讚不及。',28,'全唐诗/poet.song.164000.json','["一即三，三即一，者一箇，讚不及。", "天人羣生類，皆承此恩力。"]'),
('146023c0-0dbc-4045-a39a-1e04495566c7','須菩提贊','釋師觀','宋','宋诗','song-poetry','','[]','老老大大，岩中宴坐。',20,'全唐诗/poet.song.164000.json','["老老大大，岩中宴坐。", "帝釋雨花，見箇什麽。"]'),
('c4486f83-cab0-4f16-8988-27259b63bedb','千手眼觀音贊','釋師觀','宋','宋诗','song-poetry','','[]','通身是，遍身是，觀世音，無盡意。',28,'全唐诗/poet.song.164000.json','["通身是，遍身是，觀世音，無盡意。", "願以此功德，普及於一切。"]'),
