('7a9dabc3-fe89-4c1f-b218-067d7115daf6','頌古三十三首  其二六','釋師觀','宋','宋诗','song-poetry','','[]','墮落眉鬚不得塔，三文使盡見分疎。',32,'全唐诗/poet.song.164000.json','["墮落眉鬚不得塔，三文使盡見分疎。", "無端大嶺重饒舌，數丈龜毛舉世無。"]'),
('d1167d31-9898-4f87-96d5-ef35ece35ed4','頌古三十三首  其二七','釋師觀','宋','宋诗','song-poetry','','[]','日裏看山好，好在什麽處。',24,'全唐诗/poet.song.164000.json','["日裏看山好，好在什麽處。", "要見老雲門，不落第二句。"]'),
('3213f147-f538-4a5c-8149-67167bad995d','頌古三十三首  其二八','釋師觀','宋','宋诗','song-poetry','','[]','一字入公門，九牛拔不出。',24,'全唐诗/poet.song.164000.json','["一字入公門，九牛拔不出。", "咄這野狐精，鼻孔都打失。"]'),
('f6a4cecc-256f-4d52-9ec4-ff47ab781d6a','頌古三十三首  其二九','釋師觀','宋','宋诗','song-poetry','','[]','要箇無禪底國師，纔涉毫芒便取誅。',32,'全唐诗/poet.song.164000.json','["要箇無禪底國師，纔涉毫芒便取誅。", "堪笑這僧垂手處，道無便見有偏枯。"]'),
('4286b6b5-487f-40fb-8fdf-60e110905da8','頌古三十三首  其三○','釋師觀','宋','宋诗','song-poetry','','[]','來說是非者，便是是非人。',24,'全唐诗/poet.song.164000.json','["來說是非者，便是是非人。", "誠哉是言也，弄物不知名。"]'),
('cdb67bb7-a0db-4fae-bef1-31b98ed31d5e','頌古三十三首  其三一','釋師觀','宋','宋诗','song-poetry','','[]','牛過窗櫺，錯爲安名。',20,'全唐诗/poet.song.164000.json','["牛過窗櫺，錯爲安名。", "大唐國裏，不見一人。"]'),
('cfa54d83-6cf7-4413-a75e-f2ae1384688f','頌古三十三首  其三二','釋師觀','宋','宋诗','song-poetry','','[]','馿放三千，馬放八百。',20,'全唐诗/poet.song.164000.json','["馿放三千，馬放八百。", "透過重關，未爲英傑。"]'),
('6b2fffce-3f60-4a81-9db9-ff9484a639ac','頌古三十三首  其三三','釋師觀','宋','宋诗','song-poetry','','[]','海神知貴不知價，留與人間光照夜。',32,'全唐诗/poet.song.164000.json','["海神知貴不知價，留與人間光照夜。", "碧眼胡僧笑點頭，誰知用處無縫罅。"]'),
('2ffecbb0-dba5-4371-a903-09eb47d8900b','東坡在惠州窘於衣食以重九近有樽俎蕭然之歎和淵明貧士七詩今去重九三日爾僕以新穀未升方絕糧是憂至於樽俎又未暇計也因誦靖節貧士詩及坡翁所和者輒復用韻  其一','趙蕃','宋','宋诗','song-poetry','','[]','故鄉墮渺茫，迺此窮山依。',72,'全唐诗/poet.song.164000.json','["故鄉墮渺茫，迺此窮山依。", "力業困乏資，蕭颯如秋暉。", "人生初無根，歲月著翼飛。", "更堪幾寒暑，蔓草真同歸。", "與懷死後名，不補身前饑。", "已矣勿多譚，寧能置深悲。"]'),
('6cf0cb89-5135-4214-83c0-5c8a8ab1198c','東坡在惠州窘於衣食以重九近有樽俎蕭然之歎和淵明貧士七詩今去重九三日爾僕以新穀未升方絕糧是憂至於樽俎又未暇計也因誦靖節貧士詩及坡翁所和者輒復用韻  其二','趙蕃','宋','宋诗','song-poetry','','[]','淵明生亂世，何意爭鶴軒。',72,'全唐诗/poet.song.164000.json','["淵明生亂世，何意爭鶴軒。", "念歸非一日，寓說因田園。", "不嗟瓶儲空，寧歎竈絕烟。", "聲名向千載，誰得加磨研。", "孟軻論尚友，我亦佩此言。", "古人未易誣，今代無茲賢。"]'),
('fdbb24ac-3150-46f4-9486-a51ff41e74f1','東坡在惠州窘於衣食以重九近有樽俎蕭然之歎和淵明貧士七詩今去重九三日爾僕以新穀未升方絕糧是憂至於樽俎又未暇計也因誦靖節貧士詩及坡翁所和者輒復用韻  其三','趙蕃','宋','宋诗','song-poetry','','[]','誰云鍾期死，伯牙遂忘琴。',72,'全唐诗/poet.song.164000.json','["誰云鍾期死，伯牙遂忘琴。", "淵明出晉宋，東坡作知音。", "究其出處間，岨峿皆直尋。", "和詩固亡恙，端若一手斟。", "我時誦其集，危坐常加欽。", "緬懷兩先生，千古同此心。"]'),
('c4a1234d-c615-45ab-bc76-6e7dbf1a0784','東坡在惠州窘於衣食以重九近有樽俎蕭然之歎和淵明貧士七詩今去重九三日爾僕以新穀未升方絕糧是憂至於樽俎又未暇計也因誦靖節貧士詩及坡翁所和者輒復用韻  其四','趙蕃','宋','宋诗','song-poetry','','[]','四皓逃商山，下視衣褐婁。',72,'全唐诗/poet.song.164000.json','["四皓逃商山，下視衣褐婁。", "不知建成客，孰與封君酬。", "夷齊古逸民，食粟猶耻周。", "何曾墮人計，圖安卒成憂。", "不然靖節翁，那與沮溺儔。", "顧于一日間，無羨斯無求。"]'),
('8c43a3b5-305b-4b24-bda9-8700bf3fe7af','東坡在惠州窘於衣食以重九近有樽俎蕭然之歎和淵明貧士七詩今去重九三日爾僕以新穀未升方絕糧是憂至於樽俎又未暇計也因誦靖節貧士詩及坡翁所和者輒復用韻  其五','趙蕃','宋','宋诗','song-poetry','','[]','去年迫重九，倦遊正長干。',72,'全唐诗/poet.song.164000.json','["去年迫重九，倦遊正長干。", "稅駕僧屋古，無從借船官。", "今年山中居，朝暮無續餐。", "朔身謾九尺，何時辭餒寒。", "貨殖賜何有，簞瓢未臞顔。", "因知昔人意，道勝貧非關。"]'),
('01b34df2-225f-49db-9be8-0d604d7f65ba','東坡在惠州窘於衣食以重九近有樽俎蕭然之歎和淵明貧士七詩今去重九三日爾僕以新穀未升方絕糧是憂至於樽俎又未暇計也因誦靖節貧士詩及坡翁所和者輒復用韻  其六','趙蕃','宋','宋诗','song-poetry','','[]','閒居起常早，倦巾首如蓬。',72,'全唐诗/poet.song.164000.json','["閒居起常早，倦巾首如蓬。", "偶繙西都書，意外文字工。", "清名誰爲高，凜凜惟楚龔。", "當時豈無人，罕與二子同。", "乃知士生世，不貴侯籍通。", "九原如可作，何憚執鞭從。"]'),
('d4578aa5-b505-45cc-a24b-c964bae2a1b4','東坡在惠州窘於衣食以重九近有樽俎蕭然之歎和淵明貧士七詩今去重九三日爾僕以新穀未升方絕糧是憂至於樽俎又未暇計也因誦靖節貧士詩及坡翁所和者輒復用韻  其七','趙蕃','宋','宋诗','song-poetry','','[]','昔在龐德公，有足不入州。',72,'全唐诗/poet.song.164000.json','["昔在龐德公，有足不入州。", "鸞鳳自有志，燕雀安可儔。", "迺知金石堅，不逐萬物流。", "當時天下事，固爲長者憂。", "未易一木支，殺身何能酬。", "令人爲短氣，哀哉融與修。"]'),
('935772bb-4883-4dca-9382-524efdfb2d89','謁文叔于松谷','趙蕃','宋','宋诗','song-poetry','','[]','鷄鳴戒柴車，月落到林寺。',120,'全唐诗/poet.song.164000.json','["鷄鳴戒柴車，月落到林寺。", "先生方睡美，童子驚客至。", "晨霜粲屋瓦，初日照平地。", "雖非贊公宿，似是超師誼。", "分携屬秋風，倏忽竟此歲。", "相望不爲遠，數見良不易。", "公行立朝班，我政親農耜。", "自茲出處殊，寧使心迹異。", "歡華一朝寵，風節千古事。", "要令松谷名，因公表於世。"]'),
('0fe8ebda-8a6d-4c8e-a457-bebd2820123b','自玉山歸竹隠投宿廣平院','趙蕃','宋','宋诗','song-poetry','','[]','久客倦城市，薄言歸田廬。',240,'全唐诗/poet.song.164000.json','["久客倦城市，薄言歸田廬。", "秣馬待日歛，顛風忽來俱。", "橫策徑成去，撲撲埃滿鬚。", "晴雷隠虛空，數雨如投珠。", "渴甚念茗飲，遲回尋梵居。", "少焉復前邁，行行過烟墟。", "但驚田疇間，有似槁復蘇。", "及經道途衝，餘流尚通渠。", "乃悟適來雨，咫尺或有無。", "天公本何心，分龍信非誣。", "自茲到吾棲，崗嶺更複迂。", "山窮偶逢寺，可以休僕痡。", "投鞍議食事，僅具粥一盂。", "道人吾故人，問我來崎嶇。", "既能設瓜果，村酒亦復沽。", "我愧非淵明，僧誠遠公徒。", "停杯竟高枕，夢境知何如。", "明當带星起，草露徒侵裾。", "還家一何忙，視竹齊架書。", "優哉且自適，休問瓶無儲。"]'),
('532d52f0-0775-4e92-b746-0e9871fa2ebc','遣興二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','秋清意自佳，况此山崦靜。',48,'全唐诗/poet.song.164000.json','["秋清意自佳，况此山崦靜。", "今晨風日暖，亦復起我病。", "叢深木樨多，激烈香成陣。", "何必薝蔔林，方能明佛性。"]'),
('73e3c3b5-be41-4ce4-a0d4-2d85dcd003dc','遣興二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','西風何從來，驚我庭下綠。',48,'全唐诗/poet.song.164000.json','["西風何從來，驚我庭下綠。", "竹君了不知，儼立若带束。", "山居陋無友，弔影唯吾僕。", "得此助婆娑，寧能嘆幽獨。"]'),
('8c5b9874-f120-4323-b47d-4bef2be7a0b0','寒夜曉起呈斯遠','趙蕃','宋','宋诗','song-poetry','','[]','黄昏月甚佳，夜半風忽起。',72,'全唐诗/poet.song.164000.json','["黄昏月甚佳，夜半風忽起。", "直疑天又變，况覺寒逾水。", "破衾不能溫，曲身豈復論。", "窗明亟問似，霜裏明朝暾。", "梅開何處樹，索莫誰能顧。", "被褐復扶筇，從君覓詩去。"]'),
('4fa343ad-e4a0-41a8-884c-7cd526ba1583','晨起','趙蕃','宋','宋诗','song-poetry','','[]','布衾失餘溫，紙窗啟微明。',48,'全唐诗/poet.song.164000.json','["布衾失餘溫，紙窗啟微明。", "霜粲萬瓦白，江可一葦橫。", "故園菊應荒，郢岸梅且榮。", "客遊胡滯留，歲事行崢嶸。"]'),
('fb50fec2-274b-42ef-838f-4eccc689868a','幽居','趙蕃','宋','宋诗','song-poetry','','[]','窗前亦何有，有槐儼而長。',48,'全唐诗/poet.song.164000.json','["窗前亦何有，有槐儼而長。", "植之自誰歟，花開幾經黄。", "那知窗中人，不作昔日忙。", "但戀六月蔭，超然傲羲皇。"]'),
('3ccf857e-7083-4c14-86d0-e251b4305306','得晴欲過江訪梅已忽病作天亦復陰悵然有賦','趙蕃','宋','宋诗','song-poetry','','[]','立春數日間，梅花未多睹。',240,'全唐诗/poet.song.164000.json','["立春數日間，梅花未多睹。", "書窗有折枝，每浸則微吐。", "殘編宵未眠，卯酒朝自舉。", "時聞遞幽香，似接譚妙語。", "林園何人家，厥地非容與。", "曾知將軍祠，老木瞰江滸。", "時中幾及之，欲往遭雪阻。", "莫要居士麯，但費先生楮。", "前朝得霜霽，决意喚鳴樐。", "肩輿已出門，邂逅謁吾侶。", "忽焉頭岑岑，歸卧更侵膂。", "或者瘧爲祟，又意瘴莫禦。", "杯鐺且棄置，藥餌事煎煮。", "豈唯病獨然，陰雲重彌宇。", "羲之嗜山水，誓墓不自許。", "涪翁訪岑公，亦歎連朝雨。", "世人肆貪求，妄意輒簪組。", "寧知一笑適，亦自有從拒。", "天雲會當開，我病亦應愈。", "但恐梅之花，蹁躚如化羽。"]'),
('91f7c50f-e1fa-4e45-af7d-ad28d2bb2894','從孫一昆仲求毗陵筆','趙蕃','宋','宋诗','song-poetry','','[]','宣城死諸葛，管城不中書。',120,'全唐诗/poet.song.164000.json','["宣城死諸葛，管城不中書。", "我無操舟長，顧病河流紆。", "朝來罷茶甌，閑詩念追摹。", "毛錐不勝任，一戰驚摧車。", "孫郎吳中回，此物富有餘。", "自云得祕法，蠹口絕覬覦。", "君今英妙年，賦成似相如。", "自宜給筆札，奏技承明廬。", "非如寒窗人，章句分錙銖。", "多貯竟胡爲，何妨稍遺余。"]'),
('7b88e1e9-e20e-4384-b5de-61a517da479c','遠齋作十二辰歌見贈且帥同作','趙蕃','宋','宋诗','song-poetry','','[]','蟲臂鼠肝能幾許，何如徑駕牛車去。',96,'全唐诗/poet.song.164000.json','["蟲臂鼠肝能幾許，何如徑駕牛車去。", "虎頭未必果癡絕，死穴舊來輸狡兔。", "先生端是人中龍，爲蛇畫足吾何功。", "士窮有愧食穀馬，况乃爛羊關內封。", "春風開花到猴李，白酒黄雞思下里。", "賦因狗監笑相如，豬肝不食寧爲說。"]'),
('1d58693c-ca85-40d9-94fa-316faaab76d4','題歸去來圖','趙蕃','宋','宋诗','song-poetry','','[]','淵明豈樂居巖藪，逢此百罹聊飲酒。',64,'全唐诗/poet.song.164000.json','["淵明豈樂居巖藪，逢此百罹聊飲酒。", "龔生未免不食亡，孔融竟落姦雄手。", "想見龍眠下筆時，佇目精神思尚友。", "開圖我亦有遺恨，不得執屨從其後。"]'),
('1738e42d-af59-4b3f-9f29-f431bd5b4052','送周仲材罷官還婺女侍旁','趙蕃','宋','宋诗','song-poetry','','[]','天風索索鳴枯桑，天寒自茲繁雪霜。',160,'全唐诗/poet.song.164000.json','["天風索索鳴枯桑，天寒自茲繁雪霜。", "故人別我向何許，蘭溪水深葦可杭。", "憶初識君上君堂，論交許參鴻雁行。", "三年還往少間斷，惠好如此宜毋忘。", "人生會合胡能常，君行我留增慨慷。", "雖云吳楚數驛地，書札便恐疎寄將。", "君才有如玉截肪，不待雕琢成文章。", "一官婆娑百僚底，衆謂寶器橫道旁。", "問君此去何其忙，金尊綵服樂未央。", "他年盛事一門見，父子持橐俱明光。"]'),
('d03d72aa-76b5-40fe-a891-b70ab237c76c','張信州禱晴輒應以詩賀之','趙蕃','宋','宋诗','song-poetry','','[]','舍東舍西繰車鳴，陂南陂北秧壠平。',128,'全唐诗/poet.song.164000.json','["舍東舍西繰車鳴，陂南陂北秧壠平。", "共期今年好春事，自茲無苦惟須晴。", "如何忽作十日雨，農夫輟耕病紅女。", "爾曹惴惴何足云，忍使憂形使君慮。", "人言水旱有常數，豐凶不假祈禳助。", "那知使君爲民爾，一念未萌神固許。", "朝來風色端何祥，溪流復故山屏張。", "欣然此屋盡和氣，使君之賜真無央。"]'),
('6e529d91-bc82-4471-823c-e71e2082d349','喜晴','趙蕃','宋','宋诗','song-poetry','','[]','春風吹晴簷雨止，蘭芽半吐梅堆委。',64,'全唐诗/poet.song.164000.json','["春風吹晴簷雨止，蘭芽半吐梅堆委。", "階前背蔭苔蘚深，曳杖不妨成細履。", "浮生憂喜均何如，誰能役役愁其軀。", "時閒意適且自慰，莫問詰朝瓶乏儲。"]'),
('c47ae422-3db3-4411-af3a-c97f87bd5903','樂歲歌','趙蕃','宋','宋诗','song-poetry','','[]','早禾登場無餘粒，晚禾結穟俱全實。',128,'全唐诗/poet.song.164000.json','["早禾登場無餘粒，晚禾結穟俱全實。", "如聞自入夏秋來，十日一雨晴五日。", "去年夏旱秋與同，早禾半穫晚禾空。", "未云收獲告畢工，十家九家愁歎中。", "豈知今年有豐殖，父子相安妻反室。", "東坡先生故嘗言，民自天民天定卹。", "我今千里方來歸，釋擔先題樂歲詩。", "其誰傳似閭里兒，乘時閉糴將安施。"]'),
('b5203ef7-a502-4241-9439-7d9889305719','落星寺','趙蕃','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我自廬山十五載，犇走坐受世迫隘。',128,'全唐诗/poet.song.164000.json','["我自廬山十五載，犇走坐受世迫隘。", "今年一夢落星灣，遥賞意短終不快。", "褰裳高步千仞岡，下視城郭等蓬塊。", "陰風遠來龍噫吟，大江東下波滂湃。", "遠游止爲兩眸計，扶杖深歎造物大。", "五老自是吾故人，一笑却恨浮雲礙。", "欲搜短句記來游，倚檻孤嘯上方外。", "康州涪翁我所師，借問遺碑悉安在。"]'),
('da7a396f-58d2-4da4-abd9-e7521eeacc55','過女兒浦','趙蕃','宋','宋诗','song-poetry','','[]','青山峩峩聳髻鬟，流水瑟瑟鳴佩環。',64,'全唐诗/poet.song.164000.json','["青山峩峩聳髻鬟，流水瑟瑟鳴佩環。", "朝雲暮雨在何許，秋月春風空自閒。", "予今老矣鬢且斑，行役殆遍江之南。", "舊遊渺邈大姑石，吾家側近丫頭巖。"]'),
('8354cd63-d3c0-4b89-b3cb-4d461ea90604','抵南康','趙蕃','宋','宋诗','song-poetry','','[]','江天漠漠江雲濕，江波浩浩江鷗急。',64,'全唐诗/poet.song.164000.json','["江天漠漠江雲濕，江波浩浩江鷗急。", "二十年間幾經歷，欲論舊事俱陳迹。", "舟人漁子笑且語，不知客子行路苦。", "今夜解帆落星渚，典衣市酒寬久旅。"]'),
('0ca8a807-fc69-4df3-bafc-d80fd18a0f86','成父以子進釀法爲酒酒成許分貺趣之以詩併呈子進昆仲','趙蕃','宋','宋诗','song-poetry','','[]','蘇仙盡飲不滿勺，平生願求酒方略。',368,'全唐诗/poet.song.164000.json','["蘇仙盡飲不滿勺，平生願求酒方略。", "空山松桂不使間，必使捐糜效斟酌。", "自言坐客有酣適，己雖獨醒同醉樂。", "是心可以付調元，歎息鄉來湖海著。", "邇來繼有孫夫子，文高飲少俱蘇若。", "如何喜釀又相似，叔敖典型亂今昨。", "談間快說酒中病，鏖戰如遇將軍霍。", "至其妙處殆神授，后稷播種神農藥。", "冬篘近撇不老泉，石室蘭溪望風却。", "我時籃輿適過之，靜掃玉亭供偃薄。", "呼童洗觴置我前，謂我多寡隨人各。", "詎須珠玉始脩容，濡唇頓爾忘諧謔。", "我云此乃酒御史，徑取橄欖充咀嚼。", "庶幾正味兩相類，祛我沉痾屏無作。", "我家是邦陋隨俗，白酒釀來纔宿諾。", "彼人固肯號茅柴，此意豈復知京洛。", "阿連聞道愈於我，換米急拋居士屩。", "不勞火齊撓妻孥，要與論功上麟閣。", "祇今旬月計已熟，沾溉况自有夙約。", "醉鄉道路久生梗，愁城疆界思開拓。", "便須健步速持似，預恐肴核窮搜索。", "梅公不與俗子對，我亦竹門無鎖鑰。", "但判醉倒更微吟，萬事休休還莫莫。"]'),
('27891b49-bb9d-45f1-828c-9b9085419f13','近乏筆託二張求之于市殊不堪也作長句以資一笑','趙蕃','宋','宋诗','song-poetry','','[]','詩老作詩窮欲死，序詩迺得歐陽氏。',384,'全唐诗/poet.song.164000.json','["詩老作詩窮欲死，序詩迺得歐陽氏。", "序言人窮詩迺工，此語不疑如信史。", "少陵流落白也竄，郊島摧埋終不起。", "是知造物惡鎸鑱，故遣饑寒被其體。", "嗟我少小不解事，失身偶落翰墨裏。", "年來百念已灰滅，只有宿心猶在此。", "後來不作諸老亡，冥行恐墮澗谷底。", "雖云黄卷可尚友，糟粕詎能臻妙理。", "率然有作每自厭，一紙真成再三毀。", "庶幾穮蔉望豐年，亦學乘流到涯涘。", "那知事迺有大繆，藝未及成窮已至。", "皆言詩工固可俟，窮爲先兆自應爾。", "坐茲不復置追悔，志在溫飽誠足鄙。", "玄泓管楮日相從，固異小人甘若醴。", "朅來中書忽告老，一朝左右手俱廢。", "嘲風咏月不耐閒，按圖姑聽求諸市。", "我詩縱不稱犀象，葦管雞毛那慣使。", "紛紛著墨與水浮，勢如絲亂安得治。", "戲題滿几輒大笑，翻憶兒詩汙窗紙。", "操舟無長病河紆，我詩固說當罪己。", "又聞工欲善迺事，未有不先資利器。", "作牋搜乞累朋友，往往猶吾歎崔子。", "錦囊藤篋世不乏，鼠齧蟲攻誰料理。", "那知我輩有百艱，此事且然他可比。"]'),
('1895acdf-eefa-4c4d-b512-06873eb2c01f','郡檄子肅檢視旱田以詩寄之','趙蕃','宋','宋诗','song-poetry','','[]','是邦且熟無多收，况於水旱相爲憂。',128,'全唐诗/poet.song.164000.json','["是邦且熟無多收，况於水旱相爲憂。", "使君奏課避非實，檄公按視臨田疇。", "民聞公來相告語，活國憂民公自許。", "平時愛我如恐傷，今胡不能爲輕賦。", "人生衣食固有端，作苦寧敢求自安。", "分當戮力給公上，何意年歲逢艱難。", "吾君德盛過文景，詔書屢下民惟省。", "公其爲我謝使君，考雖下下民安枕。"]'),
('0eb06654-95ea-4fcf-b293-a090ca0ef72f','題江貫道江行晚日圖','趙蕃','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','霞尾千山赤，雲腰幾樹連。',48,'全唐诗/poet.song.164000.json','["霞尾千山赤，雲腰幾樹連。", "若非彭蠡正，當是洞庭偏。", "歲月驚飛鳥，功名憶墮鳶。", "開圖若有感，歸思忽無邊。"]'),
('ed983056-ba22-499b-8f64-7be246d8d77f','晨起','趙蕃','宋','宋诗','song-poetry','','[]','人語村村好，雞聲處處聞。',48,'全唐诗/poet.song.164000.json','["人語村村好，雞聲處處聞。", "樹猶埋宿雨，山未釋停雲。", "俯仰夏已度，屈伸秋又分。", "平生燈火念，牢落嘆離羣。"]'),
('b40b4863-cb7c-461d-9e93-58bcafafabbd','幽居多暇風雨兼旬山色菁葱禽聲在樹顧而樂之因賦此','趙蕃','宋','宋诗','song-poetry','','[]','林雪乾留凍，巘雲行带昏。',48,'全唐诗/poet.song.164000.json','["林雪乾留凍，巘雲行带昏。", "幽人貪熟睡，簷鵲故多言。", "宿潤微侵屨，晨光漸滿軒。", "倦能行竹逕，閑且灌蘭盆。"]'),
('574c6a64-66c9-4776-8684-46ded2e55292','有以靈壽杖爲貺周旋累年忽爾摧折感而賦之','趙蕃','宋','宋诗','song-poetry','','[]','度嶺且萬里，友于凡幾年。',48,'全唐诗/poet.song.164000.json','["度嶺且萬里，友于凡幾年。", "忽驚同拉朽，何敢恃扶顛。", "躋勝亡行具，結趺聊坐禪。", "山南與山北，從此罷蹁躚。"]'),
('1960e547-9995-45ff-aa1a-b9de8191ec69','山行','趙蕃','宋','宋诗','song-poetry','','[]','晨起雨間雪，晚行風送晴。',48,'全唐诗/poet.song.164000.json','["晨起雨間雪，晚行風送晴。", "梅殘冰玉瘦，林遠畫圖呈。", "賈客嗟長路，農夫樂早耕。", "余懷獨無累，徙倚待詩成。"]'),
('b36d7f5b-7c63-461d-b9a7-00f1629f8018','清明','趙蕃','宋','宋诗','song-poetry','','[]','寒食又清時，連陰得蹔晴。',48,'全唐诗/poet.song.164000.json','["寒食又清時，連陰得蹔晴。", "欲知春事晚，已見綠陰成。", "蝶有俱飛逐，鳥仍求友聲。", "春衣期暖至，短褐尚寒生。"]'),
('f4bfa3bc-189c-4c5c-a4d0-0422b597b65c','徙居祖印寺','趙蕃','宋','宋诗','song-poetry','','[]','十載依脩竹，今秋始一辭。',48,'全唐诗/poet.song.164000.json','["十載依脩竹，今秋始一辭。", "琴書與俱載，風月故長隨。", "四海均爲寓，旁觀莫浪疑。", "全家肯同住，未媿鹿門期。"]'),
('9bad882e-1f6d-4f22-9115-0cbe95be21d0','郊居秋晚五首  其一','趙蕃','宋','宋诗','song-poetry','','[]','舊歲旱爲虐，今年雨以時。',48,'全唐诗/poet.song.164000.json','["舊歲旱爲虐，今年雨以時。", "如聞諸郡國，可脫半寒饑。", "我自無田者，空成樂歲詩。", "誰官太史氏，直筆要無遺。"]'),
('ac6cbf9f-c27e-409e-b8e0-a37046133044','郊居秋晚五首  其二','趙蕃','宋','宋诗','song-poetry','','[]','祇道秋蕭索，木犀能再開。',48,'全唐诗/poet.song.164000.json','["祇道秋蕭索，木犀能再開。", "驚看倚修竹，便恐滿蒼苔。", "花瘦非疇昔，香深有自來。", "微吟真浪爾，細折爲誰哉。"]'),
('e1b6f56e-215f-4824-8963-8ecd201455ea','郊居秋晚五首  其三','趙蕃','宋','宋诗','song-poetry','','[]','庭菊種匪晚，秋風開爾遲。',48,'全唐诗/poet.song.164000.json','["庭菊種匪晚，秋風開爾遲。", "人嗟地力薄，我有歲寒期。", "蘭芷元同類，蒿萊敢肆欺。", "懷哉非失所，社老謾銜悲。"]'),
('ecaf32e3-8117-4897-9e92-5eca73d4237a','郊居秋晚五首  其四','趙蕃','宋','宋诗','song-poetry','','[]','松柏有正性，風霜無橫侵。',48,'全唐诗/poet.song.164000.json','["松柏有正性，風霜無橫侵。", "南方異摇落，衆木共青森。", "曲士應懷悅，我曹嘗感心。", "詩成誰和者，絃絕未忘琴。"]'),
('d8a00a90-af40-45df-ba44-a708a4ed184c','郊居秋晚五首  其五','趙蕃','宋','宋诗','song-poetry','','[]','霜雨飛何密，窮秋易作悲。',48,'全唐诗/poet.song.164000.json','["霜雨飛何密，窮秋易作悲。", "長身竹孤瘦，短髮草黄萎。", "漸邇風霜迫，誰無裘褐思。", "向惟逃夏日，今已念朝曦。"]'),
('46c9e9a8-85b6-4fdc-ac77-2ef93cbe480f','催租人至作','趙蕃','宋','宋诗','song-poetry','','[]','竹屋煎茶罷，風床散帙餘。',48,'全唐诗/poet.song.164000.json','["竹屋煎茶罷，風床散帙餘。", "花殘蜂不至，食盡雀來疎。", "無客對揮麈，有筇扶遶除。", "茲時潘處士，詩敗爲催租。"]'),
('9f2787a0-00fa-4b11-8a25-770be088b8ca','端峰往還三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','振衣猶戶內，發興已雲端。',48,'全唐诗/poet.song.164000.json','["振衣猶戶內，發興已雲端。", "問路非生境，逢人若素歡。", "行知近林邃，望覺遠峰攢。", "顧可資瞻眺，胡能卹髀髖。"]'),
('64ff4457-aa04-4513-bd3c-e702bd91042f','端峰往還三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','甚厭窮居陋，聊爲佛界遨。',48,'全唐诗/poet.song.164000.json','["甚厭窮居陋，聊爲佛界遨。", "追隨有逢掖，應對屬方袍。", "褊性便幽隠，畏途思避逃。", "明當與山別，回首念塵勞。"]'),
('57c14d8c-4cf5-4e27-80cf-3e771bdb812b','端峰往還三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','蹔住已積日，此生知幾來。',48,'全唐诗/poet.song.164000.json','["蹔住已積日，此生知幾來。", "歛容看夭矯，側足避崔嵬。", "隨意從登降，無心計挽推。", "雲寒易成晚，家近故須回。"]'),
('ee948b47-0c99-49f4-a8c8-3dbe7f972ebb','小園早步','趙蕃','宋','宋诗','song-poetry','','[]','今朝欣雨止，天氣漸清和。',48,'全唐诗/poet.song.164000.json','["今朝欣雨止，天氣漸清和。", "籬落小桃破，階除馴雀多。", "占方移果樹，带土數蔬科。", "農務侵尋及，吾寧久卧疴。"]'),
('772c08db-8c83-447f-aa7d-72d64508dad7','閏月二十日離玉山八月到餘干易舟又二日抵鄱陽城追集途中所作得詩十有二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','摧輪荒水磨，漲潦失連湖。',48,'全唐诗/poet.song.164000.json','["摧輪荒水磨，漲潦失連湖。", "縱使非長路，能忘去此都。", "未應爲物役，真復坐饑驅。", "好在佳山水，懸應識故吾。"]'),
('93711a43-62a1-4505-8b2b-264cc559e18f','閏月二十日離玉山八月到餘干易舟又二日抵鄱陽城追集途中所作得詩十有二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','草草朝成市，匆匆客繫船。',48,'全唐诗/poet.song.164000.json','["草草朝成市，匆匆客繫船。", "荒雞亂人語，細雨雜炊煙。", "歲月真前夢，江山殆宿緣。", "沙鷗應笑我，疎鬢異當年。"]'),
('4ea2aa75-c42e-4daa-a924-99108fceaaf8','閏月二十日離玉山八月到餘干易舟又二日抵鄱陽城追集途中所作得詩十有二首  其三','趙蕃','宋','宋诗','song-poetry','','[]','岸盡催撐渡，風橫促解橋。',48,'全唐诗/poet.song.164000.json','["岸盡催撐渡，風橫促解橋。", "傳聞記常歲，偉觀得今朝。", "時有疎鐘度，誰云隔岸遥。", "明當絕溪去，應爲好山招。"]'),
('56fab6b8-fddb-42f8-80e5-4d48c680c7ae','閏月二十日離玉山八月到餘干易舟又二日抵鄱陽城追集途中所作得詩十有二首  其四','趙蕃','宋','宋诗','song-poetry','','[]','下水有放溜，泝流多哭灘。',48,'全唐诗/poet.song.164000.json','["下水有放溜，泝流多哭灘。", "人能等遲速，事豈病艱難。", "返照千山赤，春風兩鬢寒。", "生平慣行役，無復漫悲酸。"]'),
('cb77d602-18e2-451c-b0a3-eba5d5ad81d1','閏月二十日離玉山八月到餘干易舟又二日抵鄱陽城追集途中所作得詩十有二首  其五','趙蕃','宋','宋诗','song-poetry','','[]','汭口成孤泊，章巖說舊遊。',48,'全唐诗/poet.song.164000.json','["汭口成孤泊，章巖說舊遊。", "征商毋見挽，日暮自應休。", "煙暝棲鴉樹，沙昏宿鷺洲。", "浮生真泛泛，吾道莽悠悠。"]'),
('34036b9e-fdd8-4da3-a1bb-8beef5063830','閏月二十日離玉山八月到餘干易舟又二日抵鄱陽城追集途中所作得詩十有二首  其六','趙蕃','宋','宋诗','song-poetry','','[]','借石誰爲主，叫應呼莫譍。',48,'全唐诗/poet.song.164000.json','["借石誰爲主，叫應呼莫譍。", "樓高才隠約，樹遠更崚嶒。", "掛席凡三過，停橈欠一登。", "扁舟向何許，漂泊傍漁罾。"]'),
('fd7d956e-e3fa-48eb-86af-cf1a1e672ef5','閏月二十日離玉山八月到餘干易舟又二日抵鄱陽城追集途中所作得詩十有二首  其七','趙蕃','宋','宋诗','song-poetry','','[]','樓殿何年寺，檣帆別郡船。',48,'全唐诗/poet.song.164000.json','["樓殿何年寺，檣帆別郡船。", "溪山妙圖畫，井邑盛人煙。", "未覺鄉音改，空驚歲事遷。", "桃花知不遠，底處覓真僊。"]'),
('c46702d6-3272-49c6-8cce-58576b90fad7','閏月二十日離玉山八月到餘干易舟又二日抵鄱陽城追集途中所作得詩十有二首  其八','趙蕃','宋','宋诗','song-poetry','','[]','不見千株樹，空留百尺臺。',48,'全唐诗/poet.song.164000.json','["不見千株樹，空留百尺臺。", "仙人定無有，行客自裴回。", "更欲危欄倚，生嫌莫色催。", "病僧多不出，門外長蒼苔。"]'),
('8668654d-5428-4c1e-8970-9d950cdd0024','閏月二十日離玉山八月到餘干易舟又二日抵鄱陽城追集途中所作得詩十有二首  其九','趙蕃','宋','宋诗','song-poetry','','[]','望望龜峰寺，行行番國船。',48,'全唐诗/poet.song.164000.json','["望望龜峰寺，行行番國船。", "林深寒日薄，沙逈晚風顛。", "能賦思孫楚，同行有惠連。", "好詩相撥觸，才盡不能宣。"]'),
('a8a39507-0099-43f1-ace0-6ec70112bdba','閏月二十日離玉山八月到餘干易舟又二日抵鄱陽城追集途中所作得詩十有二首  其一○','趙蕃','宋','宋诗','song-poetry','','[]','喚渡風殊懷，穿林日向中。',48,'全唐诗/poet.song.164000.json','["喚渡風殊懷，穿林日向中。", "飛泉半崖落，峭壁與天通。", "往者名猶在，仙人事已空。", "徐巖不爲遠，歸去若匆匆。"]'),
('a01522a9-0f24-461c-a05e-03f6f7c97e74','閏月二十日離玉山八月到餘干易舟又二日抵鄱陽城追集途中所作得詩十有二首  其一一','趙蕃','宋','宋诗','song-poetry','','[]','試登雲錦閣，還上揖仙亭。',48,'全唐诗/poet.song.164000.json','["試登雲錦閣，還上揖仙亭。", "棟宇雖摧落，江山自典型。", "衝風聊策杖，晚日更揚舲。", "要寫吳江句，初無六尺屏。"]'),
('1dc29de8-0e87-4a7e-a2da-ba08b0b8b9ae','閏月二十日離玉山八月到餘干易舟又二日抵鄱陽城追集途中所作得詩十有二首  其一二','趙蕃','宋','宋诗','song-poetry','','[]','草草天涯棹，悠悠江上鷗。',48,'全唐诗/poet.song.164000.json','["草草天涯棹，悠悠江上鷗。", "琵琶千古恨，蓑笠十年游。", "莫向官亭泊，閑爲佛界流。", "明朝更西去，依舊覓扁舟。"]'),
('0306cbc2-c898-4f61-86c0-4bb00bc3e8d3','定誇浦','趙蕃','宋','宋诗','song-poetry','','[]','棹掠湖邊浦，帆收柳外橋。',48,'全唐诗/poet.song.164000.json','["棹掠湖邊浦，帆收柳外橋。", "蒲深映鳬沒，浪靜覺魚跳。", "紗帢因眠側，霜豪倚醉摇。", "春風空浩蕩，客思只蕭條。"]'),
('e7feec22-de66-435f-93a3-463412b68f38','富陽道中遇風感歎作','趙蕃','宋','宋诗','song-poetry','','[]','回首江山舊，他年來往頻。',48,'全唐诗/poet.song.164000.json','["回首江山舊，他年來往頻。", "人誰無一飽，汝獨值多辛。", "泛泛將何往，悠悠媿此身。", "懷哉松與菊，白露及時新。"]'),
('e7deff50-bc8c-4257-a045-f9e996c55fac','將宿天心寺以失路遂止野人家','趙蕃','宋','宋诗','song-poetry','','[]','一出有百阻，吾生何太艱。',48,'全唐诗/poet.song.164000.json','["一出有百阻，吾生何太艱。", "問途迷野寺，積淖落前山。", "勢以鷄晨待，聊安虎落間。", "濁醪無路覓，破衲與渠關。"]'),
('dd1e2842-e669-4aaf-b825-9e1ba6a235bc','喜公擇之歸兼懷子崧三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','曾因避仇去，竟作倦遊歸。',48,'全唐诗/poet.song.164000.json','["曾因避仇去，竟作倦遊歸。", "梅蕊經青眼，緇塵染素衣。", "湖山新有得，歲月舊成非。", "小定能來否，柴關夜啟扉。"]'),
('1e337653-1bd9-4916-8707-b93de8375c7c','喜公擇之歸兼懷子崧三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','子去吾誰與，諸孫共此悲。',48,'全唐诗/poet.song.164000.json','["子去吾誰與，諸孫共此悲。", "幾經行役苦，還讀寄來詩。", "事要規摹立，寧憂寒餓爲。", "安知造物意，於爾不吾私。"]'),
('91e250b3-a52d-4ba5-a708-8eafa86ec297','喜公擇之歸兼懷子崧三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','建德老斯立，近來雙鯉魚。',48,'全唐诗/poet.song.164000.json','["建德老斯立，近來雙鯉魚。", "殷勤數稱子，交友未慚予。", "多病誰如我，微官政凂渠。", "吾君方銳治，何乃緩徵車。"]'),
('8f6cb6e5-0540-4488-aa87-154e6ff7e3fd','悼亡','趙蕃','宋','宋诗','song-poetry','','[]','死別生難見，生離死會逢。',48,'全唐诗/poet.song.164000.json','["死別生難見，生離死會逢。", "休憑海山信，浪覓少翁容。", "春院無新跡，羅衣有舊縫。", "昨朝桃李艷，今日綠陰重。"]'),
('1a6745d0-b1ff-4537-9a5e-9585ff4595ef','悼劉仲遠  其一','趙蕃','宋','宋诗','song-poetry','','[]','平生遠齋老，爲說惠連賢。',48,'全唐诗/poet.song.164000.json','["平生遠齋老，爲說惠連賢。", "制行有成德，工詩稱舊聯。", "幾年徒慕想，十載獲周旋。", "別去吳中遠，書無雁足傳。"]'),
('5fbf5557-091f-44b9-80b8-e9ae996f5d6b','悼劉仲遠  其二','趙蕃','宋','宋诗','song-poetry','','[]','朝共阿戎飯，暮同烏戍舟。',48,'全唐诗/poet.song.164000.json','["朝共阿戎飯，暮同烏戍舟。", "新詩蒙惠好，顧我闕賡酬。", "化鶴驚何往，觀魚事已休。", "音容無日見，巾屨想神游。"]'),
('5c7747a5-da5f-446b-a16e-b9a1101aef75','悼劉仲遠  其三','趙蕃','宋','宋诗','song-poetry','','[]','不念廼兄老，忍遺諸子才。',48,'全唐诗/poet.song.164000.json','["不念廼兄老，忍遺諸子才。", "結交予最晚，聞訃亦深哀。", "銘志誰爲作，松杉何地栽。", "堂堂那復有，皎日竟浮埃。"]'),
('57b27dfc-49db-4c21-b3fe-1856b73d9b6a','竹隠新籬','趙蕃','宋','宋诗','song-poetry','','[]','地迥闕虎落，秋來逢鼠偷。',120,'全唐诗/poet.song.164000.json','["地迥闕虎落，秋來逢鼠偷。", "貧居乏給使，力作費營謀。", "鄰近俱相集，讙言卒未休。", "濁醪澆渴肺，香飯飽饑喉。", "密篠分新翠，深林失故稠。", "斬除才就束，委積動成丘。", "經布潛依塹，蛇行曲過溝。", "周遭類屏障，森列勝戈矛。", "黄耳斯逃責，青氈好在不。", "幽棲知有託，高枕得無憂。"]'),
('62ca6ca1-f93c-436b-aba8-b039538148eb','呈趙叔侍郎子直二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','憶昨才聞召節趨，江湖日月誦除書。',64,'全唐诗/poet.song.164000.json','["憶昨才聞召節趨，江湖日月誦除書。", "政途去此不容咫，物望在廷誰得如。", "豈但疲民望蘇醒，更知寒士待吹噓。", "所期異日施行次，不負于今拜獻初。"]'),
('1ec3540b-a087-422d-9a67-b3f9b52ce738','呈趙叔侍郎子直二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','潦倒三年白下官，畏途常以此心觀。',64,'全唐诗/poet.song.164000.json','["潦倒三年白下官，畏途常以此心觀。", "求爲廟令直不易，翻入帝城良獨難。", "落落白頭游且倦，悠悠青眼刺空漫。", "文章功用知無補，保此不渝惟歲寒。"]'),
('4a875efc-2f61-440c-925a-5906c6051676','侍郎周公不赴富沙士論推高以詩寄呈','趙蕃','宋','宋诗','song-poetry','','[]','人誰不慕直言名，未有保持終不傾。',64,'全唐诗/poet.song.164000.json','["人誰不慕直言名，未有保持終不傾。", "可使濁涇侵渭水，信於落月見長庚。", "要令國有九鼎重，自是身如一葉輕。", "常病此風今寂寞，古涂荆棘頼公行。"]'),
('2ae45e07-86e1-4407-a9e3-a164de0a6ee8','新淦道中呈運使錢侍郎','趙蕃','宋','宋诗','song-poetry','','[]','幾日陰霾鬭不開，今晨萬頃靜無埃。',64,'全唐诗/poet.song.164000.json','["幾日陰霾鬭不開，今晨萬頃靜無埃。", "山楓借潤旌旗色，江鳥忘機鼓吹猜。", "詔獄務平勤駐節，閫符兼總待還臺。", "扁舟又邇東隨檄，借此餘波亦快哉。"]'),
('3b6d1d91-0eae-41d3-9f05-3777407c01f0','同謝丈簽判送趙台州至靈鷲簽判丈道中有詩蕃同賦','趙蕃','宋','宋诗','song-poetry','','[]','朝來細雨又微風，遲我山行盡日中。',64,'全唐诗/poet.song.164000.json','["朝來細雨又微風，遲我山行盡日中。", "莫嘆籃輿礙泥淖，也勝策馬犯塵紅。", "欲知風俗家家厚，看取耕桑處處同。", "更訪百年垂白叟，要聽舊事說元豐。"]'),
('1b44df8b-670e-40ba-a66d-e0e9b2c57f39','訪梅殊未有開意','趙蕃','宋','宋诗','song-poetry','','[]','不憚朝寒起杖藜，問梅隨往到山蹊。',64,'全唐诗/poet.song.164000.json','["不憚朝寒起杖藜，問梅隨往到山蹊。", "枯根半死苔痕剝，細蕾深藏藤刺迷。", "倚市懸知無正態，入空還恐見深擠。", "幽居空谷端可愧，顧歎詩無老手題。"]'),
('da46179a-5ffa-4611-a6f4-2ee2a8ec8754','次韻子肅秋日感興兼懷公擇二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','炎冷財分覆手間，化機於爾見深慳。',64,'全唐诗/poet.song.164000.json','["炎冷財分覆手間，化機於爾見深慳。", "歸歟君釣荆溪水，已矣我耕懷玉山。", "幾羨脩翎辭世網，絕憐駿足老天閑。", "區區莫有窮途歎，了了要從初地還。"]'),
('cd3c0550-4635-46d8-a158-d9f4161ad568','次韻子肅秋日感興兼懷公擇二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','秋盡誰無狐貉思，一年行矣又垂垂。',64,'全唐诗/poet.song.164000.json','["秋盡誰無狐貉思，一年行矣又垂垂。", "顧慚志行如山立，敢爲推遷作浪悲。", "貧賤已知安少壯，功名何有望衰遲。", "長安此際尤蕭索，坐念故人應窘炊。"]'),
('049bf27b-3947-4c4e-8585-5abaaede08e2','十三日逆風舟行甚遲','趙蕃','宋','宋诗','song-poetry','','[]','昨夜縱風幾喪生，今朝泝水頗留行。',64,'全唐诗/poet.song.164000.json','["昨夜縱風幾喪生，今朝泝水頗留行。", "細看洶湧收帆脚，孰若夷猶聽槳聲。", "客路了知難數傲，長年謂我勿多驚。", "世間遲速元同致，莫問到衢今幾程。"]'),
('83a4c343-b134-4f32-8786-4a2a4e75467b','寒食前一日發黄堰明日抵定誇連日逆風吹沙不可渡湖','趙蕃','宋','宋诗','song-poetry','','[]','故人留我過寒食，意重寧同所歷家。',64,'全唐诗/poet.song.164000.json','["故人留我過寒食，意重寧同所歷家。", "苦信長年貪道里，翻成五日滯風沙。", "擬從塔上占鈴語，又見雲間起砲車。", "立遍津頭無數柳，亂絲頻擺失棲鴉。"]'),
('4b19f74e-8114-4b7e-9469-16cb94218a52','兩日隨錢丈放舟恬無風浪今日別歸仍值逆風作長句寄錢丈','趙蕃','宋','宋诗','song-poetry','','[]','大舸帆高掠浦飛，小舟笪短泝灘歸。',64,'全唐诗/poet.song.164000.json','["大舸帆高掠浦飛，小舟笪短泝灘歸。", "雖云來去難俱遂，自是神人相不違。", "頼得好山看要熟，不妨晚雨落仍微。", "遲回半日夫何歎，於此因知造物機。"]'),
('265bf05c-a7ea-4f23-9606-752d6706cea6','雨中遣興呈遠齋父子孫丈昆仲','趙蕃','宋','宋诗','song-poetry','','[]','睡思昏然晝掩門，覺來山雨已翻盆。',64,'全唐诗/poet.song.164000.json','["睡思昏然晝掩門，覺來山雨已翻盆。", "黄梅應熟騷人念，綠野可耕田父言。", "林外竹鷄時自語，階前花鴨故相喧。", "詩材滿眼費驅使，此事合輸劉與孫。"]'),
('4d45371d-5d8d-49ca-b485-c97d55806f5d','趣成父釀酒用子進家法故及其昆仲','趙蕃','宋','宋诗','song-poetry','','[]','入眼江梅皆好枝，是中勞我幾懷思。',64,'全唐诗/poet.song.164000.json','["入眼江梅皆好枝，是中勞我幾懷思。", "詩聲何止一頭出，酒事乃稱百室師。", "聞道名方曾口授，定應買秫趁冬炊。", "小須旬月釀當熟，寄我茅齋不可遲。"]'),
('752ab05f-02dd-4a2f-9cfe-f1d03966c986','感懷','趙蕃','宋','宋诗','song-poetry','','[]','憶在兒童聞混融，江湖老矣再能逢。',64,'全唐诗/poet.song.164000.json','["憶在兒童聞混融，江湖老矣再能逢。", "潮音遁伏門間虎，神骨崢嶸霜後松。", "粥飯蹔應隨願力，井舂終可聽吾從。", "蕭灘灘上風帆發，引領白雲何處峰。"]'),
('8ba46dc9-91ca-46f0-813d-7a1f491b7703','清明懷成父','趙蕃','宋','宋诗','song-poetry','','[]','只道今年寒食晴，那知風雨在清明。',64,'全唐诗/poet.song.164000.json','["只道今年寒食晴，那知風雨在清明。", "異鄉逢節自感動，何况此身今老生。", "爲底輕辭墳墓去，不敢回首弟兄情。", "悠然强作江東望，雲湧如山白浪橫。"]'),
('32e0ae5e-fbe5-47b8-9556-0207bade308b','喜晴','趙蕃','宋','宋诗','song-poetry','','[]','地雖湖北稻爲鄉，歲比曾微一報穰。',64,'全唐诗/poet.song.164000.json','["地雖湖北稻爲鄉，歲比曾微一報穰。", "望望雨晴求屢告，欣欣守尉德俱良。", "共期負籠爭晴割，敢愛當檠滴夜凉。", "更擬年豐酒初賤，鈎藤免飲澀如棠。"]'),
