('2382e800-8b70-4bc9-980c-e3bca3ed973e','碧雲  其二','趙蕃','宋','宋诗','song-poetry','','[]','翳翳村巷，遥遥犬聲。',30,'全唐诗/poet.song.164000.json','["翳翳村巷，遥遥犬聲。", "肅肅庭樹，啾啾鳥鳴。", "所期不來，實關我情。"]'),
('8a2e8c9d-82da-4e18-96fe-64d19daea03a','碧雲  其三','趙蕃','宋','宋诗','song-poetry','','[]','寒鐙既張，幽室有光。',30,'全唐诗/poet.song.164000.json','["寒鐙既張，幽室有光。", "豈無他人，惟子之良。", "閉彼柴荆，今夕斯長。"]'),
('9b7f3832-1cf3-45e1-ba47-bfecd74aa06b','三月十三日夜五更聞杜鵑時成父欲入浙因賦六章章四句以送之  其一','趙蕃','宋','宋诗','song-poetry','','[]','不如歸去，蒼山茂樹。',20,'全唐诗/poet.song.164000.json','["不如歸去，蒼山茂樹。", "獨胡爲乎，空此號謼。"]'),
('53842117-be34-4f4e-a6ba-533206bd087b','三月十三日夜五更聞杜鵑時成父欲入浙因賦六章章四句以送之  其二','趙蕃','宋','宋诗','song-poetry','','[]','歸去來兮，斯言可師。',20,'全唐诗/poet.song.164000.json','["歸去來兮，斯言可師。", "我今已歸，胡能不知。"]'),
('5802f850-6ae7-4159-9e69-e0cfc4fb61c8','三月十三日夜五更聞杜鵑時成父欲入浙因賦六章章四句以送之  其三','趙蕃','宋','宋诗','song-poetry','','[]','不如歸去，春且云莫。',20,'全唐诗/poet.song.164000.json','["不如歸去，春且云莫。", "山中之樂，豈同岐路。"]'),
('523ba74d-1f88-4f88-8dc5-cd9984ab551e','三月十三日夜五更聞杜鵑時成父欲入浙因賦六章章四句以送之  其四','趙蕃','宋','宋诗','song-poetry','','[]','歸去來兮，言發動隨。',20,'全唐诗/poet.song.164000.json','["歸去來兮，言發動隨。", "古之逸民，舍陶而誰。"]'),
('75845834-666b-4c13-aebb-4e754312a962','三月十三日夜五更聞杜鵑時成父欲入浙因賦六章章四句以送之  其五','趙蕃','宋','宋诗','song-poetry','','[]','不如歸去，載丁載寧。',20,'全唐诗/poet.song.164000.json','["不如歸去，載丁載寧。", "勸子勿去，子寧我聽。"]'),
('53aba926-5c4b-4dc6-8b5d-4480e6a69ee5','三月十三日夜五更聞杜鵑時成父欲入浙因賦六章章四句以送之  其六','趙蕃','宋','宋诗','song-poetry','','[]','不如歸去，子寧肯住。',20,'全唐诗/poet.song.164000.json','["不如歸去，子寧肯住。", "歸去來兮，早歌式微。"]'),
('94882ff7-68f8-4748-99ab-c81b02a299d5','山行見月作  其一','趙蕃','宋','宋诗','song-poetry','','[]','有風肅然，落於樹巔。',20,'全唐诗/poet.song.164000.json','["有風肅然，落於樹巔。", "使我沈痾，不藥而痊。"]'),
('b3285714-6cbe-4312-93dc-12d810b35175','山行見月作  其二','趙蕃','宋','宋诗','song-poetry','','[]','意行何之，陟此雲嶺。',20,'全唐诗/poet.song.164000.json','["意行何之，陟此雲嶺。", "如夢而覺，如昏而醒。"]'),
('9fd9a8db-6b84-4609-91b2-39ba9b7438bc','山行見月作  其三','趙蕃','宋','宋诗','song-poetry','','[]','東坡老翁，有言莫酬。',20,'全唐诗/poet.song.164000.json','["東坡老翁，有言莫酬。", "凉天佳月，即爲中秋。"]'),
('00490ce0-f9d6-4fe6-aba6-21869c5ff616','山行見月作  其四','趙蕃','宋','宋诗','song-poetry','','[]','恨我無酒，負爾一醉。',20,'全唐诗/poet.song.164000.json','["恨我無酒，負爾一醉。", "酌茲寒泉，兀爾忘睡。"]'),
('e5deb698-6edb-45de-886c-cd240f38783b','古意二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','齊王昔好竽，有客工鼓瑟。',48,'全唐诗/poet.song.164000.json','["齊王昔好竽，有客工鼓瑟。", "持之立王門，三年不得入。", "不知所好異，卒致遭怒叱。", "我今幸早計，歸去無自逸。"]'),
('dd730439-12bd-4b69-afc9-af68456ec590','古意二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','曾聞蜀道難，難於上青天。',48,'全唐诗/poet.song.164000.json','["曾聞蜀道難，難於上青天。", "蜀道難何以，嵯峩劍門關。", "未抵鄱陽湖，無風浪掀船。", "脫身其早歸，無汙蛟鰐涎。"]'),
('91bf9372-e0c2-4fea-a046-e4cf7152d7f5','擬古','趙蕃','宋','宋诗','song-poetry','','[]','松柏抱奇姿，自應能歲寒。',48,'全唐诗/poet.song.164000.json','["松柏抱奇姿，自應能歲寒。", "籬菊蓋小草，後雕良獨難。", "誰云一時芳，顧將比春蘭。", "蘭開桃李際，菊傲風霜闌。"]'),
('e1ccb99a-149a-4a49-9c8c-4d862177e3d2','呈尤運使袤延之五首  其一','趙蕃','宋','宋诗','song-poetry','','[]','往者江次對，不妄出薦口。',48,'全唐诗/poet.song.164000.json','["往者江次對，不妄出薦口。", "門無雜遝賓，麟角鼈肋九。", "斯文獨許公，是謂言可否。", "幾年闕通謁，今乃獲拜手。"]'),
('9a5e4826-3738-4a25-ad1e-e703c3e42c79','呈尤運使袤延之五首  其二','趙蕃','宋','宋诗','song-poetry','','[]','今時使者中，所進非一律。',48,'全唐诗/poet.song.164000.json','["今時使者中，所進非一律。", "學術用其長，公獨名副實。", "江左更江右，非爲循更迭。", "政以歲方艱，當遣德星出。"]'),
('462d0e7a-8bf8-4803-b994-7faded2e3e59','呈尤運使袤延之五首  其三','趙蕃','宋','宋诗','song-poetry','','[]','少年見公文，大類韓退之。',48,'全唐诗/poet.song.164000.json','["少年見公文，大類韓退之。", "集古一千卷，復楷歐少師。", "楷歐亦類韓，萬頃定渺瀰。", "於今到收斂，寧易窺涘涯。"]'),
('4a517e3c-ecd4-4d95-a5a3-b9cad7d1da57','呈尤運使袤延之五首  其四','趙蕃','宋','宋诗','song-poetry','','[]','翰墨有先達，知己僅三數。',48,'全唐诗/poet.song.164000.json','["翰墨有先達，知己僅三數。", "省齋憐其貧，晦庵過其譽。", "懷哉介庵老，先我騎鯨去。", "公如幸教之，豈歎歲不與。"]'),
('08fa1996-1036-40dc-8d24-73a7ad3a1182','呈尤運使袤延之五首  其五','趙蕃','宋','宋诗','song-poetry','','[]','青衿詩學爲，白髮步乃却。',48,'全唐诗/poet.song.164000.json','["青衿詩學爲，白髮步乃却。", "茫茫悟中入，了了難邊覺。", "抱痾每向人，誰有如神藥。", "公乎有異聞，蘄爲啟玄鑰。"]'),
('712b7de1-1c55-45cd-a722-d7bffe240c7a','常州先生以太守入對五首  其一','趙蕃','宋','宋诗','song-poetry','','[]','皇皇幾甸符，郁郁容臺禮。',48,'全唐诗/poet.song.164000.json','["皇皇幾甸符，郁郁容臺禮。", "固殊彼奏召，有待今沃啟。", "上能格君心，次可裨國體。", "俗吏急簿書，細務紛鹽米。"]'),
('6cef188f-8d66-47ab-bb4d-728391ba3037','常州先生以太守入對五首  其二','趙蕃','宋','宋诗','song-poetry','','[]','爭觀蘇翰林，未識李北海。',48,'全唐诗/poet.song.164000.json','["爭觀蘇翰林，未識李北海。", "獨能親話言，異彼想風采。", "徬徨計拍馬，留滯搴蘭茝。", "匹馬候南還，輕舟即東匯。"]'),
('1b0e01f7-4c5d-428d-ba3b-ffb776e6d515','常州先生以太守入對五首  其三','趙蕃','宋','宋诗','song-poetry','','[]','一州固匪輕，四海豈不重。',48,'全唐诗/poet.song.164000.json','["一州固匪輕，四海豈不重。", "與其事扶疎，孰若深培壅。", "驥不取德稱，馬多求駕泛。", "偉哉底柱功，障彼百川洶。"]'),
('0b31b7c7-f59d-4af5-9e6c-ceb1f5fdd31c','常州先生以太守入對五首  其四','趙蕃','宋','宋诗','song-poetry','','[]','青氈非舊物，喬木豈故國。',48,'全唐诗/poet.song.164000.json','["青氈非舊物，喬木豈故國。", "家傳墨莊書，人嗣文靖德。", "欲知治興衰，是繫道滋熄。", "愚獨愧衣冠，身宜親稼穡。"]'),
('629715ae-3e79-486d-a00e-1205f05dca22','常州先生以太守入對五首  其五','趙蕃','宋','宋诗','song-poetry','','[]','姑蘇訪虎丘，西庵作清遊。',48,'全唐诗/poet.song.164000.json','["姑蘇訪虎丘，西庵作清遊。", "能談著書人，老僧非黑頭。", "義興望荆溪，景坡亦前脩。", "不能乘桴者，滄波沒白鷗。"]'),
('9e5b7e89-6c76-4962-9873-829448c101ee','送趙叔自吏部知福州四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','當年治安策，通達如賈誼。',48,'全唐诗/poet.song.164000.json','["當年治安策，通達如賈誼。", "汲黯不留內，似非朝廷美。", "得非蕭望之，政事要詳試。", "兩州已有聲，刺史還連帥。"]'),
('897dc9a8-bf3a-4950-95ec-fc287dfe9e49','送趙叔自吏部知福州四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','人從閩中來，盡道閩中樂。',48,'全唐诗/poet.song.164000.json','["人從閩中來，盡道閩中樂。", "舊穀既年豐，今雨還時若。", "公行亦何事，重赴三山約。", "我乃願從之，微官還見縛。"]'),
('84d02c76-3d0a-4fce-be42-a1259aaabbf2','送趙叔自吏部知福州四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','公雖去朝廷，祕殿通班在。',48,'全唐诗/poet.song.164000.json','["公雖去朝廷，祕殿通班在。", "不應獻納忠，於爾分內外。", "而况我此州，甘棠存蔽芾。", "旱疫苦相仍，要當蒙大賚。"]'),
('7e6d6e59-7750-415d-a040-7eca2cd6853b','送趙叔自吏部知福州四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','憶昨過辭公，云有湖外役。',48,'全唐诗/poet.song.164000.json','["憶昨過辭公，云有湖外役。", "遲遲未能去，乃此困艱食。", "湖外米雖賤，旱歲賈者多。", "賈多米必貴，吾饑其奈何。"]'),
('b1cef321-3e8b-474b-8c96-558e48fe4025','呈陸嚴州五首  其一','趙蕃','宋','宋诗','song-poetry','','[]','江山不因人，何以相發揮。',48,'全唐诗/poet.song.164000.json','["江山不因人，何以相發揮。", "人而非江山，興亦無所歸。", "是故新定郡，得公倍光輝。", "豈惟江山然，鷗鳥亦依依。"]'),
('117af861-cd7c-40e0-b315-998ef0890524','呈陸嚴州五首  其二','趙蕃','宋','宋诗','song-poetry','','[]','簿領古白下，檄書走臨川。',48,'全唐诗/poet.song.164000.json','["簿領古白下，檄書走臨川。", "陳詩道所懷，奈此巍巍然。", "臨分得聞見，語以故有連。", "此意亦厚矣，乖離今十年。"]'),
('7a82a0f0-5eb8-480e-8e44-101fae3621f0','呈陸嚴州五首  其三','趙蕃','宋','宋诗','song-poetry','','[]','會稽巖壑林，新定山水藪。',48,'全唐诗/poet.song.164000.json','["會稽巖壑林，新定山水藪。", "一焉喚來居，一焉煩出守。", "人言公未遇，我獨以爲不。", "得失彼此間，於茲分薄厚。"]'),
('4ba31e21-fb59-4a0d-a1b2-3e31145d1d98','呈陸嚴州五首  其四','趙蕃','宋','宋诗','song-poetry','','[]','一代文翰主，百年風月懷。',48,'全唐诗/poet.song.164000.json','["一代文翰主，百年風月懷。", "於今則所獨，視古良與偕。", "試評雲霧窗，孰與山水齋。", "况我方與嚴，身沈名不埋。"]'),
('d3d5be89-504f-4cf0-b4c0-ef9d77e1b031','呈陸嚴州五首  其五','趙蕃','宋','宋诗','song-poetry','','[]','往游金陵都，始攀石湖仙。',48,'全唐诗/poet.song.164000.json','["往游金陵都，始攀石湖仙。", "爲我談公詩，大雅後有焉。", "謂我欠公詩，勉哉成其天。", "此語久不理，今朝墮公前。"]'),
('32f44ca5-8911-4fb4-8e9a-f302871ed39c','聞克齋舅氏除江東提舉以此寄賀','趙蕃','宋','宋诗','song-poetry','','[]','春風桃李花，開落幾許時。',120,'全唐诗/poet.song.164000.json','["春風桃李花，開落幾許時。", "諒彼松柏質，動有千歲期。", "舅氏早負名，不作窈窕姿。", "冰霜飽摧剝，未覺明堂遲。", "小休朱兩轓，四牡已載馳。", "歛散有常度，刺舉由我施。", "過家得上冢，偃薄寧久爲。", "又意漢廷上，鼓舞須厥辭。", "文章豈憎命，窮人詎因時。", "賤子盍自勉，毋庸罪毛錐。"]'),
('c127368f-5f81-4eec-bd7c-07a913ec4f5d','寄賀周子充除左相留正除右相王謙仲除參政','趙蕃','宋','宋诗','song-poetry','','[]','淳熙十六年，正月十九日。',240,'全唐诗/poet.song.164000.json','["淳熙十六年，正月十九日。", "雪餘雨更作，有客方抱疾。", "忽傳底處書，昏暮叩蓬蓽。", "問之何許人，乃是吾家姪。", "書中道何爲，除目報甲乙。", "要令二父知，此意深所悉。", "我方盤谷歸，詎應聞黜陟。", "雖云在田野，又可忘輔弼。", "况於鄉里賢，與夫舊連率。", "及其先友家，投分亦頗密。", "恭惟三君子，德盛難具述。", "要皆由從官，以至秉政筆。", "於今天下事，孰得復孰失。", "仰思與夜繼，想不遑暇逸。", "置郵速傳命，頌口當四出。", "而我病不能，欲置還未畢。", "要歌夔臯詩，稱美寧敢溢。", "願觀勳業成，公論斯可必。", "曾聞鳥鳴春，氣應還唧唧。", "喜甚屐且折，憂深緯寧恤。"]'),
('551a6bd4-c36e-4e7f-9eec-7e07a5725618','子暢尉曹秩滿侍親攝戶掾於上饒賦詩二首以送之  其一','趙蕃','宋','宋诗','song-poetry','','[]','遊君父子間，情誼等骨肉。',48,'全唐诗/poet.song.164000.json','["遊君父子間，情誼等骨肉。", "那知三年度，但謂一日足。", "今晨復何事，溪頭有行舳。", "臨別慘莫言，裴回謾瞻矚。"]'),
('d1280464-34a9-4085-957d-07aa11b95bfa','子暢尉曹秩滿侍親攝戶掾於上饒賦詩二首以送之  其二','趙蕃','宋','宋诗','song-poetry','','[]','平生幾游居，有親亦有故。',48,'全唐诗/poet.song.164000.json','["平生幾游居，有親亦有故。", "一飯或相忘，素書不能屢。", "心知世情薄，但益古人慕。", "如君父子賢，百蓋一二數。"]'),
('52b5fd7f-3f14-4a55-ba33-f3fa80b924b9','寄曾運使','趙蕃','宋','宋诗','song-poetry','','[]','知名必曹劉，乃可暗中索。',120,'全唐诗/poet.song.164000.json','["知名必曹劉，乃可暗中索。", "無聞若我遭，過眼誰復憶。", "如何十年後，姓名猶見識。", "當時所陳詩，亦復能道說。", "豈我能致然，先生自爲德。", "維時歲云莫，歸路千山隔。", "見公不三四，身已限南北。", "迨茲去無由，乃悔來卒迫。", "况今落蠻夷，公且天咫尺。", "猶擬信州船，看竹茶山宅。"]'),
('e7d42472-0999-40cf-9d79-bdbc953951eb','謝王使君','趙蕃','宋','宋诗','song-poetry','','[]','卧痾衡茅下，誰顧疾作門。',240,'全唐诗/poet.song.164000.json','["卧痾衡茅下，誰顧疾作門。", "忽傳故人書，犬吠雞爭喧。", "書陳使君賢，有好罔不惇。", "念子藥物須，萬錢致深恩。", "我未謁使君，此饋曷見存。", "是風久寂寥，當於古人論。", "亟起欲下拜，展轉足但捫。", "事殊送酒家，孤負老瓦盆。", "食粥已數月，政類顔平原。", "呼僮糴新粳，洗甑汲井渾。", "鄰蔬價不二，取足充盤飧。", "豈止飽妻孥，自可留弟昆。", "聊寬口腹累，姑置襦袴溫。", "惟我困流落，寄跡無田園。", "東南數十州，遍走如乞墦。", "今者屬有役，病縛不得犇。", "幾思出入勞，復慮霜雪繁。", "使君儻加惠，茲又何足言。", "屢將入城府，跼蹐駒在轅。", "因風道感謝，情至筆載援。"]'),
('6cf7a29a-5dfa-426e-b048-5215ea9e3efa','送劉得華赴漢陽教授二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','昔公去太學，士曰奪我師。',48,'全唐诗/poet.song.164000.json','["昔公去太學，士曰奪我師。", "今公去皇閣，里閭極公思。", "公何德於人，曰公勇於義。", "使其用於時，其效何止是。"]'),
('6de20073-01e4-4b71-9abe-31b38d642095','送劉得華赴漢陽教授二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','漢陽在何許，越在河之北。',48,'全唐诗/poet.song.164000.json','["漢陽在何許，越在河之北。", "聖朝富文物，要使均萬國。", "輟我學省彥，以爲遠方重。", "化成亟歸來，明堂待梁棟。"]'),
('52e47098-0347-4c09-9ad9-a6f9771af589','席上奉呈教授歐陽丈時併餞戴兄故其中及之','趙蕃','宋','宋诗','song-poetry','','[]','良由姿不敏，所以須朋友。',144,'全唐诗/poet.song.164000.json','["良由姿不敏，所以須朋友。", "朋友多得人，不忍相瑕垢。", "萬安初經過，渝水重邂逅。", "君今分教來，我政官曹守。", "何期逃虛中，乃值平生舊。", "蠻山雖云荒，蠻水亦頗秀。", "功名漢將餘，草木騷人後。", "春園縱芳歇，夏屋屬陰茂。", "官池荷卷舒，野寺泉波驟。", "追隨方自茲，留落復何有。", "合者故慰心，離者頻回首。", "聊歌五字詩，以侑一杯酒。"]'),
('79700081-3906-48c4-bfec-c7102e52095a','送施教授','趙蕃','宋','宋诗','song-poetry','','[]','盛心蓋俗忘，姦聲其道傷。',96,'全唐诗/poet.song.164000.json','["盛心蓋俗忘，姦聲其道傷。", "摻別伊何吟，停杯慨以慷。", "君官上饒郡，分教明虞唐。", "俄而及瓜代，朝天架康莊。", "巖廊冠劍地，學省翰墨場。", "失人易揣摩，失己勞酌量。", "情融香梅葩，玉水春茫茫。", "鴻毛遇順風，市朝在錢塘。"]'),
('2545591f-2f9a-4fb4-8f17-fe1ad15a4ad7','送彭孚先赴辰州教授','趙蕃','宋','宋诗','song-poetry','','[]','因行碧湘門，倏念黄草尾。',108,'全唐诗/poet.song.164000.json','["因行碧湘門，倏念黄草尾。", "曩辭戴安道，同者歐陽子。", "那知三年過，僅謂一日爾。", "惟辰雖陋邦，分教多名士。", "前瞻固高明，後至復奇偉。", "天將惠其俗，賢者不自鄙。", "流傳幾人說，邂逅一見喜。", "談論未云終，別袂已復起。", "勿謂隔沅湘，因來致蘭芷。"]'),
('fedfad1a-f6ab-4328-8786-2aa4f940c467','送梁仁伯赴江陵丞三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','往者左司公，會作荆州牧。',48,'全唐诗/poet.song.164000.json','["往者左司公，會作荆州牧。", "君時雖從行，所志惟聖讀。", "今焉去爲吏，與昔當異躅。", "試以身所經，參之耳曾熟。"]'),
('88876996-5522-44dc-8352-f909bbeb67fc','送梁仁伯赴江陵丞三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','直道多不容，枉道夫豈可。',48,'全唐诗/poet.song.164000.json','["直道多不容，枉道夫豈可。", "直道誠忤人，枉道還喪我。", "如君直有餘，爲計亦多左。", "而我枉未能，若爲逃轗軻。"]'),
('ea15a96f-f688-42d9-9b64-d996d8baf76c','送梁仁伯赴江陵丞三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','君搴澧之蘭，我擷沅之茝。',48,'全唐诗/poet.song.164000.json','["君搴澧之蘭，我擷沅之茝。", "邂逅桃花源，一笑若相待。", "那知青草湖，追隨復連載。", "南浦問何邊，冰谿復安在。"]'),
('6c92140c-d71f-472f-a3be-0c37fa2ae983','挽宋柳州綬','趙蕃','宋','宋诗','song-poetry','','[]','少陵在大曆，涪翁在元祐。',216,'全唐诗/poet.song.164000.json','["少陵在大曆，涪翁在元祐。", "相去幾百載，合若出一手。", "流傳到徐洪，繼起鳴江右。", "遂令風雅作，千載亡遺究。", "猗歟宋柳州，有志諸公後。", "作詩匪雕琢，氣質先忠厚。", "銳鋒深自斂，至寶不輕售。", "行年且半百，纔爲嶠南守。", "嶠南山水佳，中州未曾有。", "慨然遠游意，不憚萬里走。", "下車甫朞年，已上政成奏。", "無何天作孽，一病藥莫捄。", "跖壽回乃夭，天理果大謬。", "諸郎有家法，處己知孝友。", "崎嶇窮川陸，寓郡還公匶。", "卜龜得安宅，厥後斯雲覆。", "自憐蹤迹脫，敢敘親且舊。", "作詩寫餘哀，清淚空如𩆎。"]'),
('82077aaf-3023-45ac-bed3-b7d713d2a3e3','讀呂益卿所寄詩編明日四月一日也','趙蕃','宋','宋诗','song-poetry','','[]','舊雨連今雨，空庭斷行跡。',192,'全唐诗/poet.song.164000.json','["舊雨連今雨，空庭斷行跡。", "有時出門看，平湖四無壁。", "忽傳何處書，令我喜折屐。", "新知呂夫子，寄我詩滿冊。", "是時羊牛下，携之就簷隙。", "首披山居賦，奇字多莫識。", "徐徐見關鍵，坦若由戶出。", "定師離騷經，不入相如室。", "秋懷似選詩，法嚴仍事實。", "白沙龍陽作，如杜紀行役。", "卒至同谷吟，三讀淚橫臆。", "君何知之晚，今古蓋一律。", "兒曹苦問爺，何事爾不懌。", "徑卧忘解衣，中夜猶太息。", "曉窗啼鴂喧，今日復何日。", "和以扶疎篇，吾馭真可叱。"]'),
('8ae775d4-3c24-4cca-86ac-3b083d7f139e','五月下旬夢趙文鼎書寄斯遠','趙蕃','宋','宋诗','song-poetry','','[]','我不見君死，直疑君固生。',120,'全唐诗/poet.song.164000.json','["我不見君死，直疑君固生。", "賦詩無所寄，始復爲失聲。", "雞窗已三號，不但當既鳴。", "恍云秋之中，取酒相與傾。", "坐有饋生魚，歡言事煎烹。", "飲我謂杯小，何翅一再行。", "落月落未落，猶疑見鮮明。", "已焉覺夢爾，起坐神未平。", "滄波渺萬里，底處尋騎鯨。", "悵望莫子語，徘徊空思盈。"]'),
('038ed5df-7602-4bd8-ae12-121b61b5ca6d','重陽近矣風雨驟至誦邠老滿城風雨近重陽之句輒爲一章書呈教授沅陵','趙蕃','宋','宋诗','song-poetry','','[]','好詩不在多，自足傳不朽。',204,'全唐诗/poet.song.164000.json','["好詩不在多，自足傳不朽。", "池塘生春草，餘句世無取。", "詩家黄州潘，蘇黄逮師友。", "六義極淵源，一貫相授受。", "秋風有奇思，簞瓢忘巷陋。", "奈何催租人，敗之不使就。", "我謂此七字，已敵三千首。", "政使無敗者，意盡終難又。", "縱令葺成章，未免加飣餖。", "衣錦欲尚絅，何嘗炫文繡。", "一洗凡馬空，浪說充天廄。", "重陽晴則已，雨必風在口。", "今茲季月來，陰雨變時候。", "愔愔爵羅門，寂寂鳥噪牖。", "黄花冷未芳，黄葉掃復有。", "頗將寫吾懷，渠在那出手。", "併想東籬人，瞻前忽焉後。"]'),
('88400249-bc22-4fbf-aa63-0a12bc3c50a1','重賦畏知寓齋','趙蕃','宋','宋诗','song-poetry','','[]','君昔少年日，起家官帝城。',288,'全唐诗/poet.song.164000.json','["君昔少年日，起家官帝城。", "諸公盛稱許，往往動得名。", "夷途一步趨，可到公與卿。", "永懷松柏堅，高謝桃李榮。", "謚齋廼曰漸，毫髮無妄行。", "惟時尹夫子，猶躬南山耕。", "是公妙言語，一字與不輕。", "銘能爲君述，君志益以明。", "蹉跎才幾何，白髮殆數莖。", "低回尚前銜，牢落方南征。", "瀟湘清絕地，屈賈放逐情。", "感今重惻古，慨嘆識此生。", "究竟漸之義，顧未忘蘗萌。", "彼哉少年事，老矣夫何營。", "徹之易以寓，俯夢仰輒驚。", "何止宦爲客，身悟浮雲更。", "南軒子張子，好學如玄成。", "奮然吐長句，真覺萬戶輕。", "尹張志則異，與君盡同盟。", "見君極空洞，不比小器盈。", "嗣宗絕臧否，白眼常若瞠。", "司馬萬事好，是中差自宏。", "看君接物際，二士蓋熟評。", "君今家山居，扁榜猶在桁。"]'),
('3e95f8fc-8037-46d6-b962-7f43f1e0b71f','有懷子肅讀其詩卷因成數語','趙蕃','宋','宋诗','song-poetry','','[]','退之以文鳴，餘事尤長詩。',144,'全唐诗/poet.song.164000.json','["退之以文鳴，餘事尤長詩。", "名家賈孟流，未必踰於斯。", "淵明工五言，亦有歸來辭。", "迺知意到處，百發無一虧。", "孫侯絕人才，詩文俱中規。", "究其所源流，蓋匪一日基。", "有如審言門，遂至杜拾遺。", "餘波被芝蘭，同功有塤箎。", "嗟予晚聞道，未易等級推。", "劇談每從容，瞠若莫可追。", "閑窗念從公，兩脚如縶維。", "探囊獲新句，亦足慰所思。"]'),
('8b025b93-cc21-4254-a1b6-65b2ed9cb7b8','將謁介庵以詩先之','趙蕃','宋','宋诗','song-poetry','','[]','溪山故無盡，隨取隨以足。',240,'全唐诗/poet.song.164000.json','["溪山故無盡，隨取隨以足。", "平生笑賀監，敕賜鏡湖曲。", "今代介庵老，未歸先築屋。", "一區占何地，琵琶欣在目。", "是洲出誰氏，詩自隨州續。", "當年名絕唱，今也安可獨。", "溪如益彎環，山爲增隠伏。", "以知得所託，水潤由韞玉。", "一朝起乘傳，屢疏乞祠祿。", "俞音落天上，裝行不待束。", "還家謝溪山，拄杖巾一幅。", "開堂會賓友，快語瀉酃醁。", "我時得得來，奉屨期追逐。", "維摩適示病，對客倦冠服。", "悠然失前瞻，重詣規再卜。", "尺書往問訊，勞公手親復。", "愛我誨我至，敬拜不敢瀆。", "自憐生無資，是役尤僕僕。", "轅駒豈忘遠，歸棹戒已宿。", "但乞老先生，一言壯空麓。"]'),
('9a5ac5cb-c770-4b70-bbf2-6d82dd2b507c','書田中問示成父','趙蕃','宋','宋诗','song-poetry','','[]','每逢田中來，必問田中事。',108,'全唐诗/poet.song.164000.json','["每逢田中來，必問田中事。", "言者爲蹙頞，聽者爲酸鼻。", "皆云水節愆，所以陂修廢。", "田栽未曾了，旱勢已復至。", "承天無可說，有澱亦將既。", "早禾以日論，晚禾尚月計。", "餓莩已五六，疫死又三四。", "自茲儻無雨，何以能卒歲。", "時成道危苦，示爾應歔欷。"]'),
('ee81a719-02dd-4124-a383-2688c87f97b1','送逸歸上饒赴試','趙蕃','宋','宋诗','song-poetry','','[]','謂汝可勿去，汝去意已堅。',144,'全唐诗/poet.song.164000.json','["謂汝可勿去，汝去意已堅。", "念欲終不遣，汝請倍諄然。", "平時父母傍，一事略不與。", "及今身自行，凡百誰汝護。", "况當苦炎熱，道遠不可說。", "晚須背斜陽，曉要踏殘月。", "墟落乃可爾，陂湖深戒之。", "藥物務頻進，童馬勿過疲。", "得失渠有命，勉旃非日競。", "汝解事文科，吾其老三徑。", "汝歸見吾友，見叔仍見舅。", "爲道糠覈肥，無奈相思瘦。"]'),
('50c33722-9819-474f-bbd0-11b25751ee3f','寄在伯三首後一首併示逸  其一','趙蕃','宋','宋诗','song-poetry','','[]','出門欲尋巖，聞君已行舟。',48,'全唐诗/poet.song.164000.json','["出門欲尋巖，聞君已行舟。", "川遠不可涉，佇立空夷猶。", "雨風既冥冥，離思復幽幽。", "人生苟無別，安能成白頭。"]'),
('636f7a61-3e66-443f-84c4-2e66f4ef69e2','寄在伯三首後一首併示逸  其二','趙蕃','宋','宋诗','song-poetry','','[]','君行日已遠，我思日益長。',48,'全唐诗/poet.song.164000.json','["君行日已遠，我思日益長。", "何物可諭此，山高水茫茫。", "人生要有別，男兒志四方。", "奈此老多感，况於朋友良。"]'),
('99e4680d-ae52-4d96-ae54-1eceafdca8ea','寄在伯三首後一首併示逸  其三','趙蕃','宋','宋诗','song-poetry','','[]','兒行欣得師，爺往愁欠友。',48,'全唐诗/poet.song.164000.json','["兒行欣得師，爺往愁欠友。", "去爺勿惘然，得師知慰否。", "有時頻執經，無事莫多酒。", "無謂數月程，秋風在回首。"]'),
('20a36372-6dec-4ee7-84e1-755e39418c4a','寄主管舅二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','少公上黄扉，長公思玉局。',72,'全唐诗/poet.song.164000.json','["少公上黄扉，長公思玉局。", "恭惟我舅氏，出處似前躅。", "潯陽開三徑，鏡湖賜一曲。", "是爲千載人，何有萬鍾祿。", "新詩久不誦，妙墨時在目。", "黄落又秋風，林空見松竹。"]'),
('dad30d95-9be3-46f6-9252-f6e265265f44','寄主管舅二首  其二','趙蕃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','甥官楚西南，舅住天尺五。',72,'全唐诗/poet.song.164000.json','["甥官楚西南，舅住天尺五。", "安否候何如，歲月曠如許。", "阿兄有書來，報道安輿舉。", "東閣故莫留，西湖要爲主。", "寥寥和靖君，遺跡墮榛莽。", "咫尺到梅花，追隨悵脩阻。"]'),
('9f5c94d6-a97e-498c-935f-1939c1047f9b','寄衡州舅氏','趙蕃','宋','宋诗','song-poetry','','[]','西山有喬松，蒙附百畝陰。',216,'全唐诗/poet.song.164000.json','["西山有喬松，蒙附百畝陰。", "蓬蒿宅其下，旅生亦駸駸。", "永懷豫章公，斯文金玉音。", "徐洪蓋自出，源流高以深。", "吾舅之於黄，端若一體臨。", "媿我望數子，引尺那及尋。", "弱冠誦流傳，蒼蒼且垂簪。", "前帆去已駛，後舟政憂沉。", "憶昨送弟行，作詩道離襟。", "末篇何所言，志我念母心。", "豈知辱貺答，碔砆致璆琳。", "退之贈郊籍，少陵寄高岑。", "我固解公意，誨我力自任。", "不惟書諸紳，起居見前參。", "幾思侍公側，取酒親酌斟。", "積荒頼鋤耰，痼疾蘄砭鍼。", "涉湘定何時，紙貴行見今。", "勿繼屈賈詞，起和南風琴。"]'),
('467780e4-afe2-4199-a07e-23a109c428d5','寄劉叔驥','趙蕃','宋','宋诗','song-poetry','','[]','朝行巴陵帆，暮泊漢陽鼓。',48,'全唐诗/poet.song.164000.json','["朝行巴陵帆，暮泊漢陽鼓。", "胡爲我所思，祗說在何許。", "折麻念離居，搴若懷遠渚。", "望望莫致之，江頭漫延佇。"]'),
('c02028e0-c080-4e78-964f-66746b1741bb','寄鄭舜舉','趙蕃','宋','宋诗','song-poetry','','[]','吾友歐陽生，詩律雜郊島。',48,'全唐诗/poet.song.164000.json','["吾友歐陽生，詩律雜郊島。", "相逢每談君，必謂詩太好。", "送行許長句，兼復書小草。", "鴻鴈儻不來，何由慰懷抱。"]'),
('0f2ee5ac-5615-45b3-b56b-ca083d166306','寄懷在伯三首  其一','趙蕃','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','沅水與湘水，合流俱洞庭。',48,'全唐诗/poet.song.164000.json','["沅水與湘水，合流俱洞庭。", "如何君於我，迺隔影與形。", "滄江鷗鷺野，深林蘭蕙馨。", "含章斯發發，遂性逐冥冥。"]'),
('3b217308-6261-4ac2-a28f-8c213179fcb5','寄懷在伯三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','我苦千里役，兒荒三月書。',48,'全唐诗/poet.song.164000.json','["我苦千里役，兒荒三月書。", "役苦殆委頓，書荒廑墾鋤。", "夜雨倒湖水，春耕競田廬。", "事貴在勇决，爾胡但居諸。"]'),
('1185f32d-10d4-4d66-99ac-a8b69d5ef20c','寄懷在伯三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','倏爾聽鳴鴂，慨然悲衆芳。',48,'全唐诗/poet.song.164000.json','["倏爾聽鳴鴂，慨然悲衆芳。", "春事且衰歇，吾行可相羊。", "問年踰不惑，嘐嘐斯謂狂。", "益矣多聞友，從之道阻長。"]'),
('197d9ae2-81a4-48fa-81fe-a7816b4a4414','十月八日聞鷄鳴即起案上偶有陶集繙閱數詩有懷斯遠三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','衾寒數窺窗，窗暗鷄已號。',48,'全唐诗/poet.song.164000.json','["衾寒數窺窗，窗暗鷄已號。", "比鄰遞東西，我起披縕袍。", "始占霜檐粲，忽聽風林鏖。", "迺知中夜雨，吾念亦良勞。"]'),
('ebe0468f-5af6-481f-b88e-410789cd1aa7','十月八日聞鷄鳴即起案上偶有陶集繙閱數詩有懷斯遠三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','寒缸燭餘膏，破爐明宿火。',48,'全唐诗/poet.song.164000.json','["寒缸燭餘膏，破爐明宿火。", "嬾復布衾眠，遂作藜牀坐。", "默坐亦何爲，姑取陶詩課。", "我友安在哉，良思與之和。"]'),
('44808a62-77f2-4104-b306-67f7cf556111','十月八日聞鷄鳴即起案上偶有陶集繙閱數詩有懷斯遠三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','聞君治書樓，誦書仍課文。',48,'全唐诗/poet.song.164000.json','["聞君治書樓，誦書仍課文。", "古人不朽計，政在三冬勤。", "今時獨不然，白屋期青雲。", "君豈斯人歟，大雅迥不羣。"]'),
('a5621293-195d-4246-9aeb-5023ddc92dd5','冬至後五夕頻夢陳擇之','趙蕃','宋','宋诗','song-poetry','','[]','所見日雜遝，寧復當我思。',192,'全唐诗/poet.song.164000.json','["所見日雜遝，寧復當我思。", "我此僻且陋，三夜頻夢之。", "遣騎告欲行，手持一通詩。", "發緘與兒讀，絕妙解人頤。", "我欲留君飯，顛倒裳與衣。", "宛如快閣日，不似南浦時。", "到蜀今幾日，首議何所爲。", "一儉勝百奢，徐公亦安施。", "幕府足閒暇，浣花有餘嬉。", "謫仙縱多才，蜀道無險巇。", "微痾固除洗，起居當具宜。", "蜀中富名士，匪卜亦隠醫。", "秘方苟有傳，寄我無或遺。", "寄我亦何用，多病成早衰。", "歸哉復歸哉，秣馬車載脂。", "上君白玉堂，王人亦黄扉。"]'),
('3c830105-ec15-4ab9-99c6-579e455a96bb','雨中憶花寄懷曾季永嚴從禮二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','餘寒苦淹留，破衲無遽棄。',72,'全唐诗/poet.song.164000.json','["餘寒苦淹留，破衲無遽棄。", "欣聞好雨來，正念春耕未。", "瀕南花退早，何止桃李事。", "牡丹及酴醿，錦碎仍玉委。", "流年定何之，嘆息付流水。", "想像田廬中，桑柔麥如尾。"]'),
('b3f047f9-b755-40a1-8248-ecefcdfe4b02','雨中憶花寄懷曾季永嚴從禮二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','白下古聚落，種花成土風。',84,'全唐诗/poet.song.164000.json','["白下古聚落，種花成土風。", "貧者籬疎薄，富家欄檻重。", "嚴曾蓋甥舅，交友著我中。", "牡丹大盤盂，酴醿鬰蛟龍。", "走觀仍折送，憶費詩酒供。", "今年百里外，此事不得同。", "坐病風雨惡，因之懷二公。"]'),
('59648321-2cc7-47e2-8bf2-1b165ed5e941','湖州親舊二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','憶昔倚少壯，不畏離別苦。',72,'全唐诗/poet.song.164000.json','["憶昔倚少壯，不畏離別苦。", "及今更中年，頗識謝公語。", "連朝接殷勤，故已辦茲去。", "今晨竟不免，况此風更雨。", "夾溪誰家柳，向我强作舞。", "汝且不自持，寧能留我住。"]'),
('50477d01-543d-4f3c-a24d-d82cf439eaff','湖州親舊二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','舟行風打頭，苦恨行不駛。',72,'全唐诗/poet.song.164000.json','["舟行風打頭，苦恨行不駛。", "今晨得順風，亦自非所喜。", "溪山如許佳，欲畫無絕藝。", "要當稍收拾，一一付詩裏。", "近看忽成遠，得此已失彼。", "但令人此心，惘惘不足耳。"]'),
('b6a463b4-1a1b-411e-b1bb-90de8e749dd5','寄孫子進昆仲','趙蕃','宋','宋诗','song-poetry','','[]','霜風入枯葦，客枕那能安。',240,'全唐诗/poet.song.164000.json','["霜風入枯葦，客枕那能安。", "起尋短燈檠，捐書復慵看。", "緬思平生遊，平陸多奔湍。", "懷哉豈無人，荆吳路漫漫。", "大孫行秘書，今古靡不觀。", "天文號隠奧，坐使十載殫。", "溢而爲文章，卷舒見波瀾。", "丞哉亦奇士，老不卑小官。", "詩成太白豪，笑殺東野寒。", "酒酣或看劍，肯爲無魚彈。", "儀也節更苦，凜若誰能干。", "譬之於草木，青松蔽春蘭。", "不願太官賜，自愛苜蓿盤。", "相携住荆溪，冥鴻渺雲端。", "釀泉飲佳客，採溪薦朝餐。", "不負風月佳，始知天地寬。", "我欲往從之，買船斬釣竿。", "富春訪嚴陵，吳淞覓張翰。", "人生鮮如意，高趣况易闌。", "君毋輕此樂，此樂非游般。"]'),
('078ae700-a9d9-4264-acd3-f99a8b00017a','寄李晦庵','趙蕃','宋','宋诗','song-poetry','','[]','昔我曾大父，高交世無倫。',288,'全唐诗/poet.song.164000.json','["昔我曾大父，高交世無倫。", "晚生不盡得，所知三數人。", "堂堂贊皇公，實能繼張陳。", "諫垣磨薦墨，許之以經綸。", "江陵竟連蹇，翰墨留餘珍。", "晦庵乃其季，英氣蓋八垠。", "家世斯文事，屬付真不泯。", "我亦早聞義，中年見天津。", "委曲問先世，與成傾蓋親。", "公故鼎富貴，我乃困賤貧。", "有詩猥蒙誦，顧乏佳句新。", "往過龔州庵，凍筆書吟呻。", "公來辱繼作，春氣動壁塵。", "去年濡須家，墨妙出傾囷。", "乍疑何人書，老大能精神。", "熟視乃鄙作，愧汗幾拭巾。", "已焉忽語此，知公蓋深仁。", "憫我抱奇疾，不救死且瀕。", "稍加匕寸施，庶使屈得伸。", "寧知苶然姿，攣拳殆終身。", "一官胡爲哉，鴻毛等千鈞。", "野馬窘受駕，白鷗悲就馴。", "五斗未及飽，已遭窮鬼嗔。", "劍津駭騰變，牛衣泣酸辛。"]'),
('f387b270-8a32-497d-bff1-b0698d4eb632','寄施進之','趙蕃','宋','宋诗','song-poetry','','[]','我遊尖峰回，一步成數憩。',288,'全唐诗/poet.song.164000.json','["我遊尖峰回，一步成數憩。", "仰攀松夭矯，俯睨石贔屭。", "路窮入平野，飛鳥迎决眥。", "廬舍半茅瓦，阡陌相櫛比。", "謂皆耕稼徒，不復問名字。", "那知君子居，迺在青山際。", "聽君談所宅，悟我曾略至。", "時猶未識面，豈得漫通刺。", "都城一邂逅，草木同臭味。", "我旋反林棲，君適寓古寺。", "肯來穉子師，歷歲殆逾二。", "既均手足親，又篤朋友義。", "去年君還歸，城闉直童騎。", "楮生分草餘，鱘鮓動食指。", "今年我屬疾，故舊多遐棄。", "愧君不憚勞，衝暑到溪次。", "買肉烹伏雌，芼薑仍著豉。", "無資鹿脯求，竟是豬肝累。", "以我病苦渴，榴實富汁滓。", "纍纍解包裹，其大蓋絕市。", "勸我養形神，勉我進藥餌。", "裴回晝難別，展轉宵失寐。", "分携六十日，顧我病祇爾。", "雖云間何闊，戀戀曾莫置。"]'),
('ea747061-f322-4240-ad36-83fad87c8959','寄雷丈朝宗','趙蕃','宋','宋诗','song-poetry','','[]','憶我前年秋，驅羸赴行在。',144,'全唐诗/poet.song.164000.json','["憶我前年秋，驅羸赴行在。", "凄凉醴陵門，公獨枉軒盖。", "客中遇還使，素書僅一通。", "計之曾未達，公起使廣東。", "而我困流徙，日月無定止。", "逮今得還山，莽莽舟在水。", "長沙公寓鄉，來往維其常。", "儻復後此使，音問政渺茫。", "如公所抱負，外歛中甚富。", "遄歸定非晚，入侍帝左右。", "車行過懷玉，寄聲到林谷。", "容我復驅羸，宵征戒童僕。"]'),
('db84b762-60b5-4147-b40b-99a3815324e5','寄范建康','趙蕃','宋','宋诗','song-poetry','','[]','平生聞石湖，謂是千載人。',120,'全唐诗/poet.song.164000.json','["平生聞石湖，謂是千載人。", "去年此何緣，乃獲身造門。", "公蓋廊廟貴，我乃裋褐貧。", "既以賓客見，復叨尊俎陳。", "談間必文字，媿我非比論。", "雖知媿公厚，猥誦終慙新。", "別來才一書，無使無由頻。", "河內聞發粟，原思闕周鄰。", "江東且云然，湖外將何因。", "再拜謝洪喬，浮沉問水濱。"]'),
('5c3d81c6-6e5d-4855-803a-7125d93c7173','頃見迂齋談游子明不容口且誦其詩恨未遂傾蓋之願前年一見既慰我心所恨俱匆遽不得款語近過迂齋聞寄書又復訪問死生顧屏竄林壑逃死無日何以辱盛意如此輒成一詩奉寄','趙蕃','宋','宋诗','song-poetry','','[]','平生施迂齋，劇談高安郡。',108,'全唐诗/poet.song.164000.json','["平生施迂齋，劇談高安郡。", "山川固清遠，得士且韻勝。", "就中拔其尤，游子蓋袖領。", "長哦唱酬詩，使我醉復醒。", "前年客游杭，冰雪滯歸𦩘。", "相逢逆旅間，一笑交已定。", "近聞寄書來，諄復問名姓。", "如公真騏驥，顧我乃下乘。", "歲晚儻不遺，庶幾望三徑。"]'),
('d90b42c7-a76b-4d1f-8003-e0771745148f','寄謝新安豐守胡達孝見遺近詩一軸便呈甘叔異章夢與','趙蕃','宋','宋诗','song-poetry','','[]','向子識損益，揚雄愛清靜。',144,'全唐诗/poet.song.164000.json','["向子識損益，揚雄愛清靜。", "我行蕭灘上，二宅駕輒命。", "而於酬唱中，又得胡安豐。", "詩作文選體，字有眉山蹤。", "掃門今已後，傾蓋非敢望。", "談間問先世，蓋乃丈人行。", "歸州片時程，乃復來高軒。", "從容僅數刻，傾倒貽百篇。", "平生嗜江山，到處須著語。", "及茲足漫摇，久乃舌自拄。", "時惟桂林掾，與彼新喻丞。", "俱以行卷來，暴富如不勝。"]'),
('6203e23d-cd70-486f-b9dc-862fb4390710','代書寄吳仲權','趙蕃','宋','宋诗','song-poetry','','[]','長沙失會面，龍陽將叩門。',120,'全唐诗/poet.song.164000.json','["長沙失會面，龍陽將叩門。", "君行黄鶴樓，我乃桃花源。", "裴回遂兩月，問訊非一言。", "時時得新作，日日思高軒。", "寧知竟相失，有抱闕細論。", "聞君方被薦，清廟陳璵璠。", "而我政落南，空江擷蘭蓀。", "雖云出處異，得以書疏存。", "言之有不盡，筆兮還載援。", "惟當道情愫，故爾略寒暄。"]'),
('61b95ee7-9a7d-4a3c-98f8-150232bc5264','潘恭叔欲歸壽其母夫人謝子暢以事客其館辭病在告騎招周文顯爲別僕不得與也作詩寄三兄','趙蕃','宋','宋诗','song-poetry','','[]','伏暑推不去，秋風來何暮。',72,'全唐诗/poet.song.164000.json','["伏暑推不去，秋風來何暮。", "深居謝巾幘，適意親杖屨。", "緬懷江湖遊，悵望南北路。", "舊交已如隔，新知孰成故。", "龐公非浪出，東野方廢務。", "共餞獻觴人，我病不得與。"]'),
('f3b3270b-2b6a-48e5-9035-ea7d60b620c9','簡寄潘恭叔','趙蕃','宋','宋诗','song-poetry','','[]','物生懼焦枯，吾身困蒸煮。',72,'全唐诗/poet.song.164000.json','["物生懼焦枯，吾身困蒸煮。", "起占天外雲，坐隔空中雨。", "故人住吳越，一別幾寒暑。", "今焉在咫尺，何事復間阻。", "緬思冰雪容，重想金玉語。", "可但發其蒙，端能病斯愈。"]'),
('57264395-63cd-4f17-a244-8b7466616368','寄懷章衢州辛越州','趙蕃','宋','宋诗','song-poetry','','[]','江東去江西，道阻而且長。',120,'全唐诗/poet.song.164000.json','["江東去江西，道阻而且長。", "懷我金石交，每瞻鴻鴈行。", "信州去衢州，道阻而匪脩。", "黄花遂九日，明月負中秋。", "江東去浙東，江表邈剡中。", "莫云巖壑異，固有丘壑同。", "一出與一處，或嘿而或語。", "行步澀如棘，欲飛恨無羽。", "風高已木落，薄寒能中人。", "室邇人甚遠，不孤必有鄰。"]'),
('b2f8706e-4979-4e85-b20d-8f348cf404dc','發隆興後寄宋茂叔趙然道昆仲併屬達後篇於待制侍郎二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','連朝南浦亭，繫此一葉舟。',72,'全唐诗/poet.song.164000.json','["連朝南浦亭，繫此一葉舟。", "未去已欲動，既行奚復留。", "篙撐尚依岸，風至忽打頭。", "中宵渺無際，清曉浩莫收。", "行止固有定，淹速寧與謀。", "我友邈難見，西山澹凝秋。"]'),
('1e9846d8-6859-4ba3-ba79-c845b928ed1f','發隆興後寄宋茂叔趙然道昆仲併屬達後篇於待制侍郎二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','晁君父之舅，徐子我之友。',72,'全唐诗/poet.song.164000.json','["晁君父之舅，徐子我之友。", "晁詩紫微來，徐學新安後。", "徐固困簞瓢，晁復厭奔走。", "當今諸侯賢，孰愈豫章右。", "經行見雖屢，款語不能又。", "煩君因几席，爲我探懷袖。"]'),
('40c846ef-6358-40bb-8152-cef384a76224','寄徐斯遠并成父弟','趙蕃','宋','宋诗','song-poetry','','[]','淅瀝夜來雨，蕭條林下秋。',120,'全唐诗/poet.song.164000.json','["淅瀝夜來雨，蕭條林下秋。", "因之憶我弟，重以思吾儔。", "農工方鼎來，蠶事已告休。", "得無陰寒妨，知復多寡收。", "微官本爲貧，中道成倦游。", "洪波政稽天，險路新摧輈。", "吾儔與我弟，既喜應見憂。", "憂我困一簞，喜我歸故丘。", "付與有定分，短長寧自謀。", "相期黄髮保，共勉素風脩。"]'),
('80045f02-c600-47fe-a335-abd5369f6053','得友人俞玉汝書云客遊建業月嘗能致錢十萬時方客溧陽感假尉事作詩寄玉汝','趙蕃','宋','宋诗','song-poetry','','[]','士有孟東野，薦乃韓退之。',48,'全唐诗/poet.song.164000.json','["士有孟東野，薦乃韓退之。", "五十纔一尉，俸錢仍半支。", "嗟予亦蹇者，白髮方糟醨。", "因聲謝吾友，十萬亦多爲。"]'),
('d0c5aef5-f63a-4fd2-8149-594c60ca30d6','寄答潘文叔并屬恭叔五首  其一','趙蕃','宋','宋诗','song-poetry','','[]','人生無友朋，何以攻短闕。',48,'全唐诗/poet.song.164000.json','["人生無友朋，何以攻短闕。", "我交君弟兄，意合非固結。", "奈何不須臾，已復經歲月。", "葉落政知秋，竹新還縹節。"]'),
('13313d2f-f31d-4583-b8aa-dde1db88e51c','寄答潘文叔并屬恭叔五首  其二','趙蕃','宋','宋诗','song-poetry','','[]','君家舍人公，世謂王楊作。',48,'全唐诗/poet.song.164000.json','["君家舍人公，世謂王楊作。", "誰知所傳授，白首終林壑。", "至今有源流，涇渭分清濁。", "豈比世上兒，風姿矜濯濯。"]'),
('6e399be6-e7b6-464a-89da-a9a1ac6e1413','寄答潘文叔并屬恭叔五首  其三','趙蕃','宋','宋诗','song-poetry','','[]','主簿舍徙說，御史身耻呈。',48,'全唐诗/poet.song.164000.json','["主簿舍徙說，御史身耻呈。", "夫豈爲異與，義理可不明。", "嗟哉後來者，窺踰多喪貞。", "所以使古人，炯炯長擅名。"]'),
('66499f67-34de-41ce-a012-eca3cc7bfd8f','寄答潘文叔并屬恭叔五首  其四','趙蕃','宋','宋诗','song-poetry','','[]','平生蔣詡徑，家傍揚雲宅。',48,'全唐诗/poet.song.164000.json','["平生蔣詡徑，家傍揚雲宅。", "木老夏敷陰，泉疏春動脈。", "索居每懷弟，斗食身久客。", "况乃蒲柳姿，茂悅非松柏。"]'),
('68ba850a-e5df-4f58-bba7-cea838b78a6c','寄答潘文叔并屬恭叔五首  其五','趙蕃','宋','宋诗','song-poetry','','[]','斯文呂與張，用世故落落。',48,'全唐诗/poet.song.164000.json','["斯文呂與張，用世故落落。", "年來踵蒿原，天意亦已虐。", "君嘗登其門，如戶發管籥。", "何當傳相授，此道得深酌。"]'),
('dd4976df-260e-4f8a-800d-a0aa2dcf9187','贈曾槃樂道','趙蕃','宋','宋诗','song-poetry','','[]','我居懷玉山，茶山非一游。',96,'全唐诗/poet.song.164000.json','["我居懷玉山，茶山非一游。", "每觀文清竹，凜若人好修。", "往來道嘉禾，詩曾長公投。", "十年再建業，問勞加綢繆。", "中歌殄瘁詩，尺疏去莫由。", "雖微荆州論，感歎自不休。", "今日復何日，蘭溪繫歸舟。", "典型君尚有，一見寫余憂。"]'),
('407111be-7eab-4a76-9fff-82df33d3f0be','贈路芾德章','趙蕃','宋','宋诗','song-poetry','','[]','憶昔介菴老，視我猶子弟。',120,'全唐诗/poet.song.164000.json','["憶昔介菴老，視我猶子弟。", "於今於越州，必灑西州涕。", "重憶郎中公，契與外氏通。", "慨我未知學，一見寧發蒙。", "公於介菴老，筆硯相親友。", "而於郎中公，學問躬授受。", "與我非素交，有兒仍甚愚。", "辱公收教之，舉俗有是夫。", "辱書示深眷，未報無加譴。", "平日但聞風，今朝真識面。"]'),
('250b7a26-8c65-4605-acdd-15c5f14b7a20','贈孫從之','趙蕃','宋','宋诗','song-poetry','','[]','吏事要及民，何假須緣飾。',240,'全唐诗/poet.song.164000.json','["吏事要及民，何假須緣飾。", "是故西都儒，往往名背實。", "萍鄉孫明府，抱負惟儒術。", "起家長此邦，爲政皆有述。", "催科非我急，急民使滋殖。", "今夏戒艱食，粒米勸蓄積。", "種麥貴宿耕，禾孫視前績。", "是我賢弟昆，三市俱鼎立。", "正之官南昌，大吏遭絲刻。", "爲陳先世事，稍稍從吾律。", "竊嘗歎斯人，當補諫爭缺。", "如何即九原，我爲長太息。", "叔也今王官，路以雲霄逼。", "才難未易識，屢薦今始入。", "贛川與洪州，目見非耳得。", "使之佐廟謨，彌縫寧闕職。", "公行被裏言，步武俱文石。", "爲移一縣政，於以均萬國。", "我雖落蠻夷，歸來豈無日。", "儻遂樂耕耘，於焉吾事畢。"]'),
('8a0157a1-44cd-4224-b892-d8cc2caf3df5','贈耆英','趙蕃','宋','宋诗','song-poetry','','[]','用世故欲巧，拙者終近德。',48,'全唐诗/poet.song.164000.json','["用世故欲巧，拙者終近德。", "人皆笑髯曾，我獨長太息。", "貧吾豈人爲，問天天不癡。", "君看松柏受，寧與春風期。"]'),
('525295a6-0371-48c5-8d11-6e345fba7084','贈尤檢正四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','多書如鄴侯，讀書如張巡。',48,'全唐诗/poet.song.164000.json','["多書如鄴侯，讀書如張巡。", "一代信不數，吾身見能親。", "門牆雖云舊，蹤跡乃若新。", "政以沅湘遠，無由書疏頻。"]'),
('0e598021-45f4-42ef-9303-d8f611ea8a35','贈尤檢正四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','往焉石灰橋，粲粲方秘書。',48,'全唐诗/poet.song.164000.json','["往焉石灰橋，粲粲方秘書。", "近者南浦亭，皇皇乃軺車。", "遄歸今幾年，人望益以儲。", "俱期白獸省，共徯玉堂廬。"]'),
('89c8071c-3ecb-4e38-bf9f-0c6c8bea5d10','贈尤檢正四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','榜舟浙江潮，僦屋長安雪。',48,'全唐诗/poet.song.164000.json','["榜舟浙江潮，僦屋長安雪。", "寒濤幸少年，積凍還復結。", "雖逃蛟鰐虞，未免薪芻絕。", "噂𠴲悵難登，囁嚅羞妄悅。"]'),
('3d0cca2b-30e9-496c-8495-661f7740a3a5','贈尤檢正四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','季秋過廬陵，客有示新錄。',48,'全唐诗/poet.song.164000.json','["季秋過廬陵，客有示新錄。", "尤楊兩詩翁，間以嚴州陸。", "澧蘭與沅茝，頓覺無芬馥。", "何况破囊中，欲探還自忸。"]'),
('1ce9ef9d-0fac-445c-974c-df41b37125bb','呈嚴黎二師并寄韓季蕭','趙蕃','宋','宋诗','song-poetry','','[]','名者世公器，丈也寧取虛。',264,'全唐诗/poet.song.164000.json','["名者世公器，丈也寧取虛。", "我聞曾嚴黎，蓋自入學初。", "每繙東萊集，出門思稅車。", "一見良不易，寒暑三十餘。", "前年太和官，遣書叩曾廬。", "得報副以詩，妙處真起予。", "更有嚴黎在，因曾庶幾歟。", "驟聞鄂渚歿，經年爲欷歔。", "嚴黎固老矣，我亦雪滿梳。", "奈何苦偪仄，决焉不躊躇。", "嚴師雖龍鍾，眸子炯炯如。", "縱云昏忘集，解記韓呂徐。", "黎君更强健，白髮盡掃除。", "豈非仙人家，服食信有諸。", "我詩燕石爾，報以瓊與琚。", "便當與曾作，編聯世行於。", "季蕭陵陽孫，與嚴並門居。", "棄捐舉子業，盡讀先世書。", "時從二老遊，不曳王門裾。", "我言無可采，殷勤乃來渠。", "二老已知名，保此良不疎。", "惟我與爾者，勉哉涼入墟。"]'),
('0fb90d31-871c-4f86-ac1f-42b1142f3423','次韻斯遠見寄','趙蕃','宋','宋诗','song-poetry','','[]','天地如許寬，出門自無之。',72,'全唐诗/poet.song.164000.json','["天地如許寬，出門自無之。", "筠窗書味長，靠壁筇一枝。", "吾曹本通脫，孰謂書有色。", "但取翰墨娛，且然相主客。", "霜簷曉皚皚，落葉擁不開。", "門開有行迹，元是題詩來。"]'),
('ecab1ff6-2c4e-4062-90e7-de09c3b4b760','次韻馬莊父問行期之什','趙蕃','宋','宋诗','song-poetry','','[]','日日言歸去，年年事遠遊。',36,'全唐诗/poet.song.164000.json','["日日言歸去，年年事遠遊。", "世態甘若醴，我曹和不流。", "殷勤枉詩問，準擬繫帆留。"]'),
('144569bb-de77-4ddc-8999-b50ef472f0c3','次韻斯遠二十七日道中見懷二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','去冬黄公亭，咏詩看梅花。',72,'全唐诗/poet.song.164000.json','["去冬黄公亭，咏詩看梅花。", "深行或山崦，縱步亦水涯。", "雖知追隨樂，固有間闊嗟。", "詞鋒君莫當，銳甚如莫邪。", "我欲尾其後，志局道苦遐。", "千年定藏山，一世斯名家。"]'),
('8e118253-7562-4d58-a5cc-113c1e3be404','次韻斯遠二十七日道中見懷二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','我姿甚不敏，與俗仍倍殊。',72,'全唐诗/poet.song.164000.json','["我姿甚不敏，與俗仍倍殊。", "難貪太常酒，顧歸陶令廬。", "山中亦何有，寂寞誰與娛。", "晤言闊無友，展卷聊得書。", "人生七十稀，我今半已餘。", "百里九十戒，躊躇重躊躇。"]'),
('54ef7299-ecb8-406d-aba7-20bbc457effc','次韻審知遣興','趙蕃','宋','宋诗','song-poetry','','[]','沉綿既逾時，生死誰或訪。',120,'全唐诗/poet.song.164000.json','["沉綿既逾時，生死誰或訪。", "殷勤惠之書，疇昔固有望。", "載觀近賦詩，頗復獻窮狀。", "功名岐則多，究竟策非上。", "賈誼卒避灌，晁錯終死盎。", "孰愈安一區，隨事享三當。", "嗟我信畸人，逐食無定向。", "轉蓬真飄風，斷綆遭逆浪。", "悠悠任通塞，冉冉失少壯。", "志願老棲遲，耕寬築夷曠。"]'),
('02499e75-16b6-4aba-a214-0e5feed066fc','與蘇運使詡四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','筠陽有賢牧，典選得望郎。',48,'全唐诗/poet.song.164000.json','["筠陽有賢牧，典選得望郎。", "漢廷急獻納，使節乃輝光。", "翰墨一門盛，人才當代良。", "平生願識面，今日獲升堂。"]'),
('09c93653-fadf-43c2-9804-54b5795a547e','與蘇運使詡四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','培塿無大木，溝瀆無巨魚。',48,'全唐诗/poet.song.164000.json','["培塿無大木，溝瀆無巨魚。", "窈然澗壑深，渺若江海潴。", "澗壑雖云深，蕭艾寧廢諸。", "江海雖云廣，蛭螾亦與居。"]'),
('3d40711e-d1f8-487e-9c33-713409857cb5','與蘇運使詡四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','昔在元祐初，重選館閣才。',48,'全唐诗/poet.song.164000.json','["昔在元祐初，重選館閣才。", "時我高王父，實與數子偕。", "黄門任言事，薦口曾爲開。", "有孫不能振，白髮自興哀。"]'),
('23544dc4-ede9-4816-80dc-8e90ed055417','與蘇運使詡四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','草木日摇落，道路方阻長。',48,'全唐诗/poet.song.164000.json','["草木日摇落，道路方阻長。", "豐年米故賤，逆旅錢自荒。", "暝宿村舍烟，朝行板橋霜。", "豈不願息肩，於此增徬徨。"]'),
('5ef44c7a-f331-4cac-a024-85b9c3e17ada','閨怨二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','維南有佳人，實秉絕代色。',48,'全唐诗/poet.song.164000.json','["維南有佳人，實秉絕代色。", "幼聞妾婦道，不肯傾人國。", "幽居今過時，行媒迥無迹。", "世方求冶容，孰能知婦德。"]'),
('1dfe3908-4f29-4397-ab6c-10e6f3fabb42','閨怨二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','東鄰有賢女，膏沐不加御。',48,'全唐诗/poet.song.164000.json','["東鄰有賢女，膏沐不加御。", "朝惟躬奉養，莫且趣機杼。", "曰賢嫁何晚，政坐一貧故。", "誰能幣聘之，此女非傲婦。"]'),
('468d03b6-eea8-4c74-8fb6-7855bd7859af','檢校竹隠竹數三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','憶昔山中居，朝莫惟脫粟。',48,'全唐诗/poet.song.164000.json','["憶昔山中居，朝莫惟脫粟。", "何以居之安，頼此猗猗綠。", "一朝顧舍去，夢寐勞心目。", "今晨忽在眼，如客得歸宿。"]'),
('099b4070-ccf9-454a-8c63-569c09a25f3c','檢校竹隠竹數三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','竹雖不解語，風能爲之言。',48,'全唐诗/poet.song.164000.json','["竹雖不解語，風能爲之言。", "斧斤伐我本，畜牧踐我孫。", "戕者可以隄，踐者可以藩。", "我顧不忘汝，汝言毋重煩。"]'),
('cda10937-9d82-4a56-aae7-e8598eeda29c','檢校竹隠竹數三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','錢多論以屋，畜多論以谷。',48,'全唐诗/poet.song.164000.json','["錢多論以屋，畜多論以谷。", "我獨何爲者，箇箇數脩竹。", "竹箇雖不多，是亦我所欲。", "於以盜之防，盜防寧此足。"]'),
('cd0a200a-c638-48dc-8ded-eaa6ef346562','移松與斯遠同賦','趙蕃','宋','宋诗','song-poetry','','[]','垂垂白髮侵，落落青松愛。',36,'全唐诗/poet.song.164000.json','["垂垂白髮侵，落落青松愛。", "協趣在山林，移根出蓬艾。", "逝矣我何悲，蒼然渠可耐。"]'),
('3709c2ba-17e4-4bc9-bd17-f33f46dce1cc','舂米方歸瑞峰寺僧送菜適至遂成晚饋','趙蕃','宋','宋诗','song-poetry','','[]','香秔出村舂，晚菘來野寺。',48,'全唐诗/poet.song.164000.json','["香秔出村舂，晚菘來野寺。", "八珍不吾易，一飽有餘味。", "鳴鐘與列鼎，飯蔬仍飲水。", "此道本平觀，在人安擇爾。"]'),
('ab7865e3-ba07-429a-930f-b05407c8fbfa','栽田行','趙蕃','宋','宋诗','song-poetry','','[]','早田栽已成，晚田耕未遍。',144,'全唐诗/poet.song.164000.json','["早田栽已成，晚田耕未遍。", "風吹苗已長，汝事不可緩。", "邇來雨況足，高下通溉灌。", "雖云手足瘽，孰愈溝壑患。", "自茲日不百，早稻期入爨。", "晚禾雖云晚，霜肅但秋半。", "我昔山中居，升沒每關歎。", "及今食官倉，謂得度昏旦。", "那知不足飽，過午或空案。", "尚言工吟哦，猶說鄙計算。", "那知汝田翁，栽種日月斷。", "但懼政或疵，因之罹水旱。"]'),
('10581157-7cfc-4860-bbda-0bf69b952984','成父送梅一株','趙蕃','宋','宋诗','song-poetry','','[]','無竹恐人俗，無梅憂竹孤。',72,'全唐诗/poet.song.164000.json','["無竹恐人俗，無梅憂竹孤。", "阿連解我意，爲致三尺株。", "蒔之西窗前，青白相與扶。", "梅瘦竹亦瘠，豈唯人獨癯。", "終年厄貧病，藉爾得暫愉。", "索酒莫計琖，瓶罄當續沽。"]'),
('1fe918b3-1ea2-4cce-a817-0b17c5a00cb5','得蕙數本有懷斯遠二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','幽蘭一收馨，餘卉無足睨。',48,'全唐诗/poet.song.164000.json','["幽蘭一收馨，餘卉無足睨。", "今晨採樵子，貽我以數蕙。", "風氣固王謝，兄弟猶魯衛。", "雨合打窗深，於余真得計。"]'),
('97af5120-b4ca-4099-9dea-3951cb0a39e5','得蕙數本有懷斯遠二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','酒熱無共酌，詩成欠同哦。',48,'全唐诗/poet.song.164000.json','["酒熱無共酌，詩成欠同哦。", "况此春旦莫，忽來蕙成窠。", "樵蘇尚知貴，採掘能異科。", "安得同心人，與之酣且歌。"]'),
('a52187df-2ad2-4180-b74a-4f5c9798251f','賦滕彥真家玉桂','趙蕃','宋','宋诗','song-poetry','','[]','伏暑不可耐，所思惟執冰。',60,'全唐诗/poet.song.164000.json','["伏暑不可耐，所思惟執冰。", "常時月桂紅，乃作素色凝。", "維南實炎方，草木氣所憑。", "素馨與茉莉，玉色俱相仍。", "得非因月感，光射尚能乘。"]'),
('8589c7f3-3cd2-4ace-b0dc-5b1d5a14e732','掃桂','趙蕃','宋','宋诗','song-poetry','','[]','年年賦木犀，獨未到此樹。',72,'全唐诗/poet.song.164000.json','["年年賦木犀，獨未到此樹。", "信知官舍居，更甚此身寓。", "黄葉滿堦除，蔓草委霜露。", "相逢每變色，此樹獨如故。", "殷勤爲掃除，不必但花務。", "風月四時佳，吾其枉幽步。"]'),
('a7d7e2bd-3754-4b72-9ecd-c65d0adcf545','對菊有作','趙蕃','宋','宋诗','song-poetry','','[]','草木均是體，顧有幸不幸。',156,'全唐诗/poet.song.164000.json','["草木均是體，顧有幸不幸。", "故侯住瓜田，四皓卧芝嶺。", "譬如佳山川，何地乏幽屏。", "居然說終少，籍甚談箕潁。", "得非以人重，後世聞之警。", "維菊本甚微，在昔曾莫省。", "羅生蓬蒿間，自分託地冷。", "一趨騷人國，再墮淵明境。", "遂同隠居者，身晦名獨耿。", "何當園五畝，不覬田二頃。", "秋風及春雨，採擷花與穎。", "既充天隨饑，亦望南陽永。", "有志未能攄，對花徒引領。"]'),
('e3accf70-0727-437a-80da-b3a0fbda9546','周江州有靈壁石趙蘄州名以玉芝周索詩爲賦一首','趙蕃','宋','宋诗','song-poetry','','[]','論石如論玉，貴德不貴名。',192,'全唐诗/poet.song.164000.json','["論石如論玉，貴德不貴名。", "形似偶爾同，未妨聊置評。", "嗚呼禹甸破，土貢久莫并。", "問公安取此，萬里隨南征。", "向來四方遊，束書與俱擎。", "愧彼錢馬癖，寄我山林盟。", "風流蘄州守，夙有能詩聲。", "見之謚以芝，用意真不輕。", "謂公許器質，一再臨專城。", "宜爲齋房秀，作瑞于聖明。", "未應如商山，寂寞身中清。", "須公力勉旃，石亦當與榮。", "念我匪能賦，徵索見公情。", "又惟此必詩，落筆空汗生。", "傳聞南池上，有石來自英。", "我雖未識面，想像猶弟兄。"]'),
('a61acb87-3f63-46d4-91ce-49ad85d07ef1','詠隔塹梅','趙蕃','宋','宋诗','song-poetry','','[]','叢篁亂臨溪，叢樹深隔塹。',48,'全唐诗/poet.song.164000.json','["叢篁亂臨溪，叢樹深隔塹。", "愛之不能即，玩之寧有厭。", "五字遣誰哦，一杯頻爾念。", "幸勿折新開，留將遂幽占。"]'),
('5b778561-4060-4d2e-b345-050f77269a98','題廳後梅樹','趙蕃','宋','宋诗','song-poetry','','[]','移梅初有詩，梅開重成賦。',72,'全唐诗/poet.song.164000.json','["移梅初有詩，梅開重成賦。", "豈問耳目謀，蓋珍貞白故。", "花宜倚竹妍，陰稱巡簷步。", "或嫌太幽閟，結實每愆御。", "我非調鼎手，何暇爲此慮。", "但取冰玉姿，不遭桃李污。"]'),
('8d9ece54-2bba-484b-9f39-6844c009a299','明叔送一丈黄菊','趙蕃','宋','宋诗','song-poetry','','[]','菊開本叢叢，此種乃樹樹。',84,'全唐诗/poet.song.164000.json','["菊開本叢叢，此種乃樹樹。", "嘗聞一丈黄，直謂莊周寓。", "及茲鋤移來，信可繩尺度。", "乃知太華蓮，十丈語非誤。", "陳君怯風景，酒盡不能酤。", "遺我遣我愁，仍須墮言句。", "更念貧無帷，何以致調護。"]'),
('58ebd7da-084e-48d9-9849-74e9200685fe','除草','趙蕃','宋','宋诗','song-poetry','','[]','入門空榛蕪，半死猶未槁。',72,'全唐诗/poet.song.164000.json','["入門空榛蕪，半死猶未槁。", "清霜且零落，縱蔓那得保。", "奈何刺吾眼，快意思一掃。", "童來乃鈍鍤，兀兀日又了。", "蘭枯艾長壯，亂多治則少。", "君子小人歟，幽憂挂懷抱。"]'),
('cef498da-8146-43ce-85bd-2f5ada4420db','賣花行','趙蕃','宋','宋诗','song-poetry','','[]','頳肩負薪行，所直不滿百。',48,'全唐诗/poet.song.164000.json','["頳肩負薪行，所直不滿百。", "大舸載之來，江頭自山積。", "不如花作稛，先後價增損。", "身逸得錢多，人寧知務本。"]'),
('afaf2834-463b-4eba-b73a-77c81cb0c406','投宿廣平道上逢梅懷斯遠','趙蕃','宋','宋诗','song-poetry','','[]','驅羸度斜影，恨不與子俱。',48,'全唐诗/poet.song.164000.json','["驅羸度斜影，恨不與子俱。", "梅花忽照眼，炯若冰玉臞。", "暝投佛寺宿，憶子曾寄躅。", "摩挲壁間詩，雖昏尚能讀。"]'),
('28cab58a-e939-413a-86ed-0c6fce33537b','出北門記所見二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','浮雲冒山頂，橫碧門與直。',48,'全唐诗/poet.song.164000.json','["浮雲冒山頂，橫碧門與直。", "所嗟籃輿駛，令我頭屢側。", "前瞻亦何有，浮圖梯七級。", "彷彿記遺基，當年居皖伯。"]'),
('e76d502b-1178-4d99-bacc-87a073c64218','出北門記所見二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','我行舒州來，觸目歎荒棘。',48,'全唐诗/poet.song.164000.json','["我行舒州來，觸目歎荒棘。", "今經北門道，麻麥殊翳密。", "乃知人力愆，地固有遺殖。", "安得遍厥耕，疲羸當少息。"]'),
('6e266674-d4dd-4819-af7b-c7af25f4a126','將行示遠父秉文四八弟','趙蕃','宋','宋诗','song-poetry','','[]','鷄啼午方停，蟬噪暑未秋。',180,'全唐诗/poet.song.164000.json','["鷄啼午方停，蟬噪暑未秋。", "寓居雖市近，適意如林投。", "可人誰能來，王徐真勝流。", "王居近官道，樹林間田疇。", "徐居復何如，老木蔭濁溝。", "我往必竟日，不爲有魚留。", "我有長安行，食謀非道謀。", "王郎上冢去，决焉問吳舟。", "令弟饑所驅，迤邐從此由。", "徐郎獨不出，于世罕所求。", "念當爲此別，要歷山寺幽。", "令弟既泣女，我亦病未瘳。", "是事且若此，其他當罷休。", "中秋與重九，預作離闊憂。", "惟其梅花時，醉之此山頭。"]'),
('8bb10dc2-9a36-441f-9ad3-315307cecf44','別齊之','趙蕃','宋','宋诗','song-poetry','','[]','新月凈林木，微風動菰蒲。',192,'全唐诗/poet.song.164000.json','["新月凈林木，微風動菰蒲。", "客子不能寐，拊身念艱虞。", "忽思騎鯨翁，已去不可呼。", "樂哉今夕境，忍令墮空虛。", "南都李文學，豪氣老不除。", "將爲章江行，值我彭蠡湖。", "一見如平生，健論真起予。", "座間誦新作，崢嶸突黄初。", "携酒夜過我，烹鷄仍鱠魚。", "快飲不記琖，耳熱歌烏烏。", "乘墜俱大謬，醉倒不用扶。", "幾夢即了我，此身無復餘。", "勝踐無古今，人事自作疎。", "東西南北人，何必懷此都。", "明朝兩茫茫，危途各崎嶇。", "語離有遺恨，更起捋君鬚。"]'),
('1942f189-8efe-44e4-a4c8-4ebf8d8f1a11','贈別吳仲權三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','英英延陵家，藹藹宜章縣。',48,'全唐诗/poet.song.164000.json','["英英延陵家，藹藹宜章縣。", "政用魯諸生，俗今齊一變。", "諸公競推轂，天子思晚見。", "用捨有是夫，交親誰不羨。"]'),
('57695c9d-f740-460c-82d5-4a9ec4f59b03','贈別吳仲權三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','昔在山水樂，往往失意人。',48,'全唐诗/poet.song.164000.json','["昔在山水樂，往往失意人。", "公今絃歌餘，迺復於此親。", "搜羅既奇勝，落筆爲寫真。", "文章復何似，高處殆先秦。"]'),
('6284025a-794d-4c27-b639-13f527cb9944','贈別吳仲權三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','移舟漢將祠，躡屐秦人洞。',48,'全唐诗/poet.song.164000.json','["移舟漢將祠，躡屐秦人洞。", "一別幾何時，酒杯還此共。", "前途或追隨，祇恐終倥傯。", "要是策羸驂，無繇踵飛鞚。"]'),
('3afc937e-b66b-444c-a4ac-bf29900e7ea5','答周允升留別','趙蕃','宋','宋诗','song-poetry','','[]','客居江之南，未識衡嶽大。',192,'全唐诗/poet.song.164000.json','["客居江之南，未識衡嶽大。", "長於想象中，便作登臨外。", "南游悵不已，病目恍增快。", "要窮山水原，靡問仙靈態。", "鎸鑱雅未能，造物底不貸。", "欣逢人中龍，一掃胸次隘。", "偕爲青雲期，豈顧白眼怪。", "多聞與多識，幾別復幾會。", "籓籬我妄窺，根柢君有在。", "自慚非孟嘉，直恐誤郭泰。", "蕙蘭被餘薰，珠玉覺非對。", "茲方賦歸來，與乃別所愛。", "於今未深悲，後日當重慨。", "江流固滔滔，山木亦旆旆。", "煙霞既有疾，風月豈無債。", "相與詠和平，無庸發噍殺。"]'),
('370d55cc-e399-440b-bc30-571996e642c1','用程季儀送行之韻爲別','趙蕃','宋','宋诗','song-poetry','','[]','過江今幾年，遺俗不屢見。',240,'全唐诗/poet.song.164000.json','["過江今幾年，遺俗不屢見。", "縱餘門戶稱，直有冠裳變。", "惟君河洛間，南走楚粵遍。", "雖從科詔求，未脫褐衣賤。", "芬然蘭三薰，粹矣金百鍊。", "潭潭務中澄，煜煜鄙外絢。", "遂登南軒門，如識伊川面。", "周旋苟有得，喜躍幾成抃。", "淵深保戰兢，鴆毒戒安宴。", "於今過城南，政似趨無倦。", "儒冠蓋多端，劇論如合戰。", "試評季路勇，孰與之反殿。", "前日我辭君，炎風尚交扇。", "祗今君別我，餘暑已堪餞。", "歲序急推遷，吾行甚流轉。", "爝火詎當陽，雨雪寧待晛。", "孤唳豈潜聲，卑飛終掛罥。", "小令泊扁舟，暫爲瀝破研。", "我如浩然歸，君異方朔薦。", "契闊方自茲，追隨復何便。"]'),
('27190b4e-96d9-4b4d-a959-10407e6d0afd','平江尋吳恭叔不獲','趙蕃','宋','宋诗','song-poetry','','[]','皋橋在何許，往者郊送翱。',108,'全唐诗/poet.song.164000.json','["皋橋在何許，往者郊送翱。", "我行姑蘇城，半日空週遭。", "惟君昔我契，義不減同袍。", "珠林一杯酒，明朝隔江濤。", "年來尺書絕，目斷飛鴻高。", "我今換一官，五溪當不毛。", "君行官王都，雜遝從英髦。", "城中十萬戶，歷問無乃勞。", "茲焉失一見，使我心忉忉。"]'),
('c7573d1c-2078-438a-a7a7-4594b9ed2b06','沖谷道章少隠還自上饒不見過而遂歸懷玉作詩十二韻奉寄併煩送似寓齋也','趙蕃','宋','宋诗','song-poetry','','[]','幽居非不佳，竹屋靜以深。',144,'全唐诗/poet.song.164000.json','["幽居非不佳，竹屋靜以深。", "春歸邈亡蹤，草木成嘉陰。", "天氣殊未快，令人頭岑岑。", "忽思從公譚，微風動衣襟。", "白雲何許在，引領勞我心。", "平生誦佳句，三歎有遺音。", "端如猛虎嘯，百獸藏中林。", "交游一周子，自昔已至今。", "論道若有合，根源要追尋。", "文章固定價，美玉同精金。", "窮通我均樂，茲事要力任。", "通脫不累物，賢哉阮瞻琴。"]'),
('0425c275-d156-4432-8b84-ebc51ad93f61','送公擇入浙','趙蕃','宋','宋诗','song-poetry','','[]','日者君過我，今焉我辭君。',168,'全唐诗/poet.song.164000.json','["日者君過我，今焉我辭君。", "楚荆易得秋，霜霰行在辰。", "我車甫來歸，君騎已在門。", "喜我更安健，勞言再三陳。", "已焉忽謂我，我行不逡巡。", "問君何因爾，欲語聲輒吞。", "我自解君意，操袂增酸辛。", "男兒志四方，懷安實敗名。", "不見折脅雎，慷慨西入秦。", "君行其有合，宿憤當一伸。", "造物固甚巧，頗解戲弄人。", "願君稍安之，無爲自傷神。", "諸孫君好交，送君必以文。", "可慰別後覽，何憂去裝貧。"]'),
('d0072815-b8c7-472f-a6f0-2c3f18522945','送昭禮還金陵四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','上饒去金陵，道里何其邈。',48,'全唐诗/poet.song.164000.json','["上饒去金陵，道里何其邈。", "俱爲江東郡，各在天一角。", "君行寧知遠，我住若有縛。", "何以見相思，書來不嫌數。"]'),
('a7cd3a03-32f0-4d7a-ba64-f1dd21b19384','送昭禮還金陵四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','君似便風船，千里纔一瞬。',48,'全唐诗/poet.song.164000.json','["君似便風船，千里纔一瞬。", "我如久眢井，湮沒不可浚。", "愧君力推挽，令我去鄙吝。", "加我以數年，庶幾乎少進。"]'),
('d82efb9d-11c6-476a-b6c2-b28a0996e721','送昭禮還金陵四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','松巒特立士，君也爲之子。',48,'全唐诗/poet.song.164000.json','["松巒特立士，君也爲之子。", "異同誚歆向，父子自知己。", "向來知名人，得此多失彼。", "願君考其然，九十半百里。"]'),
('6392ec1e-68fb-437a-bb01-2e9c9c8a90bc','送昭禮還金陵四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','誦君贈遺詩，吃吃口不倦。',48,'全唐诗/poet.song.164000.json','["誦君贈遺詩，吃吃口不倦。", "相從曾未款，取別寧我願。", "竟乖卜鄰約，遂作摶沙散。", "君如不我忘，我復何所恨。"]'),
('379b0f5b-0981-430e-a566-172fda49374b','茂德行亟不及作昭禮書姑此問訊','趙蕃','宋','宋诗','song-poetry','','[]','憶昔相從初，二十有三年。',144,'全唐诗/poet.song.164000.json','["憶昔相從初，二十有三年。", "別日更莫紀，少壯成華顛。", "中間何不有，匪但歲月遷。", "幾尋長安居，莫訪新市船。", "尺書且難寄，再面端何緣。", "今晨大阮來，倒屣不待前。", "問君比安否，談君語蟬連。", "短髮尚短褐，青箱保青氈。", "吾人相從初，情與兄弟肩。", "蘭陵折梅贈，虞山聽鷄眠。", "如何一分首，遂作胡越然。", "詩以道所懷，寧寫宣城箋。"]'),
('c33afd46-c026-419d-99b2-ca9f1ea9cb5c','蕃與斯遠季奕同生於十二月蕃初五日季奕初十日斯遠十八日近辱季奕貺詩猶未獲報茲及斯遠之壽併此奉頌二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','徐子崖根竹，風雪不掩綠。',48,'全唐诗/poet.song.164000.json','["徐子崖根竹，風雪不掩綠。", "鄭子谷中蘭，冰霜已騰馥。", "二子有此風，宜爾生窮冬。", "我獨何爲者，飄然直轉蓬。"]'),
('cf10c9f2-7316-4cee-a79e-dc7cad37a86f','蕃與斯遠季奕同生於十二月蕃初五日季奕初十日斯遠十八日近辱季奕貺詩猶未獲報茲及斯遠之壽併此奉頌二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','鄭子才不疎，徐子文甚勇。',48,'全唐诗/poet.song.164000.json','["鄭子才不疎，徐子文甚勇。", "一旦召嚴徐，一旦策晁董。", "去年蕭寺中，杯酒兼旬同。", "間闊見難合，况乎分悴豐。"]'),
('a871eb6c-c6ad-4b7d-8063-ef5154214356','次韻和答斯遠見過書所見','趙蕃','宋','宋诗','song-poetry','','[]','來歸僅兼旬，來過已云屢。',156,'全唐诗/poet.song.164000.json','["來歸僅兼旬，來過已云屢。", "共耽林剎深，同賞溪亭露。", "濁清一再行，俊逸今古句。", "或哦山更幽，或詠舟橫渡。", "竟日爲之留，曛黑始能去。", "昔人物外游，隱遯亦數路。", "於今區中緣，向背豈同趣。", "我非韓伯休，君殆黄叔度。", "莫嗟聲氣卑，但恐歲月遽。", "解嘲乃文嬉，賓戲蓋言諭。", "陶寫固不惡，沈溺斯可懼。", "人雖或我寬，我則難自恕。", "望望獨行憂，瘽瘽良友助。"]'),
('d752a8e8-bff8-4323-b878-fea3d199bf28','明叔每見過不久輒去仲威尤難招致索居書事呈二君','趙蕃','宋','宋诗','song-poetry','','[]','可人費招呼，柰此陳與胡。',84,'全唐诗/poet.song.164000.json','["可人費招呼，柰此陳與胡。", "問事失昏忘，論詩辨精粗。", "清風不可絆，白日易成晡。", "欲睡難安枕，繙書得踞爐。", "聒人紛宿鳥，對面走饑鼯。", "啁哳聊容汝，睢盱反闖吾。", "寧無捕黄口，亦有聘貍奴。"]'),
('78bbed7a-d114-4059-b768-407a460b5fbe','仲威復枉粥字韻詩見屬甚厚不可不答','趙蕃','宋','宋诗','song-poetry','','[]','盛時無窮民，漢詔優廩粥。',168,'全唐诗/poet.song.164000.json','["盛時無窮民，漢詔優廩粥。", "邇來詔書行，亦賫帛與肉。", "薦才職諸侯，因異駕徵卜。", "共思急賢治，惟日有不足。", "士生幸斯時，詎應隠巖谷。", "盍出致吾君，堯舜其爾俗。", "餘孽何足云，况說故地復。", "堂堂胡澹庵，夫子乃其族。", "看君妙人物，門戶真不辱。", "必須長養成，明顯待拭目。", "而我本散材，謬賦支離粟。", "宜從力田科，邂逅賦取菽。", "敢如陶淵明，歸歟托松菊。", "亦有父時書，續將教人讀。"]'),
('e85149c0-d616-4a38-bc0d-a8b606b12181','子肅以古風見還詩軸頗述歸田之樂次韻答之','趙蕃','宋','宋诗','song-poetry','','[]','春風忽滿目，感嘆離羣居。',168,'全唐诗/poet.song.164000.json','["春風忽滿目，感嘆離羣居。", "郊行竟何之，野蔓徒侵裾。", "仰看嶺頭雲，片段隨卷舒。", "悠然若有得，似我心地初。", "乃愧學道晚，何時悟真如。", "自茲稍鞭策，齒髮及未疎。", "有兒幸成丁，可以親犁鉏。", "要同商州民，窮功治山畬。", "王租及時了，優游伴樵漁。", "時乘少游馬，或卧淵明輿。", "所過輒就醉，其他焉取餘。", "此計儻遂心，誰能更淫書。", "公詩胡爲哉，指南實前車。", "事貴在勇决，駸駸歲將除。"]'),
('eccd38a9-e1e7-442b-8061-21bcb8377968','夜讀子肅詩再用前韻','趙蕃','宋','宋诗','song-poetry','','[]','棲鴉既投林，蕭然野人居。',168,'全唐诗/poet.song.164000.json','["棲鴉既投林，蕭然野人居。", "獨立茅簷下，依依月生裾。", "涉春抱煩痾，茲夕稍自舒。", "誦公寄來詩，何啻超黄初。", "正聲久欲絕，作者徒紛如。", "得公振頹波，如漢有二疏。", "擬欲躡其跡，荒棘廢墾鉏。", "譬由治田人，必待三年畬。", "敢矜一日功，草草同獵漁。", "窮通固定分，往者悲接輿。", "百年等夢間，壽夭誰贏餘。", "如何彼虞翻，惋歎輒著書。", "人生貴適意，安步可當車。", "茲道儻與聞，他焉從破除。"]'),
('fce12463-d79a-47f7-9dee-516483cb97bb','向監稅以前韻見貽復用韻答之','趙蕃','宋','宋诗','song-poetry','','[]','鄒陽困游梁，自喻託枯朽。',204,'全唐诗/poet.song.164000.json','["鄒陽困游梁，自喻託枯朽。", "功名彼何能，慷慨終無取。", "寧知古君臣，義蓋存師友。", "高謝亦有人，班班推廣受。", "先師有遺言，何有居夷陋。", "歎息柳儀曹，枉尺贊五就。", "詩書自青衿，事業見白首。", "基本苟不定，歲月寧能又。", "煌煌瀟湘姿，肯雜樝梨餖。", "而彼倚市門，詎復工刺繡。", "騏驥伏鹽車，駑駘空滿廐。", "置是勿易談，舊矣憎多口。", "君詩定自佳，官乃等尉候。", "詩成不自足，乃復過我牖。", "同官有歐沈，一時真頗有。", "要加萬鎰彫，必待無價手。", "君其往從之，我亦瞠其後。"]'),
('9a73913a-9364-4bce-8057-037262c2deda','答審知見貽','趙蕃','宋','宋诗','song-poetry','','[]','昔我墮極南，去茲千萬山。',168,'全唐诗/poet.song.164000.json','["昔我墮極南，去茲千萬山。", "見面夫豈易，附書良亦難。", "官今聽之歸，連日乃獲語。", "洗蘇塵埃懷，如久旱得雨。", "君才日蒼蒼，略已千丈長。", "計其所功用，可中棟與梁。", "如我蓬艾等，怒長不尺寸。", "秋風一摧折，僅可供束藴。", "宜君有聲名，光彩益以新。", "而我復何事，强謂詩窮人。", "春秋了集義，詩箋復編類。", "建有朱校書，婺有呂正字。", "二公今儒先，名滿天地間。", "勿謂東家丘，睎顔人亦顔。"]'),
('665846a9-31e6-4219-8a9c-169486b2b894','晦日用陶靖節蜡日韻','趙蕃','宋','宋诗','song-poetry','','[]','正月忽已晦，惠風亦全和。',48,'全唐诗/poet.song.164000.json','["正月忽已晦，惠風亦全和。", "更留十日晴，桃李當有花。", "病夫不知春，但覺所感多。", "東軒對深樾，日暮鳥猶歌。"]'),
('489e5f10-bc4c-4c82-aa4c-26d9758e654b','晚立偶作','趙蕃','宋','宋诗','song-poetry','','[]','晨雨濕木蘭，夕風吹紫荆。',48,'全唐诗/poet.song.164000.json','["晨雨濕木蘭，夕風吹紫荆。", "江南異中州，春晚猶秋清。", "壯年不可恃，老態忽已生。", "柴門立久倦，濁醪歸徐傾。"]'),
('7a19c23c-c43b-4e47-a790-d93a99a1ac09','晨起見牧牛者','趙蕃','宋','宋诗','song-poetry','','[]','前者蓑而眠，後者笠而坐。',48,'全唐诗/poet.song.164000.json','["前者蓑而眠，後者笠而坐。", "陂長不待鞭，草軟無用莝。", "蚤耕蹔廑力，午放長逸卧。", "薄暮翁洗犁，兒歌互相和。"]'),
('e2d10b28-e33d-479e-8a91-a51226f51e51','晚立有作','趙蕃','宋','宋诗','song-poetry','','[]','朝暉熏我肌，不飲類酣適。',108,'全唐诗/poet.song.164000.json','["朝暉熏我肌，不飲類酣適。", "夕陰慘我顔，所抱非隠戚。", "晝夜無停機，日月布常職。", "浮生任變滅，二者互出沒。", "汝憂何從生，汝喜何自得。", "陰晴况莫料，暄暖難屢必。", "顧雖甚蒙昧，詎敢規造物。", "衾裯欠宵具，薪炭乏預積。", "未免形語言，寧知見顔色。"]'),
('5c126b80-51b4-4519-acd8-0d2bd84140c5','書事  其一','趙蕃','宋','宋诗','song-poetry','','[]','長年穫稻時，人盡趨南畝。',48,'全唐诗/poet.song.164000.json','["長年穫稻時，人盡趨南畝。", "束薪固圖售，求益敢屢拒。", "念昔居田園，連林恣斤斧。", "炊飲煮坡羹，徒聞亂風雨。"]'),
('7e6b164a-b1ae-410e-b434-c7208fee7679','書事  其二','趙蕃','宋','宋诗','song-poetry','','[]','山谿急宵舂，野市赴朝糴。',48,'全唐诗/poet.song.164000.json','["山谿急宵舂，野市赴朝糴。", "人言非踴貴，富者猶露積。", "豐年且不飽，惡歲真可戚。", "懸釜以待炊，衾裯寧許直。"]'),
('a890f772-6eb0-40ce-abfd-d52c31bd14e0','書事  其三','趙蕃','宋','宋诗','song-poetry','','[]','貧非事烹煎，病止治藥物。',48,'全唐诗/poet.song.164000.json','["貧非事烹煎，病止治藥物。", "烏薪鬻之市，束縛論寸尺。", "煙浮多穉松，質重非老櫟。", "熾焰忽復然，寒灰已成積。"]'),
('a770183f-3b5c-47dc-86de-ca8c8f94bba6','書事  其四','趙蕃','宋','宋诗','song-poetry','','[]','久旱始足雨，畦圃新料理。',48,'全唐诗/poet.song.164000.json','["久旱始足雨，畦圃新料理。", "秋茄尚入饌，晚菘能敗齒。", "萬錢固無相，三韭聊自詭。", "抱甕豈忘勤，移家嫌近市。"]'),
('cfe29ae9-2283-4a57-b004-11b3c2356dea','書事  其五','趙蕃','宋','宋诗','song-poetry','','[]','兒童不知憂，度日長戲劇。',48,'全唐诗/poet.song.164000.json','["兒童不知憂，度日長戲劇。", "忽傳山中訊，欣喜沾柿栗。", "爲物雖甚微，貴是家所植。", "何當携爾曹，遶樹親尋摘。"]'),
('e4871ae0-9778-4c42-a2dc-35d603e6f040','書事  其六','趙蕃','宋','宋诗','song-poetry','','[]','東街鼓坎坎，西街鼓鼕鼕。',48,'全唐诗/poet.song.164000.json','["東街鼓坎坎，西街鼓鼕鼕。", "市酒倚法禁，椎牛聚羣凶。", "差事驚父老，狂歌走兒童。", "此俗苟不止，斯民始終窮。"]'),
('44674686-5026-4b98-bb7c-6603cd571c04','書事  其七','趙蕃','宋','宋诗','song-poetry','','[]','早禾雖登場，舂簸纔足食。',48,'全唐诗/poet.song.164000.json','["早禾雖登場，舂簸纔足食。", "晚禾尚棲隴，登減未可必。", "吏持與催符，官趣違限責。", "爲政本憂民，民憂政何德。"]'),
('7e80204e-d97a-4c6a-8730-396176808567','書事  其八','趙蕃','宋','宋诗','song-poetry','','[]','兒啼宵不飽，女訴夏無衣。',48,'全唐诗/poet.song.164000.json','["兒啼宵不飽，女訴夏無衣。", "幾載宦遊倦，素來生事微。", "詩書須自勉，紉補莫多違。", "我亦田園去，終難粟肉希。"]'),
('a690b1fb-f80f-42b5-a702-2975ff361849','書事  其九','趙蕃','宋','宋诗','song-poetry','','[]','北風卷湖水，萬里雪欲狂。',144,'全唐诗/poet.song.164000.json','["北風卷湖水，萬里雪欲狂。", "乘勢不自止，雲開日垂光。", "風伯益振厲，行子立欲殭。", "青女探其機，變作明日霜。", "湖水凍成坼，層冰傲朝陽。", "松柏愁悴死，寧云草蒼蒼。", "哀哉羈栖人，破褐無幾長。", "塞向亦墐戶，退憐無地藏。", "緬思六月中，誓言望清商。", "及今玄冬時，懔懔反莫當。", "流金與折膠，事乃旦暮常。", "安時輔爾躬，毋爲徒自傷。"]'),
('df3bb653-f156-4e1c-ab95-bd30ac89b417','書事  其一○','趙蕃','宋','宋诗','song-poetry','','[]','我行一何忙，羽檄來星犇。',240,'全唐诗/poet.song.164000.json','["我行一何忙，羽檄來星犇。", "忙行抑何事，列境備戍屯。", "賊犯連英郴，江右聲已宣。", "往年縛李金，此邦蓋晏然。", "而今獨胡爲，騷驛窮朝昏。", "政坐茶賊時，曾窺此邦藩。", "茶賊異此賊，本皆商販民。", "忽當法令變，州縣復少恩。", "求生既無路，冒此圖或存。", "此賊據巢穴，其徒况是繁。", "萌芽手可披，不披生惡根。", "雖云巢穴深，豈離率土濱。", "彼猶蠭蟻聚，我軍貔虎羣。", "彼積鼠壤餘，我粟多腐陳。", "彼乃寇攘爾，我蓋仁義云。", "邊庭尚思犁，此又何足言。", "何當快除掃，聽民樂耕耘。", "我亦得拋官，歸舟趁春渾。", "胡爲故使我，駒局仍鴟蹲。", "更慮一朝焚，碔砆同璵璠。"]'),
('f114f9a5-5aab-4c3f-a24b-aee1e1eb3e29','久不作詩詩思甚涸春物日盛漫興三章用常德棗心筆書本不工重復加弱似亦與詩相稱云  其一','趙蕃','宋','宋诗','song-poetry','','[]','威嚴退冰霜，清潤歸梅柳。',48,'全唐诗/poet.song.164000.json','["威嚴退冰霜，清潤歸梅柳。", "少時騁青春，老至傷白首。", "日長卷添書，病倦盃費酒。", "姑置鴈鶩行，顧慚牛馬走。"]'),
('49709ff3-d4ab-4e1c-9f1d-8e902ad2a40b','久不作詩詩思甚涸春物日盛漫興三章用常德棗心筆書本不工重復加弱似亦與詩相稱云  其二','趙蕃','宋','宋诗','song-poetry','','[]','庭行看萌芽，簷立聽呼應。',48,'全唐诗/poet.song.164000.json','["庭行看萌芽，簷立聽呼應。", "在物且云然，於我可不競。", "青衫戀五斗，白髮間三徑。", "是豈人之爲，絕知吾有命。"]'),
('74e4bbd1-1204-4a4d-817f-dd0a688afda2','久不作詩詩思甚涸春物日盛漫興三章用常德棗心筆書本不工重復加弱似亦與詩相稱云  其三','趙蕃','宋','宋诗','song-poetry','','[]','春回溪山姿，候趣農桑務。',48,'全唐诗/poet.song.164000.json','["春回溪山姿，候趣農桑務。", "自知盍歸來，人歎推不去。", "順心豈故違，宿諾寧久負。", "既已媿淵明，又應慚季路。"]'),
('d5f7a2b0-0fd7-4b1b-96e9-3090e1a49513','即事二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','問薪薪已無，問米米已空。',48,'全唐诗/poet.song.164000.json','["問薪薪已無，問米米已空。", "假貸愧鄰里，犇走愁僕童。", "乞食陶徵君，乞米平原公。", "昔人有如此，吾今未爲窮。"]'),
('cc23d28d-c5b8-4ad7-a5a0-e8bf11937c44','即事二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','廢圃失不治，委積成荆杞。',48,'全唐诗/poet.song.164000.json','["廢圃失不治，委積成荆杞。", "何敢問嘉蔬，亦無馬牙齒。", "舊聞苦行僧，破鐺煮糙米。", "我今頗似之，但未除髮耳。"]'),
('c78cb915-2dd6-4c81-b805-dfb95bab2ba5','雜興四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','家居百金貨，富可千金敵。',48,'全唐诗/poet.song.164000.json','["家居百金貨，富可千金敵。", "持行鬻於市，曾微一錢直。", "人或不汝知，汝售無固急。", "邂逅識真者，百金還復得。"]'),
('d7055f99-ffbf-4273-a4cb-065cad670cbc','雜興四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','蘭生深林中，故與蕭艾同。',48,'全唐诗/poet.song.164000.json','["蘭生深林中，故與蕭艾同。", "春風披拂之，芳氣何沖融。", "宜有同心人，採擷佩厥躬。", "採擷苟不至，依然守荒叢。"]'),
('61abe639-6b73-441e-911f-79563433554f','雜興四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','不見澗底松，樹子元楚楚。',48,'全唐诗/poet.song.164000.json','["不見澗底松，樹子元楚楚。", "長大今幾年，植立無風雨。", "一朝建明堂，未免斤斧苦。", "斤斧不爲傷，掄材固其所。"]'),
('4f6c9c1a-9b1b-4a0b-8745-016992eb721d','雜興四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','良農之於田，曾匪一日力。',48,'全唐诗/poet.song.164000.json','["良農之於田，曾匪一日力。", "耕耘各以時，志在秋有穫。", "其間罹水旱，亦是天地德。", "汝不替厥功，後當值豐殖。"]'),
('c24d01bf-0169-44fa-a506-2f6ffc446a38','旅中雜興五首  其一','趙蕃','宋','宋诗','song-poetry','','[]','炯炯冰玉姿，落落山林相。',48,'全唐诗/poet.song.164000.json','["炯炯冰玉姿，落落山林相。", "問渠坐何事，斬伐傷神王。", "更加束縛之，求市朱門傍。", "渠雖不解言，我爲成惆悵。"]'),
('043f36a6-de19-4ee6-bbce-23e4328d8731','旅中雜興五首  其二','趙蕃','宋','宋诗','song-poetry','','[]','英英深林蘭，發發不自閟。',48,'全唐诗/poet.song.164000.json','["英英深林蘭，發發不自閟。", "誰遣入市門，樵夫强解事。", "渠雖賞芬芳，我自羞嫵媚。", "懷哉山中人，紉結參珮璲。"]'),
('c3630ec5-6d7b-4d4e-9d88-5047a097105d','旅中雜興五首  其三','趙蕃','宋','宋诗','song-poetry','','[]','屢雪不一雪，雲脚何時絕。',48,'全唐诗/poet.song.164000.json','["屢雪不一雪，雲脚何時絕。", "春風雖云來，積凍吹又結。", "未論芻薪價，曳履凍欲裂。", "苦欲作商音，聲寒還復輟。"]'),
('7dd99e2e-261a-496c-be8b-76b9a5e9fcaf','旅中雜興五首  其四','趙蕃','宋','宋诗','song-poetry','','[]','舊雪固已多，新雪翻增劇。',48,'全唐诗/poet.song.164000.json','["舊雪固已多，新雪翻增劇。", "立春已涉五，太昊猶辟易。", "長安有羈旅，無以度朝夕。", "所願見白日，歸舟泛深碧。"]'),
('42cada30-0ee0-422e-9f82-6fe35fd7eb4d','旅中雜興五首  其五','趙蕃','宋','宋诗','song-poetry','','[]','少慕隠逸人，開口談四皓。',48,'全唐诗/poet.song.164000.json','["少慕隠逸人，開口談四皓。", "及今聞其風，尚愧劉德老。", "詔恩雖與官，辭避猶却掃。", "不應吏部門，皇皇踏泥潦。"]'),
('70d2133d-6151-4fab-9ba3-8b3599940b6c','晚書二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','落月不可駐，落日不可揮。',48,'全唐诗/poet.song.164000.json','["落月不可駐，落日不可揮。", "豈昧白晝長，畏此餘暑威。", "人生延促頃，光景變滅微。", "水霧已似合，山烟亦成霏。"]'),
('7e7df2da-fa6d-4815-8717-399b22e5e83b','晚書二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','抱道等金玉，乃不知自珍。',60,'全唐诗/poet.song.164000.json','["抱道等金玉，乃不知自珍。", "終朝噂𠴲間，叩門復隨塵。", "那知江湖叟，生計竿與綸。", "逢人問售否，或至生怒嗔。", "此理何謂然，即我我即人。"]'),
('6a1bb497-fd67-459f-8e71-b5200731e1c6','酬季益','趙蕃','宋','宋诗','song-poetry','','[]','君家三尺窗，盡著溪上山。',96,'全唐诗/poet.song.164000.json','["君家三尺窗，盡著溪上山。", "怪君坐其中，舉世招不還。", "餘嬉到五言，時許見一斑。", "顧我僅曹鄶，季孟胡可間。", "比年爾何緣，迺復罹間關。", "試問蓬蒿居，孰愈轍迹環。", "古來千里足，未必十二閑。", "是故東方士，長饑猶好顔。"]'),
('5ffc1b27-78e7-41f1-8ee0-1f4f02577f08','十三夜招全真沅陵','趙蕃','宋','宋诗','song-poetry','','[]','昨朝熱如焚，今日涼如水。',48,'全唐诗/poet.song.164000.json','["昨朝熱如焚，今日涼如水。", "豈惟悟天機，政自知物理。", "黄華一月賒，桂子數夕事。", "已辦烹伏雌，相期泛浮蟻。"]'),
('ff74a583-70c7-4e7f-bc83-5c0d3d9d1672','中秋以山居不得與周文對飲况子暢在數百里外也悵然有懷','趙蕃','宋','宋诗','song-poetry','','[]','山林遠俗人，風月親我輩。',72,'全唐诗/poet.song.164000.json','["山林遠俗人，風月親我輩。", "凉秋半今夕，痼疾况少退。", "詩懷客子哦，酒欠伯仁對。", "百年等夢幻，一笑有成敗。", "禿巾倚枯松，赤脚踏斷瀨。", "何當約二叟，勝踐同一會。"]'),
('9dea5e1d-b7d8-4b66-af4f-122904702175','秋日獨飲二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','秋風何時來，庭樹非昨好。',48,'全唐诗/poet.song.164000.json','["秋風何時來，庭樹非昨好。", "樹猶不自持，况問青青草。", "人生甚草木，閲世安可保。", "頼此忘憂物，陶公蓋知道。"]'),
('5efecee9-f674-4682-bbcb-dd902d83426e','秋日獨飲二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','素懷樂清曠，長言待秋風。',48,'全唐诗/poet.song.164000.json','["素懷樂清曠，長言待秋風。", "及茲摇落初，感歎如有攻。", "長卿既倦遊，嗣宗復途窮。", "苟無杯中物，何以娛我躬。"]'),
('0dc8e9a6-5f88-40f1-a0dc-41f8c57951bb','李聲父唐德輿程士和梁和仲過飲','趙蕃','宋','宋诗','song-poetry','','[]','相期本林園，相厄乃霰雪。',48,'全唐诗/poet.song.164000.json','["相期本林園，相厄乃霰雪。", "不難屐齒去，所怕巾角折。", "香燒古銅鼎，囊貯今墨帖。", "欲醉竟不能，匆匆謝車轍。"]'),
('041c3fe0-7263-433d-ba7c-89cd76ecfb45','病中寄呈王信州老謝丈','趙蕃','宋','宋诗','song-poetry','','[]','韓詩不可犯，顔字不可凟。',264,'全唐诗/poet.song.164000.json','["韓詩不可犯，顔字不可凟。", "舊言驅瘧癘，其效甚符籙。", "追慕記初學，諷誦懷三復。", "如何且逾月，此物猶肆毒。", "得非緣法異，無迺災釁酷。", "推移自前後，進退亦淹速。", "豈惟搜脂髓，直覺憎面目。", "醫方戒山果，牙頰怕臠肉。", "味嫌東野薺，餒厭平原粥。", "莫知所生理，真恐遂鬼錄。", "屬時秋已季，更值雨相續。", "卧聞掃空階，起步驚隕木。", "蛩號故亡頼，蚊豹成暗逐。", "未資卒歲計，頗病嚴霜促。", "幸遭賢使君，立政匪今俗。", "教微下黄堂，惠已周白屋。", "論情素有托，謁見慚未卜。", "詎應四壁立，久作窮途哭。", "謝公方在郡，薦士宜首牘。", "疇能借齒牙，價可重金玉。", "自憐非道謀，觸事先顔恧。", "病倦不成書，書成况難讀。"]'),
('aa4e5ff0-6d70-4197-91c1-b73d35e6356e','初三日晚題','趙蕃','宋','宋诗','song-poetry','','[]','浮雲晚陸離，巨浪朝澎湃。',48,'全唐诗/poet.song.164000.json','["浮雲晚陸離，巨浪朝澎湃。", "櫓摇雖甚亟，岸遠不可屆。", "巴丘兩日中，湖路千里外。", "月上照遥山，修眉雨新畫。"]'),
('f86f5d78-ba64-4276-a150-76e195941b55','是夕微雨','趙蕃','宋','宋诗','song-poetry','','[]','臘雪財覆地，春雨不溜瓦。',48,'全唐诗/poet.song.164000.json','["臘雪財覆地，春雨不溜瓦。", "天公務塞責，人意自嫌寡。", "豈惟田未耕，况是麥在野。", "安得三日霖，滂沱遍天下。"]'),
('3da9069b-9466-4dad-87bc-72aefae351e9','連日雨作頓有秋意懷感之餘得詩七首書呈教授知縣  其一','趙蕃','宋','宋诗','song-poetry','','[]','小雨洗清晝，幽花耀寒廳。',48,'全唐诗/poet.song.164000.json','["小雨洗清晝，幽花耀寒廳。", "雲間返微照，風薄成細零。", "蟬悽如欲收，蟲咽無蹔停。", "渠將趣寒事，我自感頹齡。"]'),
('7f145bb8-9b96-48e0-b7b2-880b1b26635c','連日雨作頓有秋意懷感之餘得詩七首書呈教授知縣  其二','趙蕃','宋','宋诗','song-poetry','','[]','頹齡不可羈，寒事亦已迫。',48,'全唐诗/poet.song.164000.json','["頹齡不可羈，寒事亦已迫。", "女褐破未紉，兒襦短仍窄。", "杜陵歎女癡，淵明更兒責。", "返念田家翁，囷禾與機帛。"]'),
('3c7fa356-185f-4c8e-bc32-0af54b69a268','連日雨作頓有秋意懷感之餘得詩七首書呈教授知縣  其三','趙蕃','宋','宋诗','song-poetry','','[]','牆根數席地，聊爾遣耘治。',48,'全唐诗/poet.song.164000.json','["牆根數席地，聊爾遣耘治。", "年豐菜亦熟，採掇斯及時。", "拔葵媿公儀，學圃非樊遲。", "幸逃肉食鄙，用補囊粟饑。"]'),
('6f283e58-5f7a-462e-8c54-f96ce2fc1ee3','連日雨作頓有秋意懷感之餘得詩七首書呈教授知縣  其四','趙蕃','宋','宋诗','song-poetry','','[]','淵明抱羸疾，猶復歸田園。',48,'全唐诗/poet.song.164000.json','["淵明抱羸疾，猶復歸田園。", "安能爲五斗，折腰若拳拳。", "簞瓢非可樂，不改迺稱賢。", "夫子故不死，仰鑽高且堅。"]'),
('ca280247-d3db-407d-8129-27d584e4e122','連日雨作頓有秋意懷感之餘得詩七首書呈教授知縣  其五','趙蕃','宋','宋诗','song-poetry','','[]','我官雖云薄，廩粟猶有繼。',48,'全唐诗/poet.song.164000.json','["我官雖云薄，廩粟猶有繼。", "懷哉江東弟，餬口當何計。", "風悲隕高梧，雨歎凋碧蕙。", "富合與貧離，怛然撫身世。"]'),
('96cfd8f1-008d-482a-816f-84eb220188cb','連日雨作頓有秋意懷感之餘得詩七首書呈教授知縣  其六','趙蕃','宋','宋诗','song-poetry','','[]','聞兒誦書聲，兩耳輒爲明。',48,'全唐诗/poet.song.164000.json','["聞兒誦書聲，兩耳輒爲明。", "青紫云乎哉，老我愧此生。", "家聲寒如冰，奔走霜鬢盈。", "束書故好在，淹泊諒無成。"]'),
('ba2d9a02-8ef1-4ad1-af3f-0f7664aeb615','連日雨作頓有秋意懷感之餘得詩七首書呈教授知縣  其七','趙蕃','宋','宋诗','song-poetry','','[]','沈侯賦郊居，歐公賦鳴蟬。',48,'全唐诗/poet.song.164000.json','["沈侯賦郊居，歐公賦鳴蟬。", "誰謂遠莫繼，有孫筆翩翩。", "我獨歌骯髒，世憎還自憐。", "秋風鳴不已，如欲相和然。"]'),
('d31b53b5-b4ae-4e52-9cdd-2c89f66a49c7','趣章永豐祈雨','趙蕃','宋','宋诗','song-poetry','','[]','高田卷蒼埃，下田積荒穭。',240,'全唐诗/poet.song.164000.json','["高田卷蒼埃，下田積荒穭。", "頻聞父老嘆，似訴車戽苦。", "吾鄉地猶薄，有類家素窶。", "旱繇十日晴，潦自三尺雨。", "吏斯靡常禱，神得誇屢許。", "近雖略豐稔，曾不厚倉庾。", "桑麻籍銖兩，門戶强撐拄。", "往時屬初夏，插秧未終畝。", "甘膏偶愆候，人意已深阻。", "沛然天爲賜，翕爾農遂舉。", "沉憂釋阽危，樂事覬安堵。", "迨今幾何日，所歷無廢土。", "豈惟勞手足，殆欲病腰膂。", "早禾穗且實，晚稻花半吐。", "更寬經旬虞，當作有歲取。", "奈何又觖望，嗟爾復奚補。", "雲師匪云怠，風伯敢固拒。", "烹鵝竟何術，象龍恐非古。", "精誠苟潜運，響應猶或俯。", "誰能任此責，再拜謝明府。"]'),
('456f6bd6-146c-4874-8216-c05f67e42c72','初六日雨而甚微','趙蕃','宋','宋诗','song-poetry','','[]','旱勢若燎火，雨粒如投珠。',72,'全唐诗/poet.song.164000.json','["旱勢若燎火，雨粒如投珠。", "望望恐不及，嗷嗷欲成呼。", "叩龍探古湫，號佛喧通衢。", "山川禱斯必，社稷報不渝。", "古人之所是，今人之所迂。", "龍神與社鬼，其事亦區區。"]'),
('3568bd37-e009-480b-9b37-24c1e6ca01f9','雨二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','旱極乃得雨，凄然天已秋。',48,'全唐诗/poet.song.164000.json','["旱極乃得雨，凄然天已秋。", "譬如病且革，藥劑方一投。", "不猶愈於無，庶幾千一瘳。", "未聞失東隅，果有桑榆收。"]'),
('a4fc4b68-9b42-423b-a5d3-c7f062a39a05','雨二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','得雨天忽秋，起我凄其悲。',48,'全唐诗/poet.song.164000.json','["得雨天忽秋，起我凄其悲。", "凄其亦何悲，歲晏霜雪期。", "壯志久已謝，白髮來及時。", "絺綌與裘褐，棄置復營爲。"]'),
('2e0d836c-f038-4d4a-bab9-4e0de98f9cb0','閔雨','趙蕃','宋','宋诗','song-poetry','','[]','青山本無垢，坐受瘴霧侵。',120,'全唐诗/poet.song.164000.json','["青山本無垢，坐受瘴霧侵。", "馬倦不加鞭，暑氣令人昏。", "去年蝗爲災，千家百不存。", "流亡不自保，聚掠連諸村。", "閔閔望一雨，可招若敖魂。", "旱勢復如此，早禾空如雲。", "豐登數有常，赤子皆天民。", "惜此三尺雨，龍師恐不仁。", "禳禬古有法，至和格神人。", "不見東海郡，孝婦冤欲伸。"]'),
('85666b70-8b27-47f1-bdb8-0467b4f9d368','閏月二日雨三日復雨寄斯遠三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','大雨固霶霈，小雨更霢霂。',72,'全唐诗/poet.song.164000.json','["大雨固霶霈，小雨更霢霂。", "蕭然凉已生，隠若雷未伏。", "前時歷月陰，邇日連朝暴。", "早田有愁乾，菜本亦恐縮。", "居閑苦無事，憂國願時熟。", "老翠上松篁，餘滋到蘭菊。"]');
